/**
 * Firebase Messaging Service Worker
 * 
 * Handles background push notifications when the app is not in focus.
 * This file MUST be in the public/ directory to be served at the root.
 */

/* eslint-disable no-undef */
importScripts('https://www.gstatic.com/firebasejs/10.12.0/firebase-app-compat.js');
importScripts('https://www.gstatic.com/firebasejs/10.12.0/firebase-messaging-compat.js');

// Initialize Firebase in the service worker
// These values will be replaced with actual config from your Firebase project
firebase.initializeApp({
    apiKey: "AIzaSyDZnuRWWXNgRsWYkIs1YLKRP2wjxP8m818",
    authDomain: "iss-project-149f1.firebaseapp.com",
    projectId: "iss-project-149f1",
    storageBucket: "iss-project-149f1.firebasestorage.app",
    messagingSenderId: "448784288780",
    appId: "1:448784288780:web:cd80cb82fa93cf0d84b229",
});

const messaging = firebase.messaging();

/**
 * Handle background messages (when app is not in focus).
 * The browser will automatically show a notification using the 'notification' field
 * from the FCM payload. This handler is for any custom logic on 'data' messages.
 */
messaging.onBackgroundMessage((payload) => {
    console.log('[firebase-messaging-sw.js] Received background message:', payload);

    // If the payload has a notification field, the browser handles it automatically.
    // Only show a custom notification if there is no notification field (data-only message).
    if (!payload.notification && payload.data) {
        const notificationTitle = payload.data.title || 'SchoolIMS';
        const notificationOptions = {
            body: payload.data.body || payload.data.content || '',
            icon: '/favicon.ico',
            badge: '/favicon.ico',
            data: {
                url: payload.data.actionUrl || '/',
            },
        };

        self.registration.showNotification(notificationTitle, notificationOptions);
    }
});

/**
 * Handle notification click ΓÇö open the relevant page.
 */
self.addEventListener('notificationclick', (event) => {
    event.notification.close();

    const url = event.notification.data?.url || '/';

    event.waitUntil(
        self.clients.matchAll({ type: 'window', includeUncontrolled: true }).then((clientList) => {
            // Focus existing window if available
            for (const client of clientList) {
                if (client.url.includes(self.location.origin) && 'focus' in client) {
                    client.focus();
                    client.navigate(url);
                    return;
                }
            }
            // Otherwise open a new window
            if (self.clients.openWindow) {
                return self.clients.openWindow(url);
            }
        })
    );
});

import React, { useState } from 'react';
import { createPortal } from 'react-dom';
import { Trash2, AlertTriangle, Check, Loader2, X } from 'lucide-react';

interface BatchDeleteModalProps {
    isOpen: boolean;
    onClose: () => void;
    onConfirm: () => Promise<any>;
    title: string;
    message: string;
    itemCount: number;
    itemName: string;
    confirmLabel?: string; // New prop for explicit confirmation checkbox
}

const BatchDeleteModal: React.FC<BatchDeleteModalProps> = ({
    isOpen,
    onClose,
    onConfirm,
    title,
    message,
    itemCount,
    itemName,
    confirmLabel
}) => {
    const [isDeleting, setIsDeleting] = useState(false);
    const [result, setResult] = useState<{ deleted: number; failed: number; errors: string[] } | null>(null);
    const [isConfirmed, setIsConfirmed] = useState(false); // State for checkbox

    // Reset checkbox when opening/closing
    React.useEffect(() => {
        if (isOpen) setIsConfirmed(false);
    }, [isOpen]);

    const handleConfirm = async () => {
        if (confirmLabel && !isConfirmed) return; // Prevent if not confirmed
        setIsDeleting(true);
        try {
            const res = await onConfirm();
            setResult(res);
        } catch (error) {
            console.error(error);
            setResult({ deleted: 0, failed: itemCount, errors: ["Lß╗ùi kh├┤ng x├íc ─æß╗ïnh"] });
        } finally {
            setIsDeleting(false);
        }
    };

    const handleClose = () => {
        if (result) {
            // Reset state when closing after success
            setResult(null);
            setIsDeleting(false);
        }
        onClose();
    };

    if (!isOpen) return null;

    return createPortal(
        <div className="fixed inset-0 z-[110] flex items-center justify-center p-4">
            <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm animate-fade-in" onClick={handleClose} />

            {!result ? (
                /* Confirmation Modal (Classic Style) */
                <div className="relative bg-white rounded-2xl shadow-xl w-full max-w-sm overflow-hidden animate-in zoom-in-95 duration-300 p-6">
                    <div className="text-center">
                        <div className="w-16 h-16 bg-rose-100 rounded-full flex items-center justify-center mx-auto mb-4">
                            <Trash2 className="w-8 h-8 text-rose-600" />
                        </div>

                        <h3 className="text-lg font-bold text-slate-900 mb-2">{title}</h3>

                        <div className="p-4 bg-rose-50 rounded-xl border border-rose-100 flex gap-3 text-left mb-6">
                            <AlertTriangle className="w-5 h-5 text-rose-600 flex-shrink-0 mt-0.5" />
                            <div className="space-y-1">
                                <p className="text-sm font-bold text-rose-900">
                                    H├ánh ─æß╗Öng kh├┤ng thß╗â ho├án t├íc!
                                </p>
                                <p className="text-[13px] text-rose-700 leading-relaxed">
                                    Bß║ín ─æang chuß║⌐n bß╗ï x├│a <strong className="text-slate-900">{itemCount} {itemName}</strong>.{' '}
                                    {message}
                                </p>
                            </div>
                        </div>

                        {/* Simple Confirmation Checkbox */}
                        {confirmLabel && (
                            <div className="mb-6 flex items-start gap-3 text-left p-3 rounded-lg border border-slate-200 bg-slate-50 hover:bg-slate-100 transition-colors cursor-pointer" onClick={() => setIsConfirmed(!isConfirmed)}>
                                <div className={`mt-0.5 w-5 h-5 rounded border-2 flex items-center justify-center transition-colors ${isConfirmed ? 'bg-blue-600 border-blue-600' : 'border-slate-300 bg-white'}`}>
                                    {isConfirmed && <Check className="w-3.5 h-3.5 text-white" />}
                                </div>
                                <label className="text-xs font-semibold text-slate-600 cursor-pointer select-none flex-1 py-0.5">
                                    {confirmLabel}
                                </label>
                            </div>
                        )}

                        <div className="flex gap-3">
                            <button
                                onClick={onClose}
                                disabled={isDeleting}
                                className="flex-1 px-4 py-2.5 rounded-xl border border-slate-200 text-slate-600 font-bold hover:bg-slate-50 transition-all disabled:opacity-50 text-sm"
                            >
                                Hß╗ºy bß╗Å
                            </button>
                            <button
                                onClick={handleConfirm}
                                disabled={isDeleting || (!!confirmLabel && !isConfirmed)}
                                className="flex-1 px-4 py-2.5 rounded-xl bg-rose-600 text-white font-bold hover:bg-rose-700 transition-all flex items-center justify-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed shadow-lg shadow-rose-100"
                            >
                                {isDeleting ? (
                                    <>
                                        <Loader2 className="w-4 h-4 animate-spin" />
                                        <span>─Éang x├│a...</span>
                                    </>
                                ) : (
                                    <span>X├íc nhß║¡n</span>
                                )}
                            </button>
                        </div>
                    </div>
                </div>
            ) : (
                /* Result Modal (Standarized with Import) */
                <div className="relative bg-white rounded-2xl shadow-2xl w-full max-w-xl mx-4 overflow-hidden flex flex-col z-[110] max-h-[90vh] animate-in zoom-in-95 duration-300">
                    {/* Header */}
                    <div className={`px-6 py-5 flex-none ${result.failed > 0 ? 'bg-gradient-to-r from-amber-500 to-orange-400' : 'bg-gradient-to-r from-emerald-600 to-emerald-500'}`}>
                        <div className="flex items-center justify-between">
                            <h3 className="text-lg font-bold text-white tracking-tight">{title} - Kß║┐t quß║ú</h3>
                            <button onClick={handleClose} className="p-1.5 rounded-lg bg-white/10 text-white hover:bg-white/20 transition-all">
                                <X className="w-5 h-5" />
                            </button>
                        </div>
                    </div>

                    <div className="p-6 overflow-y-auto custom-scrollbar">
                        {/* Stats Grid */}
                        <div className="grid grid-cols-3 gap-3 mb-8">
                            <div className="text-center p-4 bg-slate-50/50 rounded-2xl border border-slate-100 shadow-sm">
                                <div className="text-2xl font-extrabold text-slate-800">{result.deleted + result.failed}</div>
                                <div className="text-xs font-bold text-slate-400 uppercase tracking-wider mt-1">Tß╗òng sß╗æ</div>
                            </div>
                            <div className="text-center p-4 bg-emerald-50/50 rounded-2xl border border-emerald-100/80 shadow-sm">
                                <div className="text-2xl font-extrabold text-emerald-600">{result.deleted}</div>
                                <div className="text-xs font-bold text-emerald-600 uppercase tracking-wider mt-1">Th├ánh c├┤ng</div>
                            </div>
                            <div className="text-center p-4 bg-rose-50/50 rounded-2xl border border-rose-100/80 shadow-sm">
                                <div className="text-2xl font-extrabold text-rose-600">{result.failed}</div>
                                <div className="text-xs font-bold text-rose-600 uppercase tracking-wider mt-1">Thß║Ñt bß║íi</div>
                            </div>
                        </div>

                        {/* Error Details */}
                        {result.failed > 0 && result.errors.length > 0 && (
                            <div className="space-y-3">
                                <p className="text-sm font-bold text-slate-700 flex items-center gap-2 px-1">
                                    <div className="w-1 h-4 bg-rose-500 rounded-full"></div>
                                    Chi tiß║┐t c├íc tr╞░ß╗¥ng hß╗úp lß╗ùi:
                                </p>
                                <div className="max-h-60 overflow-y-auto bg-slate-50/50 border border-slate-200/60 rounded-2xl divide-y divide-slate-100 custom-scrollbar shadow-sm">
                                    {result.errors.map((err, idx) => {
                                        // Detect "Label [Name]: Message" pattern to bold the name
                                        const colonIndex = err.indexOf(':');
                                        const namePart = colonIndex !== -1 ? err.substring(0, colonIndex + 1) : '';
                                        const messagePart = colonIndex !== -1 ? err.substring(colonIndex + 1) : err;

                                        return (
                                            <div key={idx} className="p-3.5 text-sm flex gap-3 hover:bg-white transition-colors group">
                                                <div className="font-bold text-rose-600 shrink-0 bg-rose-50 px-2.5 py-1 rounded-lg h-fit text-xs">Mß╗Ñc {idx + 1}</div>
                                                <div className="text-slate-600 leading-relaxed py-0.5">
                                                    {namePart && <span className="font-black text-slate-800">{namePart}</span>}
                                                    {messagePart}
                                                </div>
                                            </div>
                                        );
                                    })}
                                </div>
                            </div>
                        )}

                        {result.failed === 0 && (
                            <div className="py-4 px-6 text-center bg-emerald-50/60 rounded-2xl border border-emerald-100/60 mt-2 animate-in fade-in zoom-in duration-300 shadow-sm border-dashed">
                                <p className="text-emerald-800 font-bold text-base">Ho├án tß║Ñt xß╗¡ l├╜</p>
                                <p className="text-emerald-600 text-sm mt-1 font-medium italic">Tß║Ñt cß║ú dß╗» liß╗çu ─æ├ú ─æ╞░ß╗úc giß║úi quyß║┐t th├ánh c├┤ng!</p>
                            </div>
                        )}

                        <div className="mt-6">
                            <button
                                onClick={handleClose}
                                className="w-full px-5 py-2.5 rounded-xl border border-slate-200 text-slate-700 font-bold hover:bg-slate-50 transition-all text-sm shadow-sm"
                            >
                                ─É├│ng
                            </button>
                        </div>
                    </div>
                </div>
            )}
        </div>,
        document.body
    );
};

export default BatchDeleteModal;

import React from "react";

/**
 * Custom text input for date fields, used with react-datepicker.
 * Accepts rawValue to display the typed DD/MM/YYYY string.
 */
const CustomDateInput = React.forwardRef<HTMLInputElement, {
    value?: string;
    onClick?: () => void;
    onChange?: (e: React.ChangeEvent<HTMLInputElement>) => void;
    placeholder?: string;
    rawValue?: string;
    className?: string; // Add this line
}>(({ value, onClick, onChange, placeholder, rawValue, className, ...props }, ref) => (
    <input
        {...props}
        ref={ref}
        type="text"
        value={rawValue}
        onClick={onClick}
        onChange={onChange}
        placeholder={placeholder}
        className={className || "w-full px-3 py-2 rounded-lg border border-slate-200 focus:border-blue-500 outline-none"} // Use default if no className passed
        maxLength={10}
    />
));

CustomDateInput.displayName = "CustomDateInput";

export default CustomDateInput;

import { useState, useEffect, useRef, useCallback } from "react";
import { ClipboardList, Calendar, Bell, Settings } from "lucide-react";
import api from "../../services/api";

// ==================== TYPES ====================

type NotificationItem = {
    id: string;
    title: string;
    content: string;
    type?: string;
    createdAt: string;
    isRead: boolean;
};

type Props = {
    role: "system" | "school-admin" | "teacher";
};

// ==================== ICON MAPS ====================

const TYPE_ICONS: Record<string, React.ElementType> = {
    EXAM: ClipboardList,
    SCHEDULE: Calendar,
    OTHER: Bell,
    SYSTEM: Settings,
};

// ==================== COMPONENT ====================

export default function NotificationDropdown({ role }: Props) {
    const [open, setOpen] = useState(false);
    const [notifications, setNotifications] = useState<NotificationItem[]>([]);
    const [loading, setLoading] = useState(false);
    const dropdownRef = useRef<HTMLDivElement>(null);

    const fetchNotifications = useCallback(async () => {
        setLoading(true);
        try {
            let data: NotificationItem[] = [];

            if (role === "system") {
                const res = await api.get("/system/notifications");
                data = (res.data || []).map((n: any) => ({
                    id: n.id,
                    title: n.title,
                    content: n.message || n.content || "",
                    type: "SYSTEM",
                    createdAt: n.createdAt,
                    isRead: false,
                }));
            } else if (role === "teacher") {
                const res = await api.get("/teacher/notifications");
                data = (res.data || []).map((n: any) => ({
                    id: n.id,
                    title: n.title,
                    content: n.content || "",
                    type: n.notificationType || "OTHER",
                    createdAt: n.createdAt,
                    isRead: false,
                }));
            } else if (role === "school-admin") {
                // School admin uses system notifications scoped to their school
                const res = await api.get("/system/notifications");
                data = (res.data || []).map((n: any) => ({
                    id: n.id,
                    title: n.title,
                    content: n.message || n.content || "",
                    type: "SYSTEM",
                    createdAt: n.createdAt,
                    isRead: false,
                }));
            }

            setNotifications(data.slice(0, 10)); // Show latest 10
        } catch (err) {
            console.error("Failed to load notifications:", err);
            setNotifications([]);
        } finally {
            setLoading(false);
        }
    }, [role]);

    useEffect(() => {
        if (open) {
            fetchNotifications();
        }
    }, [open, fetchNotifications]);

    // Close on click outside
    useEffect(() => {
        const handleClickOutside = (e: MouseEvent) => {
            if (dropdownRef.current && !dropdownRef.current.contains(e.target as Node)) {
                setOpen(false);
            }
        };
        if (open) {
            document.addEventListener("mousedown", handleClickOutside);
        }
        return () => document.removeEventListener("mousedown", handleClickOutside);
    }, [open]);

    const markAllRead = () => {
        setNotifications((prev) => prev.map((n) => ({ ...n, isRead: true })));
    };

    const unreadCount = notifications.filter((n) => !n.isRead).length;

    const formatTime = (dateStr: string) => {
        try {
            const date = new Date(dateStr);
            const now = new Date();
            const diffMs = now.getTime() - date.getTime();
            const diffMin = Math.floor(diffMs / 60000);

            if (diffMin < 1) return "Vß╗½a xong";
            if (diffMin < 60) return `${diffMin} ph├║t tr╞░ß╗¢c`;
            const diffHours = Math.floor(diffMin / 60);
            if (diffHours < 24) return `khoß║úng ${diffHours} giß╗¥ tr╞░ß╗¢c`;
            const diffDays = Math.floor(diffHours / 24);
            if (diffDays < 7) return `${diffDays} ng├áy tr╞░ß╗¢c`;
            return date.toLocaleDateString("vi-VN");
        } catch {
            return dateStr;
        }
    };

    const getNotificationPath = () => {
        if (role === "system") return "/system/notifications";
        if (role === "school-admin") return "/school-admin/notifications";
        if (role === "teacher") return "/teacher/notifications";
        if (role === "guardian") return "/guardian/notification";
        if (role === "student") return "/student/overview";
        return "#";
    };

    return (
        <div className="relative" ref={dropdownRef}>
            {/* Bell Button */}
            <button
                onClick={() => setOpen(!open)}
                className="relative p-2 text-gray-500 hover:text-gray-700 hover:bg-gray-100 rounded-lg transition-colors dark:text-gray-400 dark:hover:text-gray-200 dark:hover:bg-gray-700"
                aria-label="Th├┤ng b├ío"
            >
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 17h5l-1.405-1.405A2.032 2.032 0 0118 14.158V11a6.002 6.002 0 00-4-5.659V5a2 2 0 10-4 0v.341C7.67 6.165 6 8.388 6 11v3.159c0 .538-.214 1.055-.595 1.436L4 17h5m6 0v1a3 3 0 11-6 0v-1m6 0H9" />
                </svg>
                {unreadCount > 0 && (
                    <span className="absolute -top-0.5 -right-0.5 min-w-[18px] h-[18px] flex items-center justify-center bg-red-500 text-white text-[10px] font-bold rounded-full px-1">
                        {unreadCount > 9 ? "9+" : unreadCount}
                    </span>
                )}
            </button>

            {/* Dropdown Panel */}
            {open && (
                <div className="absolute right-0 top-full mt-2 w-96 bg-white dark:bg-gray-800 rounded-2xl shadow-2xl border border-gray-200 dark:border-gray-700 z-50 overflow-hidden animate-in fade-in slide-in-from-top-2 duration-200">
                    {/* Header */}
                    <div className="px-4 py-3 border-b border-gray-100 dark:border-gray-700 flex items-center justify-between">
                        <div>
                            <h3 className="font-semibold text-gray-900 dark:text-white text-sm">Th├┤ng b├ío</h3>
                            {unreadCount > 0 && (
                                <p className="text-xs text-gray-500 dark:text-gray-400">{unreadCount} th├┤ng b├ío ch╞░a ─æß╗ìc</p>
                            )}
                        </div>
                        {unreadCount > 0 && (
                            <button
                                onClick={markAllRead}
                                className="text-xs text-blue-600 dark:text-blue-400 hover:text-blue-700 dark:hover:text-blue-300 font-medium flex items-center gap-1"
                            >
                                <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" />
                                </svg>
                                ─É├ính dß║Ñu tß║Ñt cß║ú
                            </button>
                        )}
                    </div>

                    {/* List */}
                    <div className="max-h-80 overflow-y-auto">
                        {loading ? (
                            <div className="py-8 text-center">
                                <div className="w-6 h-6 border-2 border-gray-200 dark:border-gray-600 border-t-blue-500 rounded-full animate-spin mx-auto mb-2" />
                                <p className="text-xs text-gray-500 dark:text-gray-400">─Éang tß║úi...</p>
                            </div>
                        ) : notifications.length === 0 ? (
                            <div className="py-10 text-center">
                                <div className="text-3xl mb-2">≡ƒô¡</div>
                                <p className="text-sm text-gray-500 dark:text-gray-400">Kh├┤ng c├│ th├┤ng b├ío n├áo</p>
                            </div>
                        ) : (
                            notifications.map((notif) => (
                                <div
                                    key={notif.id}
                                    className={`px-4 py-3 hover:bg-gray-50 dark:hover:bg-gray-700/50 transition-colors cursor-pointer border-b border-gray-50 dark:border-gray-700/50 last:border-0 flex gap-3 ${!notif.isRead ? "bg-blue-50/50 dark:bg-blue-900/10" : ""
                                        }`}
                                    onClick={() => {
                                        setNotifications((prev) =>
                                            prev.map((n) => (n.id === notif.id ? { ...n, isRead: true } : n))
                                        );
                                    }}
                                >
                                    {/* Icon */}
                                    <div className="flex-shrink-0 w-9 h-9 rounded-full bg-blue-50 dark:bg-blue-900/30 flex items-center justify-center text-blue-600 dark:text-blue-400">
                                        {(() => {
                                            const Icon = TYPE_ICONS[notif.type || "OTHER"] || Bell;
                                            return <Icon className="w-5 h-5" />;
                                        })()}
                                    </div>

                                    {/* Content */}
                                    <div className="flex-1 min-w-0">
                                        <div className="flex items-start justify-between gap-2">
                                            <h4 className={`text-sm leading-snug ${!notif.isRead ? "font-semibold text-gray-900 dark:text-white" : "font-medium text-gray-700 dark:text-gray-300"}`}>
                                                {notif.title}
                                            </h4>
                                            {!notif.isRead && (
                                                <span className="flex-shrink-0 w-2 h-2 bg-blue-500 rounded-full mt-1.5" />
                                            )}
                                        </div>
                                        <p className="text-xs text-gray-500 dark:text-gray-400 mt-0.5 line-clamp-2 leading-relaxed">
                                            {notif.content}
                                        </p>
                                        <p className="text-[11px] text-gray-400 dark:text-gray-500 mt-1">
                                            {formatTime(notif.createdAt)}
                                        </p>
                                    </div>
                                </div>
                            ))
                        )}
                    </div>

                    {/* Footer */}
                    {notifications.length > 0 && (
                        <div className="px-4 py-2.5 border-t border-gray-100 dark:border-gray-700 text-center">
                            <a
                                href={getNotificationPath()}
                                className="text-sm text-blue-600 dark:text-blue-400 hover:text-blue-700 dark:hover:text-blue-300 font-medium"
                                onClick={() => setOpen(false)}
                            >
                                Xem tß║Ñt cß║ú th├┤ng b├ío
                            </a>
                        </div>
                    )}
                </div>
            )}
        </div>
    );
}

import React from "react";

// Student status type
export type StudentStatus = 'ACTIVE' | 'GRADUATED' | 'TRANSFERRED' | 'SUSPENDED' | string;

// Status config
const statusConfig: Record<string, { label: string; bgColor: string; textColor: string }> = {
    ACTIVE: {
        label: "─Éang hß╗ìc",
        bgColor: "bg-green-100",
        textColor: "text-green-700",
    },
    GRADUATED: {
        label: "─É├ú tß╗æt nghiß╗çp",
        bgColor: "bg-blue-100",
        textColor: "text-blue-700",
    },
    TRANSFERRED: {
        label: "Chuyß╗ân tr╞░ß╗¥ng",
        bgColor: "bg-yellow-100",
        textColor: "text-yellow-700",
    },
    SUSPENDED: {
        label: "Tß║ím nghß╗ë",
        bgColor: "bg-red-100",
        textColor: "text-red-700",
    },
};

const defaultConfig = {
    label: "Kh├┤ng x├íc ─æß╗ïnh",
    bgColor: "bg-gray-100",
    textColor: "text-gray-600",
};

interface StatusBadgeProps {
    status: StudentStatus;
    size?: "sm" | "md";
