export async function requestFCMToken(vapidKey: string): Promise<string | null> {
    try {
        const messaging = await getFirebaseMessaging();
        if (!messaging) return null;

        // Check current permission state first to avoid triggering the blocked prompt repeatedly
        if (Notification.permission === "denied") {
            // Permission was previously denied ΓÇö don't request again
            return null;
        }

        const permission = await Notification.requestPermission();
        if (permission !== "granted") {
            console.warn("Notification permission denied.");
            return null;
        }

        const token = await getToken(messaging, { vapidKey });
        return token;
    } catch (error) {
        console.error("Error getting FCM token:", error);
        return null;
    }
}

