function extractMessage(err: unknown): string {
  if (typeof err === "object" && err && "response" in err) {
    const anyErr = err as any;
    return anyErr?.response?.data?.message || "X├íc minh thß║Ñt bß║íi.";
  }
  return "X├íc minh thß║Ñt bß║íi.";
}

export default function VerifyPage() {
  const navigate = useNavigate();
  const { getPendingChallenge, setResetToken } = useAuth();
  const pending = getPendingChallenge();

  const [code, setCode] = useState("");
  const [error, setError] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [resending, setResending] = useState(false);

  if (!pending?.challengeId) {
    return (
      <AuthCard title="Verify" subtitle="Kh├┤ng t├¼m thß║Ñy y├¬u cß║ºu x├íc minh.">
        <Link className="underline text-white" to="/login">Quay lß║íi ─æ─âng nhß║¡p</Link>
      </AuthCard>
    );
  }

  const onSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);
    setLoading(true);
    try {
      const res = await authService.verifyOtp(pending.challengeId, code.trim());
      setResetToken(res.resetToken);
      navigate("/new-password");
    } catch (err) {
      setError(extractMessage(err));
    } finally {
      setLoading(false);
