            value={code}
            onChange={(e) => setCode(e.target.value)}
            placeholder="Nhß║¡p 6 chß╗» sß╗æ"
            inputMode="numeric"
          />
        </div>

        <button
          disabled={loading}
          className="w-full rounded-xl bg-slate-950 py-3 text-sm font-semibold text-white shadow-sm hover:bg-slate-900 disabled:opacity-60"
        >
          {loading ? "─Éang x├íc nhß║¡n..." : "X├íc nhß║¡n"}
        </button>

        <button
          type="button"
          disabled={resending}
          onClick={resend}
          className="w-full text-sm text-slate-600 hover:text-slate-900 disabled:opacity-60 mt-4"
        >
          Gß╗¡i lß║íi m├ú x├íc minh
        </button>

        <div className="mt-4 rounded-xl border border-amber-200 bg-amber-50 px-4 py-3 text-sm text-amber-700">
          <div className="flex items-start gap-2">
            <WarnIcon />
            <span>M├ú x├íc minh c├│ hiß╗çu lß╗▒c trong 5 ph├║t. Nß║┐u kh├┤ng nhß║¡n ─æ╞░ß╗úc email, vui l├▓ng kiß╗âm tra hß╗Öp th╞░ spam.</span>
          </div>
