                                    </select>
                                </div>
                                <div className="col-span-2 sm:col-span-1">
                                    <label className="block text-sm font-medium text-gray-700 mb-1.5">N─âm hß╗ìc <span className="text-red-500">*</span></label>
                                    <select
                                        value={academicYear}
