                                    <ul className="list-disc pl-5 space-y-1 text-sm text-red-600 max-h-40 overflow-y-auto">
                                        {result.errors.map((err, i) => (
                                            <li key={i}>{err}</li>
                                        ))}
                                    </ul>
                                </div>
                            )}
