import React, { useState } from "react";
import { createPortal } from "react-dom";
import DatePicker from "react-datepicker";
import { vi } from "date-fns/locale";
import "react-datepicker/dist/react-datepicker.css";
import {
    schoolAdminService,
    type ClassRoomDto,
    type CreateStudentRequest,
    type CombinationDto
} from "../../../../services/schoolAdminService";
import { semesterService, type AcademicYearDto } from "../../../../services/semesterService";
import { XIcon } from "../../SchoolAdminIcons";
import { formatDateInput, parseDateDDMMYYYY } from "../../../../utils/dateHelpers";
import CustomDateInput from "../../../../components/common/CustomDateInput";

interface AddStudentModalProps {
    isOpen: boolean;
    onClose: () => void;
    onSuccess: () => void;
    classes: ClassRoomDto[];
    combinations: CombinationDto[];
    defaultAcademicYear: string;
}

function AddStudentModal({ isOpen, onClose, onSuccess, classes, combinations, defaultAcademicYear }: AddStudentModalProps) {
    const [fullName, setFullName] = useState("");
    const [dateOfBirth, setDateOfBirth] = useState<Date | null>(null);
    const [dateInputValue, setDateInputValue] = useState("");
    const [gender, setGender] = useState<'MALE' | 'FEMALE' | 'OTHER'>("MALE");
    const [birthPlace, setBirthPlace] = useState("");
    const [address, setAddress] = useState("");
    const [email, setEmail] = useState("");
    const [phone, setPhone] = useState("");
    const [academicYear, setAcademicYear] = useState(defaultAcademicYear);
    const [classId, setClassId] = useState("");
    // Assignment state
    const [assignmentMode, setAssignmentMode] = useState<'MANUAL' | 'AUTO'>("MANUAL");
    const [autoGrade, setAutoGrade] = useState<number>(10);
    const [autoCombinationId, setAutoCombinationId] = useState("");
    const [manualCombinationId, setManualCombinationId] = useState("");

    const [guardianName, setGuardianName] = useState("");
    const [guardianPhone, setGuardianPhone] = useState("");
    const [guardianEmail, setGuardianEmail] = useState("");
    const [guardianRelationship, setGuardianRelationship] = useState("");
    const [academicYears, setAcademicYears] = useState<AcademicYearDto[]>([]);
    const [loading, setLoading] = useState(false);
    const [loadingYears, setLoadingYears] = useState(false);
    const [error, setError] = useState<string | null>(null);

    React.useEffect(() => {
        if (isOpen) {
            fetchAcademicYears();
        }
    }, [isOpen]);

    const fetchAcademicYears = async () => {
        setLoadingYears(true);
        try {
            const years = await semesterService.listAcademicYears();
            const filtered = years.filter(y => y.status === 'ACTIVE' || y.status === 'UPCOMING');
            setAcademicYears(filtered);

            // If current academicYear is not in the list, set to active if possible
            if (filtered.length > 0) {
                const activeYear = filtered.find(y => y.status === 'ACTIVE');
                if (activeYear && !academicYear) {
                    setAcademicYear(activeYear.name);
                } else if (!academicYear) {
                    setAcademicYear(filtered[0].name);
                }
            }
        } catch (err) {
            console.error("Failed to fetch academic years", err);
        } finally {
            setLoadingYears(false);
        }
    };

    const filteredClasses = classes.filter(c => c.academicYear === academicYear);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setLoading(true);
        setError(null);

        // Validation: Required fields
        if (!fullName.trim()) {
            setError("Vui l├▓ng nhß║¡p hß╗ì v├á t├¬n hß╗ìc sinh");
            setLoading(false);
            return;
        }
        if (!dateOfBirth) {
            setError("Vui l├▓ng nhß║¡p ng├áy sinh");
            setLoading(false);
            return;
        }

        // Age validation: student must be at least 14
        {
            const today = new Date();
            let age = today.getFullYear() - dateOfBirth.getFullYear();
            const mDiff = today.getMonth() - dateOfBirth.getMonth();
            if (mDiff < 0 || (mDiff === 0 && today.getDate() < dateOfBirth.getDate())) age--;
            if (age < 14) {
                setError("Hß╗ìc sinh phß║úi ─æß╗º 14 tuß╗òi trß╗ƒ l├¬n.");
                setLoading(false);
                return;
            }
        }

        // UI Validation: If guardian email is provided, name is required
        if (guardianEmail && !guardianName) {
            setError("Vui l├▓ng nhß║¡p t├¬n phß╗Ñ huynh nß║┐u muß╗æn tß║ío t├ái khoß║ún");
            setLoading(false);
            return;
        }

        try {
            let dateOfBirthStr: string | undefined = undefined;
            if (dateOfBirth) {
                const year = dateOfBirth.getFullYear();
                const month = String(dateOfBirth.getMonth() + 1).padStart(2, '0');
                const day = String(dateOfBirth.getDate()).padStart(2, '0');
                dateOfBirthStr = `${year}-${month}-${day}`;
            }

            const req: CreateStudentRequest = {
                fullName: fullName.trim(),
                dateOfBirth: dateOfBirthStr,
                gender,
                birthPlace: birthPlace.trim() || undefined,
                address: address.trim() || undefined,
                email: email.trim() || undefined,
                phone: phone.trim() || undefined,
                classId: assignmentMode === 'MANUAL' ? (classId || undefined) : undefined,
                academicYear: academicYear,
                grade: assignmentMode === 'AUTO' ? autoGrade : undefined,
                combinationId: assignmentMode === 'AUTO' ? (autoCombinationId || undefined) : (manualCombinationId || undefined),
                guardian: guardianName ? {
                    fullName: guardianName.trim(),
                    phone: guardianPhone.trim() || undefined,
                    email: guardianEmail.trim() || undefined,
                    relationship: guardianRelationship.trim() || undefined,
                } : undefined,
            };
            await schoolAdminService.createStudent(req);
            setFullName(""); setDateOfBirth(null); setDateInputValue(""); setGender("MALE");
            setBirthPlace(""); setAddress(""); setEmail(""); setPhone("");
            setClassId(""); setAssignmentMode("MANUAL"); setAutoGrade(10); setAutoCombinationId(""); setManualCombinationId("");
            setGuardianName(""); setGuardianPhone(""); setGuardianEmail(""); setGuardianRelationship("");
            onSuccess();
            onClose();
        } catch (err: any) {
            setError(err?.response?.data?.message || "Kh├┤ng thß╗â th├¬m hß╗ìc sinh.");
        } finally {
            setLoading(false);
        }
    };

    if (!isOpen) return null;

    return createPortal(
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
