import { useState } from "react";
import { createPortal } from "react-dom";
import { schoolAdminService, type StudentDto } from "../../../../services/schoolAdminService";

interface DeleteStudentModalProps {
    isOpen: boolean;
    student: StudentDto | null;
    onClose: () => void;
    onSuccess: () => void;
}

function DeleteStudentModal({ isOpen, student, onClose, onSuccess }: DeleteStudentModalProps) {
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState<string | null>(null);
    const [isConfirmed, setIsConfirmed] = useState(false);

    // Reset confirmation when modal opens
    if (!isOpen && isConfirmed) setIsConfirmed(false);

    const handleDelete = async () => {
        if (!student) return;
        setLoading(true);
        setError(null);

        try {
            const result = await schoolAdminService.bulkDeleteStudents([student.id]);
            if (result.deleted > 0) {
                onSuccess();
                onClose();
            } else if (result.failed > 0 && result.errors.length > 0) {
                setError(result.errors[0]);
            } else {
                setError("Kh├┤ng thß╗â x├│a hß╗ìc sinh. Vui l├▓ng thß╗¡ lß║íi.");
            }
        } catch (err: any) {
            setError(err?.response?.data?.message || "Lß╗ùi hß╗ç thß╗æng.");
        } finally {
            setLoading(false);
        }
    };

    if (!isOpen || !student) return null;

    return createPortal(
        <div className="fixed inset-0 z-[100] flex items-center justify-center">
            <div className="absolute inset-0 bg-black/60 backdrop-blur-sm" onClick={onClose} />
            <div className="relative bg-white rounded-2xl shadow-2xl w-full max-w-sm mx-4 p-6">
                <div className="text-center">
                    <div className="w-16 h-16 bg-red-100 rounded-full flex items-center justify-center mx-auto mb-4">
                        <svg className="w-8 h-8 text-red-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                        </svg>
                    </div>
                    <h3 className="text-lg font-semibold text-gray-900 mb-2">X├│a hß╗ìc sinh?</h3>
                    <p className="text-gray-600 mb-4">Bß║ín c├│ chß║»c muß╗æn x├│a hß╗ìc sinh <span className="font-semibold text-gray-900">{student.fullName}</span>? H├ánh ─æß╗Öng n├áy kh├┤ng thß╗â ho├án t├íc.</p>
                    {student.hasAccount && (
                        <div className="mb-4 text-left bg-yellow-50 p-3 rounded-lg border border-yellow-200">
                            <p className="text-sm text-yellow-800 mb-2 font-medium">Cß║únh b├ío: Hß╗ìc sinh n├áy ─æang c├│ t├ái khoß║ún hß╗ç thß╗æng.</p>
                            <div className="flex items-start gap-2 cursor-pointer" onClick={() => setIsConfirmed(!isConfirmed)}>
                                <div className={`mt-0.5 w-4 h-4 rounded border flex items-center justify-center transition-colors ${isConfirmed ? 'bg-blue-600 border-blue-600' : 'border-gray-400 bg-white'}`}>
                                    {isConfirmed && <svg className="w-3 h-3 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" /></svg>}
                                </div>
                                <label className="text-sm text-gray-700 cursor-pointer select-none">
                                    T├┤i x├íc nhß║¡n x├│a hß╗ô s╞í v├á t├ái khoß║ún cß╗ºa hß╗ìc sinh n├áy
                                </label>
                            </div>
                        </div>
                    )}

                    {error && <div className="bg-red-50 border border-red-200 text-red-700 px-4 py-2 rounded-lg text-sm mb-4">{error}</div>}

                    <div className="flex gap-3">
                        <button onClick={onClose} className="flex-1 px-4 py-2 rounded-lg border border-slate-200 text-slate-700 font-medium hover:bg-slate-50">Hß╗ºy</button>
                        <button
                            onClick={handleDelete}
                            disabled={loading || (student.hasAccount && !isConfirmed)}
                            className="flex-1 px-4 py-2 rounded-lg bg-red-600 text-white font-medium hover:bg-red-700 disabled:opacity-50 disabled:cursor-not-allowed"
                        >
                            {loading ? "─Éang x├│a..." : "X├│a"}
                        </button>
                    </div>
                </div>
            </div>
        </div>,
        document.body
    );
}

export default DeleteStudentModal;

import React, { useEffect, useState } from "react";
import { createPortal } from "react-dom";
import DatePicker from "react-datepicker";
import { vi } from "date-fns/locale";
import "react-datepicker/dist/react-datepicker.css";
import {
    schoolAdminService,
    type StudentDto,
    type ClassRoomDto,
    type UpdateStudentRequest,
    type CombinationDto
} from "../../../../services/schoolAdminService";
import { XIcon } from "../../SchoolAdminIcons";
import { formatDateInput, parseDateDDMMYYYY } from "../../../../utils/dateHelpers";
import CustomDateInput from "../../../../components/common/CustomDateInput";

interface EditStudentModalProps {
    isOpen: boolean;
    student: StudentDto | null;
    classes: ClassRoomDto[];
    combinations: CombinationDto[];
    onClose: () => void;
    onSuccess: () => void;
}

function EditStudentModal({ isOpen, student, classes, combinations, onClose, onSuccess }: EditStudentModalProps) {
    const [fullName, setFullName] = useState("");
    const [dateOfBirth, setDateOfBirth] = useState<Date | null>(null);
    const [dateInputValue, setDateInputValue] = useState("");
    const [gender, setGender] = useState<'MALE' | 'FEMALE' | 'OTHER'>("MALE");
    const [birthPlace, setBirthPlace] = useState("");
    const [address, setAddress] = useState("");
    const [email, setEmail] = useState("");
    const [phone, setPhone] = useState("");
    const [status, setStatus] = useState<'ACTIVE' | 'GRADUATED' | 'TRANSFERRED' | 'SUSPENDED'>("ACTIVE");
    const [classId, setClassId] = useState("");
    const [combinationId, setCombinationId] = useState("");
    const [guardianName, setGuardianName] = useState("");
    const [guardianPhone, setGuardianPhone] = useState("");
    const [guardianEmail, setGuardianEmail] = useState("");
    const [guardianRelationship, setGuardianRelationship] = useState("");
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState<string | null>(null);

    // Initialize form when student changes
    useEffect(() => {
        if (student) {
            setFullName(student.fullName || "");
            setGender((student.gender as 'MALE' | 'FEMALE' | 'OTHER') || "MALE");
            setBirthPlace(student.birthPlace || "");
            setAddress(student.address || "");
            setEmail(student.email || "");
            setPhone(student.phone || "");
            setStatus((student.status as 'ACTIVE' | 'GRADUATED' | 'TRANSFERRED' | 'SUSPENDED') || "ACTIVE");
            setClassId(student.currentClassId || "");
            setCombinationId(student.combinationId || "");

            // Set date of birth
            if (student.dateOfBirth) {
                try {
                    const date = new Date(student.dateOfBirth);
                    if (!isNaN(date.getTime())) {
                        setDateOfBirth(date);
                        const day = String(date.getDate()).padStart(2, '0');
                        const month = String(date.getMonth() + 1).padStart(2, '0');
                        const year = date.getFullYear();
                        setDateInputValue(`${day}/${month}/${year}`);
                    }
                } catch {
                    setDateOfBirth(null);
                    setDateInputValue("");
                }
            } else {
                setDateOfBirth(null);
                setDateInputValue("");
            }

            // Set guardian info
            if (student.guardian) {
                setGuardianName(student.guardian.fullName || "");
                setGuardianPhone(student.guardian.phone || "");
                setGuardianEmail(student.guardian.email || "");
                setGuardianRelationship(student.guardian.relationship || "");
            } else {
                setGuardianName("");
                setGuardianPhone("");
                setGuardianEmail("");
                setGuardianRelationship("");
            }

            setError(null);
        }
    }, [student]);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!student) return;

        setLoading(true);
        setError(null);

        // Validation: Required fields
        if (!fullName.trim()) {
            setError("Vui l├▓ng nhß║¡p hß╗ì v├á t├¬n hß╗ìc sinh");
            setLoading(false);
            return;
        }
        if (!dateOfBirth) {
            setError("Vui l├▓ng nhß║¡p ng├áy sinh");
            setLoading(false);
            return;
        }

        // Age validation: student must be at least 14
        {
            const today = new Date();
            let age = today.getFullYear() - dateOfBirth.getFullYear();
            const mDiff = today.getMonth() - dateOfBirth.getMonth();
            if (mDiff < 0 || (mDiff === 0 && today.getDate() < dateOfBirth.getDate())) age--;
            if (age < 14) {
                setError("Hß╗ìc sinh phß║úi ─æß╗º 14 tuß╗òi trß╗ƒ l├¬n.");
                setLoading(false);
                return;
            }
        }

        // UI Validation: If guardian email is provided, name is required
        if (guardianEmail && !guardianName) {
            setError("Vui l├▓ng nhß║¡p t├¬n phß╗Ñ huynh nß║┐u muß╗æn tß║ío t├ái khoß║ún");
            setLoading(false);
            return;
        }

        try {
            let dateOfBirthStr: string | undefined = undefined;
            if (dateOfBirth) {
                const year = dateOfBirth.getFullYear();
                const month = String(dateOfBirth.getMonth() + 1).padStart(2, '0');
                const day = String(dateOfBirth.getDate()).padStart(2, '0');
                dateOfBirthStr = `${year}-${month}-${day}`;
            }

            const req: UpdateStudentRequest = {
                fullName: fullName.trim(),
                dateOfBirth: dateOfBirthStr,
                gender,
                birthPlace: birthPlace.trim() || undefined,
                address: address.trim() || undefined,
                email: email.trim() || undefined,
                phone: phone.trim() || undefined,
                status,
                classId: classId || undefined,
                combinationId: combinationId || undefined,
                guardian: guardianName ? {
                    id: student.guardian?.id,
                    fullName: guardianName.trim(),
                    phone: guardianPhone.trim() || undefined,
                    email: guardianEmail.trim() || undefined,
                    relationship: guardianRelationship.trim() || undefined,
                } : undefined,
            };

            await schoolAdminService.updateStudent(student.id, req);
            onSuccess();
            onClose();
        } catch (err: any) {
            setError(err?.response?.data?.message || "Kh├┤ng thß╗â cß║¡p nhß║¡t hß╗ìc sinh.");
        } finally {
            setLoading(false);
        }
    };

    if (!isOpen || !student) return null;

    return createPortal(
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
