            showError("Kh├┤ng thß╗â tß║úi file mß║½u. Vui l├▓ng thß╗¡ lß║íi sau.");
        }
    };

    const handleClose = () => {
        setFile(null);
        setError(null);
        setDragOver(false);
        onClose();
    };

    if (!isOpen) return null;

    return createPortal(
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
            <div className="absolute inset-0 bg-black/60 backdrop-blur-sm" onClick={handleClose} />
            <div className="relative bg-white rounded-3xl shadow-2xl w-full max-w-xl overflow-hidden flex flex-col z-[100] animate-in zoom-in-95 duration-300 max-h-[90vh]">
                {/* Header */}
                <div className="bg-gradient-to-r from-emerald-600 to-emerald-500 px-8 py-5 flex-none text-white">
                    <div className="flex items-center justify-between">
                        <div className="flex items-center gap-3">
                            <div className="w-10 h-10 bg-white/20 rounded-xl flex items-center justify-center shadow-inner">
                                <FileSpreadsheet className="w-5 h-5 text-emerald-50" />
                            </div>
                            <div>
                                <h1 className="text-xl font-bold tracking-tight">Import hß╗ìc sinh tß╗½ Excel</h1>
                                <p className="text-emerald-50/80 text-xs font-medium mt-0.5">Th├¬m mß╗¢i hß╗ìc sinh v├áo hß╗ç thß╗æng</p>
                            </div>
                        </div>
                        <button onClick={handleClose} className="p-1.5 rounded-lg bg-white/10 text-white hover:bg-white/20 transition-all">
                            <X className="w-5 h-5" />
                        </button>
                    </div>
                </div>

                {/* Body */}
                <div className="p-6 space-y-6 overflow-y-auto flex-1 custom-scrollbar">
