                            <div className="w-10 h-10 rounded-xl bg-blue-100 flex items-center justify-center">
                                <Download className="w-5 h-5 text-blue-600" />
                            </div>
                            <div>
                                <p className="text-sm font-bold text-blue-900">Tß║úi file mß║½u</p>
                                <p className="text-[11px] text-blue-600/70 mt-0.5 font-medium">Sß╗¡ dß╗Ñng file mß║½u ─æß╗â ─æß║úm bß║úo ─æß╗ïnh dß║íng ch├¡nh x├íc</p>
                            </div>
                        </div>
                        <button
                            onClick={handleDownloadTemplate}
                            className="px-4 py-2 bg-blue-600 text-white rounded-xl text-xs font-bold hover:bg-blue-700 transition-all shadow-md shadow-blue-100 shrink-0"
