                            </select>
                        </div>
                        <div className="space-y-2">
                            <label className="text-[11px] font-bold text-slate-400 uppercase tracking-wider px-1">Khß╗æi lß╗¢p</label>
                            <select
                                value={grade}
                                onChange={(e) => setGrade(Number(e.target.value))}
                                className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:border-emerald-500 focus:ring-4 focus:ring-emerald-500/5 outline-none bg-white font-bold text-slate-700 text-sm transition-all hover:border-slate-300"
                            >
                                <option value={10}>Khß╗æi 10</option>
                                <option value={11}>Khß╗æi 11</option>
                                <option value={12}>Khß╗æi 12</option>
                            </select>
                        </div>
                    </div>

                    {/* File Drop Zone */}
                    <div
                        onDragOver={(e) => { e.preventDefault(); setDragOver(true); }}
