    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setLoading(true);
        setError(null);

        // Age validation: teacher must be at least 18
        if (dateOfBirth) {
            const today = new Date();
            let age = today.getFullYear() - dateOfBirth.getFullYear();
            const mDiff = today.getMonth() - dateOfBirth.getMonth();
            if (mDiff < 0 || (mDiff === 0 && today.getDate() < dateOfBirth.getDate())) age--;
            if (age < 18) {
                setError("Gi├ío vi├¬n phß║úi ─æß╗º 18 tuß╗òi trß╗ƒ l├¬n.");
                setLoading(false);
                return;
            }
        }

        try {
            let dateOfBirthStr: string | undefined = undefined;
            if (dateOfBirth) {
                const year = dateOfBirth.getFullYear();
                const month = String(dateOfBirth.getMonth() + 1).padStart(2, '0');
                const day = String(dateOfBirth.getDate()).padStart(2, '0');
                dateOfBirthStr = `${year}-${month}-${day}`;
            }

            const req: CreateTeacherRequest = {
                fullName: fullName.trim(),
                dateOfBirth: dateOfBirthStr,
                gender,
                address: address.trim() || undefined,
                email: email.trim() || undefined,
                phone: phone.trim() || undefined,
                degree: degree.trim() || undefined,
                subjectIds: subjectIds.length > 0 ? subjectIds : undefined,
                createAccount,
            };
            await schoolAdminService.createTeacher(req);
            // Reset form
            setFullName(""); setDateOfBirth(null); setDateInputValue(""); setGender("MALE");
            setAddress(""); setEmail(""); setPhone(""); setDegree("");
            setSubjectIds([]);
            setCreateAccount(true);
            onSuccess();
            onClose();
        } catch (err: any) {
            setError(err?.response?.data?.message || "Kh├┤ng thß╗â th├¬m gi├ío vi├¬n.");
        } finally {
            setLoading(false);
        }
    };

    if (!isOpen) return null;

    return createPortal(
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
            <div className="absolute inset-0 bg-gradient-to-br from-slate-900/70 to-slate-800/70 backdrop-blur-sm" onClick={onClose} />
            <div className="relative bg-white rounded-3xl shadow-2xl w-full max-w-3xl overflow-hidden max-h-[92vh] flex flex-col z-[100] animate-in zoom-in-95 duration-300">
