                                            {subjects.filter(s => !subjectIds.includes(s.id)).map((sub: any) => (
                                                <option key={sub.id} value={sub.id}>{sub.name}</option>
                                            ))}
                                        </select>

                                        <div className="flex flex-wrap gap-2 min-h-[30px]">
