}

export default EditTeacherModal;

import React, { useState, useRef } from "react";
import { createPortal } from "react-dom";
import { Upload, Download, X, FileSpreadsheet, AlertCircle, Info } from "lucide-react";
import { schoolAdminService, type ImportTeacherResult } from "../../../../services/schoolAdminService";
import { useToast } from "../../../../context/ToastContext";

interface ImportTeacherExcelModalProps {
    isOpen: boolean;
    onClose: () => void;
    onSuccess: () => void;
    onImportComplete: (result: ImportTeacherResult) => void;
}

const ImportTeacherExcelModal: React.FC<ImportTeacherExcelModalProps> = ({
    isOpen,
    onClose,
    onSuccess,
    onImportComplete
}) => {
    const [file, setFile] = useState<File | null>(null);
    const [dragOver, setDragOver] = useState(false);
    const [uploading, setUploading] = useState(false);
    const [error, setError] = useState<string | null>(null);
    const fileInputRef = useRef<HTMLInputElement>(null);
    const { showError } = useToast();

    const handleFileSelect = (selectedFile: File) => {
        const validTypes = [
            "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
            "application/vnd.ms-excel"
        ];
        if (!validTypes.includes(selectedFile.type) && !selectedFile.name.match(/\.(xlsx|xls)$/i)) {
            setError("Vui l├▓ng chß╗ìn file Excel (.xlsx hoß║╖c .xls)");
            return;
        }
        setFile(selectedFile);
        setError(null);
    };

    const handleDrop = (e: React.DragEvent) => {
        e.preventDefault();
        setDragOver(false);
        if (e.dataTransfer.files.length > 0) {
            handleFileSelect(e.dataTransfer.files[0]);
        }
    };

    const handleSubmit = async () => {
        if (!file) {
            setError("Vui l├▓ng chß╗ìn file Excel");
            return;
        }

        setUploading(true);
        setError(null);

        try {
            const importResult = await schoolAdminService.importTeachersFromExcel(file);

            if (importResult.successCount > 0) {
                onSuccess();
            }
            handleClose();
            onImportComplete(importResult);
        } catch (err: any) {
            setError(err?.response?.data?.message || "Kh├┤ng thß╗â import file gi├ío vi├¬n.");
        } finally {
            setUploading(false);
        }
    };

    const handleDownloadTemplate = async () => {
        try {
            const blob = await schoolAdminService.downloadTeacherTemplate();
            const url = window.URL.createObjectURL(blob);
            const link = document.createElement('a');
            link.href = url;
            link.setAttribute('download', 'Mau_Import_GiaoVien.xlsx');
            document.body.appendChild(link);
            link.click();
            link.remove();
            window.URL.revokeObjectURL(url);
        } catch (err) {
            showError("Kh├┤ng thß╗â tß║úi file mß║½u. Vui l├▓ng thß╗¡ lß║íi sau.");
        }
    };

    const handleClose = () => {
        setFile(null);
        setError(null);
        setDragOver(false);
        onClose();
    };

    if (!isOpen) return null;

    return createPortal(
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
            <div className="absolute inset-0 bg-black/60 backdrop-blur-sm" onClick={handleClose} />
            <div className="relative bg-white rounded-3xl shadow-2xl w-full max-w-xl overflow-hidden flex flex-col z-[100] animate-in zoom-in-95 duration-300 max-h-[90vh]">
                {/* Header */}
                <div className="bg-gradient-to-r from-emerald-600 to-emerald-500 px-8 py-5 flex-none text-white">
                    <div className="flex items-center justify-between">
                        <div className="flex items-center gap-3">
                            <div className="w-10 h-10 bg-white/20 rounded-xl flex items-center justify-center shadow-inner">
                                <FileSpreadsheet className="w-5 h-5 text-emerald-50" />
                            </div>
                            <div>
                                <h1 className="text-xl font-bold tracking-tight">Import gi├ío vi├¬n tß╗½ Excel</h1>
                                <p className="text-emerald-50/80 text-xs font-medium mt-0.5">Th├¬m mß╗¢i gi├ío vi├¬n v├áo hß╗ç thß╗æng</p>
                            </div>
                        </div>
                        <button onClick={handleClose} className="p-1.5 rounded-lg bg-white/10 text-white hover:bg-white/20 transition-all">
                            <X className="w-5 h-5" />
                        </button>
                    </div>
                </div>

                {/* Body */}
                <div className="p-6 space-y-6 overflow-y-auto flex-1 custom-scrollbar">
                    {/* Download Template Section */}
                    <div className="bg-blue-50/50 border border-blue-100 rounded-2xl p-4 flex items-center justify-between shadow-sm">
                        <div className="flex gap-3 items-center">
                            <div className="w-10 h-10 rounded-xl bg-blue-100 flex items-center justify-center">
                                <Download className="w-5 h-5 text-blue-600" />
                            </div>
                            <div>
                                <p className="text-sm font-bold text-blue-900">Tß║úi file mß║½u</p>
                                <p className="text-[11px] text-blue-600/70 mt-0.5 font-medium">Sß╗¡ dß╗Ñng file mß║½u ─æß╗â ─æß║úm bß║úo ─æß╗ïnh dß║íng ch├¡nh x├íc</p>
                            </div>
                        </div>
                        <button
                            onClick={handleDownloadTemplate}
                            className="px-4 py-2 bg-blue-600 text-white rounded-xl text-xs font-bold hover:bg-blue-700 transition-all shadow-md shadow-blue-100 shrink-0"
                        >
                            Tß║úi file mß║½u
                        </button>
                    </div>

                    {/* File Drop Zone */}
                    <div
                        className={`border-2 border-dashed rounded-2xl p-10 text-center transition-all cursor-pointer group relative overflow-hidden
                            ${dragOver ? "border-emerald-400 bg-emerald-50/50 scale-[1.01]" : file ? "border-emerald-300 bg-emerald-50/20" : "border-slate-200 hover:border-emerald-400 hover:bg-slate-50/50"}`}
                        onDragOver={(e) => { e.preventDefault(); setDragOver(true); }}
                        onDragLeave={() => setDragOver(false)}
                        onDrop={handleDrop}
                        onClick={() => fileInputRef.current?.click()}
                    >
                        <input
                            ref={fileInputRef}
                            type="file"
                            accept=".xlsx,.xls"
                            className="hidden"
