import "react-datepicker/dist/react-datepicker.css";
import { vietnameseNameSort } from "../../../utils/sortUtils";
import { schoolAdminService } from "../../../services/schoolAdminService";
import type {
    ClassRoomDto,
    AdminSlotDto,
    AdminAttendanceDto,
    AdminSaveAttendanceRequest,
} from "../../../services/schoolAdminService";
import {
    Calendar as CalendarIcon,
    Users,
    Save,
    AlertTriangle,
    Info,
    CheckCircle,
    XCircle,
    Clock,
    BookOpen
} from "lucide-react";

import { useToast } from "../../../context/ToastContext";

const AttendanceStatus = {
    PRESENT: "PRESENT",
    ABSENT_EXCUSED: "ABSENT_EXCUSED",
    ABSENT_UNEXCUSED: "ABSENT_UNEXCUSED",
    LATE: "LATE",
} as const;

type AttendanceStatusType = typeof AttendanceStatus[keyof typeof AttendanceStatus];

export default function AttendanceManagement() {
    const { toast } = useToast();
    const [classes, setClasses] = useState<ClassRoomDto[]>([]);
    const [selectedClassId, setSelectedClassId] = useState<string>("");
    const [selectedDate, setSelectedDate] = useState(new Date());
    const [slots, setSlots] = useState<AdminSlotDto[]>([]);
    const [selectedSlot, setSelectedSlot] = useState<AdminSlotDto | null>(null);
    const [students, setStudents] = useState<AdminAttendanceDto[]>([]);
    const [loading, setLoading] = useState(false);
    const [loadingSlots, setLoadingSlots] = useState(false);
    const [saving, setSaving] = useState(false);

    const [filterGrade, setFilterGrade] = useState<string>("");
    const [skippedStudents, setSkippedStudents] = useState<{ studentId: string; reason: string; studentName?: string; studentCode?: string }[]>([]);
    const [showSkippedModal, setShowSkippedModal] = useState(false);

    // Load classes on mount
    useEffect(() => {
        loadClasses();
    }, []);

    async function loadClasses() {
        try {
            const data = await schoolAdminService.listClasses();
            setClasses(data.sort((a, b) => a.name.localeCompare(b.name)));
        } catch (error) {
            console.error("Failed to load classes:", error);
        }
    }

    const filteredClasses = useMemo(() => {
        if (!filterGrade) return classes;
        return classes.filter(c => c.grade.toString() === filterGrade);
    }, [classes, filterGrade]);

    // Clear class if it doesn't match filter
    useEffect(() => {
        if (selectedClassId && !filteredClasses.some(c => c.id === selectedClassId)) {
            setSelectedClassId("");
        }
    }, [filteredClasses, selectedClassId]);

    // Load slots when class or date changes
    useEffect(() => {
        if (selectedClassId) {
            loadSlots();
        } else {
            setSlots([]);
            setSelectedSlot(null);
            setStudents([]);
        }
    }, [selectedClassId, selectedDate]);

    async function loadSlots() {
        try {
            setLoadingSlots(true);
            setSelectedSlot(null);
            setStudents([]);
            const dateStr = format(selectedDate, "yyyy-MM-dd");
            const data = await schoolAdminService.getAttendanceSlots(selectedClassId, dateStr);
            setSlots(data);
        } catch (error) {
            console.error("Failed to load slots:", error);
            setSlots([]);
        } finally {
            setLoadingSlots(false);
        }
    }

    // Load students when slot selected
    const loadStudents = useCallback(async () => {
        if (!selectedSlot || !selectedClassId) return;
        try {
            setLoading(true);
            const dateStr = format(selectedDate, "yyyy-MM-dd");
            const data = await schoolAdminService.getAttendanceForSlot(
                selectedClassId,
                dateStr,
                selectedSlot.slotIndex
            );
            const sortedData = [...data].sort((a, b) => vietnameseNameSort(a.studentName, b.studentName));
            setStudents(sortedData);
        } catch (error) {
            console.error("Failed to load attendance:", error);
        } finally {
            setLoading(false);
        }
    }, [selectedSlot, selectedClassId, selectedDate]);

    useEffect(() => {
        loadStudents();
    }, [loadStudents]);

    const handleStatusChange = (studentId: string, status: AttendanceStatusType) => {
        setStudents(prev =>
            prev.map(s => (s.studentId === studentId ? { ...s, status } : s))
        );
    };

    const handleRemarksChange = (studentId: string, remarks: string) => {
        setStudents(prev =>
            prev.map(s => (s.studentId === studentId ? { ...s, remarks } : s))
        );
    };

    const handleSave = async () => {
        if (!selectedSlot || !selectedClassId) return;
        try {
            setSaving(true);
            const dateStr = format(selectedDate, "yyyy-MM-dd");
            const request: AdminSaveAttendanceRequest = {
                date: dateStr,
                slotIndex: selectedSlot.slotIndex,
                records: students.map(s => ({
                    studentId: s.studentId,
                    status: s.status,
                    remarks: s.remarks || "",
                })),
            };
            const res = await schoolAdminService.saveAttendance(selectedClassId, request);

            if (res.skippedStudents && res.skippedStudents.length > 0) {
                const skippedWithDetails = res.skippedStudents.map(skipped => {
                    const studentInfo = students.find(s => s.studentId === skipped.studentId);
                    return {
                        ...skipped,
                        studentName: studentInfo?.studentName || "Kh├┤ng x├íc ─æß╗ïnh",
                        studentCode: studentInfo?.studentCode || skipped.studentId
                    };
                });
                setSkippedStudents(skippedWithDetails);
                setShowSkippedModal(true);
                toast.error(`L╞░u th├ánh c├┤ng, nh╞░ng c├│ ${res.skippedStudents.length} hß╗ìc sinh bß╗ï bß╗Å qua.`);
            } else {
                toast.success("L╞░u ─æiß╗âm danh th├ánh c├┤ng!");
            }
        } catch (error: any) {
            console.error("Failed to save:", error);
            const status = error.response?.status;
            const message = error.response?.data?.message || "Lß╗ùi khi l╞░u ─æiß╗âm danh";

            if (status === 400 || status === 403 || status === 404 || status === 409) {
                toast.error(message);
            } else {
                toast.error("Hß╗ç thß╗æng gß║╖p sß╗▒ cß╗æ. Vui l├▓ng thß╗¡ lß║íi sau.");
            }
        } finally {
            setSaving(false);
        }
    };

    const statusOptions = [
        { value: AttendanceStatus.PRESENT, label: "C├│ mß║╖t", icon: CheckCircle, color: "bg-green-100 text-green-700", ring: "ring-green-500", active: "bg-green-600 text-white" },
        { value: AttendanceStatus.ABSENT_EXCUSED, label: "Vß║»ng (CP)", icon: Info, color: "bg-amber-100 text-amber-700", ring: "ring-amber-500", active: "bg-amber-500 text-white" },
        { value: AttendanceStatus.ABSENT_UNEXCUSED, label: "Vß║»ng (KP)", icon: XCircle, color: "bg-red-100 text-red-700", ring: "ring-red-500", active: "bg-red-600 text-white" },
        { value: AttendanceStatus.LATE, label: "─Éi muß╗Ön", icon: Clock, color: "bg-blue-100 text-blue-700", ring: "ring-blue-500", active: "bg-blue-600 text-white" },
    ];

    const isPastDay = (() => {
        const today = new Date();
        today.setHours(0, 0, 0, 0);
        const sel = new Date(selectedDate);
        sel.setHours(0, 0, 0, 0);
        return sel < today;
    })();

    return (
        <div className="p-6 max-w-7xl mx-auto space-y-6">
            {/* Modal Skipped Students */}
