import { useEffect, useState } from "react";
import { useParams, useNavigate } from "react-router-dom";
import { schoolAdminService, type ClassRoomDto, type StudentDto } from "../../../services/schoolAdminService";
import { ArrowLeft, Users, Calendar, DoorOpen, GraduationCap } from "lucide-react";
import { StatusBadge } from "../../../components/common";
import { vietnameseNameSort } from "../../../utils/sortUtils";

const ClassDetailView = () => {
    const { id } = useParams<{ id: string }>();
    const navigate = useNavigate();
    const [classData, setClassData] = useState<ClassRoomDto | null>(null);
    const [students, setStudents] = useState<StudentDto[]>([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState<string | null>(null);
    const [sortConfig, setSortConfig] = useState<{ key: 'fullName' | 'studentCode'; direction: 'asc' | 'desc' } | null>({ key: 'fullName', direction: 'asc' });

    const sortedStudents = [...students].sort((a, b) => {
        if (!sortConfig) return 0;
        const { key, direction } = sortConfig;

        let valA = a[key] || '';
        let valB = b[key] || '';

        if (key === 'fullName') {
            return direction === 'asc' ? vietnameseNameSort(valA, valB) : vietnameseNameSort(valB, valA);
        }

        return direction === 'asc' ? valA.localeCompare(valB) : valB.localeCompare(valA);
    });

    const handleSort = (key: 'fullName' | 'studentCode') => {
        setSortConfig(prev => {
            if (prev?.key === key) {
                return { key, direction: prev.direction === 'asc' ? 'desc' : 'asc' };
            }
            return { key, direction: 'asc' };
        });
    };

    useEffect(() => {
        if (id) {
            fetchData(id);
        }
    }, [id]);

    const fetchData = async (classId: string) => {
        setLoading(true);
        setError(null);
        try {
            const [clsData, studentsResponse] = await Promise.all([
                schoolAdminService.getClass(classId),
                schoolAdminService.listStudents({ classId, size: 1000 })
            ]);
            setClassData(clsData);
            setStudents(studentsResponse.content);
        } catch (err: any) {
            console.error("Failed to fetch class details", err);
            setError(err?.response?.data?.message || "Kh├┤ng thß╗â tß║úi th├┤ng tin lß╗¢p hß╗ìc.");
        } finally {
            setLoading(false);
        }
    };

