                    <p>{error || "Kh├┤ng t├¼m thß║Ñy th├┤ng tin lß╗¢p hß╗ìc"}</p>
                </div>
            </div>
        );
    }

    return (
        <div className="max-w-6xl mx-auto pb-12 animate-fade-in-up">
            {/* Header / Navigation */}
            <div className="mb-6">
                <button
                    onClick={() => navigate('/school-admin/classes')}
                    className="flex items-center text-slate-500 hover:text-blue-600 transition-colors font-medium"
                >
                    <ArrowLeft className="w-5 h-5 mr-2" />
                    Quay lß║íi danh s├ích lß╗¢p
                </button>
            </div>

            {/* Class Info Card */}
            <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden mb-8">
                <div className="bg-gradient-to-r from-blue-600 to-indigo-600 px-8 py-8 text-white">
                    <div className="flex justify-between items-start">
                        <div>
                            <h1 className="text-2xl font-bold text-gray-900 mb-2">{classData.name}</h1>
                            <div className="flex items-center text-blue-100 space-x-6">
                                <span className="flex items-center bg-white/20 px-3 py-1 rounded-full text-sm backdrop-blur-sm">
                                    <GraduationCap className="w-4 h-4 mr-2" />
                                    Khß╗æi {classData.grade}
                                </span>
                                <span className="flex items-center bg-white/20 px-3 py-1 rounded-full text-sm backdrop-blur-sm">
                                    <Calendar className="w-4 h-4 mr-2" />
                                    {classData.academicYear}
                                </span>
                            </div>
                        </div>
                        <div className="text-right">
                            <div className="text-blue-100 text-sm mb-1 uppercase tracking-wider font-medium">S─⌐ sß╗æ</div>
                            <div className="text-4xl font-bold">{students.length}/{classData.maxCapacity}</div>
                        </div>
                    </div>
                </div>

                <div className="px-8 py-6 grid grid-cols-1 md:grid-cols-3 gap-8">
                    <div className="flex items-start p-4 bg-slate-50 rounded-xl">
                        <div className="bg-blue-100 text-blue-600 p-3 rounded-lg mr-4">
                            <Users className="w-6 h-6" />
                        </div>
                        <div>
                            <div className="text-slate-500 text-sm font-medium uppercase tracking-wide mb-1">Gi├ío vi├¬n chß╗º nhiß╗çm</div>
                            <div className="font-semibold text-slate-800 text-lg">{classData.homeroomTeacherName || "Ch╞░a ph├ón c├┤ng"}</div>
                        </div>
                    </div>

                    <div className="flex items-start p-4 bg-slate-50 rounded-xl">
                        <div className="bg-indigo-100 text-indigo-600 p-3 rounded-lg mr-4">
                            <DoorOpen className="w-6 h-6" />
                        </div>
                        <div>
                            <div className="text-slate-500 text-sm font-medium uppercase tracking-wide mb-1">Ph├▓ng hß╗ìc</div>
                            <div className="font-semibold text-slate-800 text-lg">{classData.roomName || "Ch╞░a xß║┐p ph├▓ng"}</div>
                        </div>
                    </div>

                    <div className="flex items-start p-4 bg-slate-50 rounded-xl">
                        <div className="bg-purple-100 text-purple-600 p-3 rounded-lg mr-4">
                            <GraduationCap className="w-6 h-6" />
                        </div>
                        <div>
                            <div className="text-slate-500 text-sm font-medium uppercase tracking-wide mb-1">Tß╗ò hß╗úp / Ban</div>
                            <div className="font-semibold text-slate-800 text-lg">
                                {classData.combinationName || (
                                    classData.department === 'TU_NHIEN' ? 'Ban Tß╗▒ nhi├¬n' :
                                        classData.department === 'XA_HOI' ? 'Ban X├ú hß╗Öi' : 'Kh├┤ng ph├ón ban'
                                )}
                            </div>
                        </div>
                    </div>
                </div>
            </div>

            {/* Students List */}
            <div className="bg-white rounded-2xl shadow-sm border border-gray-200 overflow-hidden">
                <div className="px-6 py-5 border-b border-gray-100 flex justify-between items-center">
                    <h2 className="text-lg font-bold text-gray-800 flex items-center">
                        <Users className="w-5 h-5 mr-3 text-blue-600" />
                        Danh s├ích hß╗ìc sinh
                    </h2>
                </div>

                <div className="overflow-x-auto">
                    <table className="w-full">
                        <thead className="bg-gray-50">
