                                        >
                                            <Edit className="w-4 h-4" />
                                        </button>
                                        {cls.grade < 12 && cls.status === 'ACTIVE' && (
                                            <button
                                                onClick={() => { setPromotingClass(cls); setShowPromotionModal(true); }}
                                                className="text-violet-600 hover:bg-violet-50 p-1.5 rounded-lg transition-colors"
                                                title="X├⌐t l├¬n lß╗¢p"
                                            >
                                                <ArrowUpCircle className="w-4 h-4" />
                                            </button>
                                        )}
                                        <button
                                            onClick={() => {
                                                confirm({
                                                    title: "X├│a lß╗¢p hß╗ìc?",
                                                    message: (
                                                        <div>
                                                            <p>Bß║ín c├│ chß║»c muß╗æn x├│a lß╗¢p <strong>"{cls.name}"</strong>?</p>
                                                            <p className="mt-2 text-xs text-red-700 leading-relaxed bg-red-50 p-2 rounded border border-red-100 italic">
                                                                H├ánh ─æß╗Öng n├áy KH├öNG THß╗é ho├án t├íc. Hß╗ç thß╗æng sß║╜ ng─ân chß║╖n nß║┐u ─æ├ú c├│ dß╗» liß╗çu ─Éiß╗âm hoß║╖c Hß╗ìc sinh.
                                                            </p>
                                                        </div>
                                                    ),
                                                    variant: "danger",
                                                    confirmText: "X├íc nhß║¡n x├│a",
                                                    onConfirm: async () => {
                                                        try {
                                                            await schoolAdminService.deleteClass(cls.id);
                                                            fetchData();
                                                        } catch (err: any) {
                                                            setError(err?.response?.data?.message || "Kh├┤ng thß╗â x├│a lß╗¢p hß╗ìc.");
                                                        }
                                                    }
                                                });
                                            }}
                                            className="text-red-600 hover:bg-red-50 p-1.5 rounded-lg transition-colors"
                                            title="X├│a lß╗¢p hß╗ìc"
                                        >
                                            <Trash2 className="w-4 h-4" />
                                        </button>
                                    </div>
                                </td>
                            </tr>
                        ))}
                        {classes.length === 0 && (
                            <tr><td colSpan={9} className="px-6 py-8 text-center text-gray-500">Ch╞░a c├│ lß╗¢p hß╗ìc n├áo</td></tr>
                        )}
                    </tbody>
                </table>
            </div>

            {/* Modals */}
            <AddClassModal
                isOpen={showAddModal}
                onClose={() => setShowAddModal(false)}
                onSuccess={fetchData}
                teachers={teachers}
                combinations={combinations}
                rooms={rooms}
                defaultAcademicYear={currentAcademicYear}
            />
            <EditClassModal
                isOpen={showEditModal}
                classData={editingClass}
                onClose={() => {
                    setShowEditModal(false);
                    setEditingClass(null);
                }}
                onSuccess={fetchData}
                teachers={teachers}
                combinations={combinations}
                rooms={rooms}
            />
            <ConfirmationDialog />
            <PromotionModal
                isOpen={showPromotionModal}
                onClose={() => {
                    setShowPromotionModal(false);
                    setPromotingClass(null);
                }}
                onSuccess={fetchData}
                classData={promotingClass}
                allClasses={classes}
            />
        </div >
    );
}

export default ClassManagement;

import { useEffect, useState } from "react";
import { createPortal } from "react-dom";
import { schoolAdminService, type CombinationDto, type SubjectDto, type CreateCombinationRequest } from "../../../services/schoolAdminService";
import { Plus, X, Check, AlertCircle, Edit, Trash2 } from "lucide-react";
import toast from "react-hot-toast";
import { useConfirmation } from "../../../hooks/useConfirmation";

export default function CombinationManagement() {
    const [combinations, setCombinations] = useState<CombinationDto[]>([]);
    const [subjects, setSubjects] = useState<SubjectDto[]>([]);
    const [loading, setLoading] = useState(true);
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [submitting, setSubmitting] = useState(false);
    const [editingId, setEditingId] = useState<string | null>(null);
    const { confirm, ConfirmationDialog } = useConfirmation();

    // Form State
    const [formData, setFormData] = useState<CreateCombinationRequest>({
        name: "",
        code: "",
        stream: 'TU_NHIEN', // Default
        electiveSubjectIds: [],
        specializedSubjectIds: []
    });

    useEffect(() => {
        fetchData();
    }, []);

    const fetchData = async () => {
        try {
            const [combinationsData, subjectsData] = await Promise.all([
                schoolAdminService.listCombinations(),
                schoolAdminService.listSubjects()
            ]);
            setCombinations(combinationsData);
            setSubjects(subjectsData);
        } catch (error) {
            console.error("Failed to fetch data:", error);
            toast.error("Kh├┤ng thß╗â tß║úi dß╗» liß╗çu");
        } finally {
            setLoading(false);
        }
    };

    const handleSubmit = async () => {
        // Client-side validation
        if (!formData.name.trim()) {
            toast.error("Vui l├▓ng nhß║¡p t├¬n tß╗ò hß╗úp");
            return;
        }
        if (!formData.stream) {
            toast.error("Vui l├▓ng chß╗ìn Ban");
            return;
        }
        if (formData.electiveSubjectIds.length !== 4) {
            toast.error("Vui l├▓ng chß╗ìn ─æ├║ng 4 m├┤n lß╗▒a chß╗ìn");
            return;
        }
        if (formData.specializedSubjectIds.length !== 3) {
            toast.error("Vui l├▓ng chß╗ìn ─æ├║ng 3 chuy├¬n ─æß╗ü");
            return;
        }

        setSubmitting(true);
        try {
            if (editingId) {
                await schoolAdminService.updateCombination(editingId, formData);
                toast.success("Cß║¡p nhß║¡t tß╗ò hß╗úp th├ánh c├┤ng!");
            } else {
                await schoolAdminService.createCombination(formData);
                toast.success("Tß║ío tß╗ò hß╗úp th├ánh c├┤ng!");
            }
            setIsModalOpen(false);
            resetForm();
            fetchData(); // Refresh list
        } catch (error: any) {
            console.error(error);
            const msg = error.response?.data?.message || "C├│ lß╗ùi xß║úy ra";
            toast.error(msg);
        } finally {
            setSubmitting(false);
        }
    };

    const handleDelete = async (combo: CombinationDto) => {
        confirm({
            title: "X├│a tß╗ò hß╗úp m├┤n?",
            message: (
                <span>
                    Bß║ín c├│ chß║»c chß║»n muß╗æn x├│a tß╗ò hß╗úp <strong>{combo.name}</strong>? H├ánh ─æß╗Öng n├áy kh├┤ng thß╗â ho├án t├íc.
                </span>
            ),
            variant: "danger",
            confirmText: "X├│a",
            onConfirm: async () => {
                try {
                    await schoolAdminService.deleteCombination(combo.id);
                    toast.success("X├│a tß╗ò hß╗úp th├ánh c├┤ng");
                    fetchData();
                } catch (error: any) {
                    console.error(error);
                    toast.error(error.response?.data?.message || "Kh├┤ng thß╗â x├│a tß╗ò hß╗úp");
                }
            }
        });
    };

    const handleEdit = (combo: CombinationDto) => {
        setEditingId(combo.id);
        const electiveIds = combo.subjects.filter(s => s.type === 'ELECTIVE').map(s => s.id);
        const specializedIds = combo.subjects.filter(s => s.type === 'SPECIALIZED').map(s => s.id);

        setFormData({
            name: combo.name,
            code: combo.code || "",
            stream: combo.stream,
            electiveSubjectIds: electiveIds,
            specializedSubjectIds: specializedIds
        });
        setIsModalOpen(true);
    };

    const resetForm = () => {
        setFormData({ name: "", code: "", stream: 'TU_NHIEN', electiveSubjectIds: [], specializedSubjectIds: [] });
        setEditingId(null);
    };

    const toggleSubject = (id: string, type: 'ELECTIVE' | 'SPECIALIZED') => {
        setFormData(prev => {
            const list = type === 'ELECTIVE' ? [...prev.electiveSubjectIds] : [...prev.specializedSubjectIds];
            const index = list.indexOf(id);

            if (index > -1) {
                list.splice(index, 1);
            } else {
                // Check limits (4 for elective, 3 for specialized)
                const limit = type === 'ELECTIVE' ? 4 : 3;
                if (list.length >= limit) {
                    toast.error(`Chß╗ë ─æ╞░ß╗úc chß╗ìn tß╗æi ─æa ${limit} m├┤n`);
                    return prev;
                }
                list.push(id);
            }

            return type === 'ELECTIVE'
                ? { ...prev, electiveSubjectIds: list }
                : { ...prev, specializedSubjectIds: list };
        });
    };

    const electives = subjects.filter(s => s.type === 'ELECTIVE' && s.active && s.stream === formData.stream);
    // Relaxed filtering for Specialized Subjects: Show ALL active specialized subjects
    const specialized = subjects.filter(s => s.type === 'SPECIALIZED' && s.active);
    // Filter out ACTIVITY subjects (Ch├áo cß╗¥, Sinh hoß║ít lß╗¢p)
    const compulsory = subjects.filter(s =>
        s.type === 'COMPULSORY' && s.active && s.code !== 'CC' && s.code !== 'SHL'
    );

    return (
        <div className="p-4 space-y-6">
            <div className="flex justify-end items-center">
                {/* Header title removed to avoid duplication when embedded */}
                <button
                    onClick={() => { resetForm(); setIsModalOpen(true); }}
                    className="bg-gradient-to-r from-blue-600 to-blue-500 text-white px-4 py-2 rounded-lg flex items-center gap-2 text-sm font-medium hover:shadow-lg hover:shadow-blue-500/25 transition-all shadow-sm"
                >
                    <Plus className="w-5 h-5" />
                    Tß║ío Tß╗ò hß╗úp mß╗¢i
                </button>
            </div>

            {/* List Combinations (Grid View) */}
            {loading ? (
                <div className="text-center py-12">
                    <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600 mx-auto"></div>
                </div>
            ) : combinations.length === 0 ? (
                <div className="text-center py-12 bg-gray-50 rounded-xl border border-dashed border-gray-300">
                    <p className="text-gray-500">Ch╞░a c├│ tß╗ò hß╗úp n├áo ─æ╞░ß╗úc tß║ío.</p>
                </div>
            ) : (
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    {combinations.map(combo => (
                        <div key={combo.id} className="bg-white border border-gray-200 rounded-xl shadow-sm overflow-hidden hover:shadow-md transition-shadow">
                            <div className="px-5 py-4 bg-gray-50 border-b border-gray-100 flex justify-between items-center">
                                <div>
                                    <div className="flex items-center gap-2">
                                        <h3 className="font-bold text-gray-900 text-lg">{combo.name}</h3>
                                        <span className={`text-[10px] px-2.5 py-0.5 rounded-full border ${combo.stream === 'TU_NHIEN'
                                            ? 'bg-blue-50 text-blue-700 border-blue-100'
                                            : 'bg-pink-50 text-pink-700 border-pink-100'
                                            }`}>
                                            {combo.stream === 'TU_NHIEN' ? 'Tß╗▒ Nhi├¬n' : 'X├ú Hß╗Öi'}
                                        </span>
                                    </div>
                                    {combo.code && <span className="text-xs text-gray-500">{combo.code}</span>}
                                </div>
                                <div className="flex gap-2">
                                    <button
                                        onClick={() => handleEdit(combo)}
                                        className="text-blue-600 hover:bg-blue-50 p-1.5 rounded-lg transition-colors"
                                        title="Chß╗ënh sß╗¡a"
                                    >
                                        <Edit className="w-4 h-4" />
                                    </button>
                                    <button
                                        onClick={() => handleDelete(combo)}
                                        className="text-red-600 hover:bg-red-50 p-1.5 rounded-lg transition-colors"
                                        title="X├│a"
                                    >
                                        <Trash2 className="w-4 h-4" />
                                    </button>
                                </div>
                            </div>
                            <div className="p-5">
                                <p className="text-sm font-medium text-gray-700 mb-2">M├┤n lß╗▒a chß╗ìn:</p>
                                <div className="flex flex-wrap gap-2 mb-4">
                                    {combo.subjects.filter(s => s.type === 'ELECTIVE').map(s => (
                                        <span key={s.id} className="bg-green-50 text-green-700 border border-green-100 text-xs px-2.5 py-0.5 rounded-full">
                                            {s.name}
                                        </span>
                                    ))}
                                </div>

                                <p className="text-sm font-medium text-gray-700 mb-2">Chuy├¬n ─æß╗ü:</p>
                                <div className="flex flex-wrap gap-2">
                                    {combo.subjects.filter(s => s.type === 'SPECIALIZED').map(s => (
                                        <span key={s.id} className="bg-purple-50 text-purple-700 border border-purple-100 text-xs px-2.5 py-0.5 rounded-full">
                                            {s.name}
                                        </span>
                                    ))}
                                </div>

                                <div className="mt-4 pt-4 border-t border-gray-100">
                                    <p className="text-xs text-gray-500">
                                        + {compulsory.length} m├┤n bß║»t buß╗Öc (To├ín, V─ân, Anh...)
                                    </p>
                                </div>
                            </div>
                        </div>
                    ))}
                </div>
            )}

            {/* Create Modal */}
            {isModalOpen && createPortal(
                <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
                    <div className="absolute inset-0 bg-gradient-to-br from-slate-900/70 to-slate-800/70 backdrop-blur-sm" onClick={() => setIsModalOpen(false)} />
                    <div className="relative bg-white rounded-2xl shadow-2xl w-full max-w-4xl mx-4 overflow-hidden max-h-[90vh] flex flex-col z-[100]">
                        {/* Gradient Header */}
                        <div className="bg-gradient-to-r from-blue-600 via-blue-500 to-indigo-500 px-6 py-4 flex-none z-[110]">
                            <div className="flex items-center justify-between">
                                <div className="flex items-center gap-3">
                                    <div className="w-10 h-10 bg-white/20 rounded-xl flex items-center justify-center">
                                        <Plus className="w-5 h-5 text-white" />
                                    </div>
                                    <div>
                                        <h2 className="text-lg font-bold text-white">{editingId ? 'Cß║¡p nhß║¡t Tß╗ò hß╗úp' : 'Tß║ío Tß╗ò hß╗úp mß╗¢i'}</h2>
                                        <p className="text-blue-100 text-sm">{editingId ? 'Chß╗ënh sß╗¡a th├┤ng tin tß╗ò hß╗úp m├┤n' : 'Thiß║┐t lß║¡p tß╗ò hß╗úp m├┤n hß╗ìc mß╗¢i'}</p>
                                    </div>
                                </div>
                                <button onClick={() => setIsModalOpen(false)} className="w-10 h-10 rounded-xl bg-white/10 hover:bg-white/20 flex items-center justify-center text-white transition-all">
                                    <X className="w-6 h-6" />
                                </button>
                            </div>
                        </div>

                        <div className="p-6 space-y-6 overflow-y-auto">
                            {/* Basic Info */}
                            <div className="grid grid-cols-2 gap-4">
                                <div>
                                    <label className="block text-sm font-medium text-gray-700 mb-1">T├¬n Tß╗ò hß╗úp <span className="text-red-500">*</span></label>
                                    <input
                                        type="text"
                                        className="w-full border border-gray-300 rounded-lg px-3 py-2 outline-none focus:ring-2 focus:ring-blue-500"
                                        placeholder="VD: Ban Tß╗▒ Nhi├¬n 1"
                                        value={formData.name}
                                        onChange={e => setFormData({ ...formData, name: e.target.value })}
                                    />
                                </div>
                                <div>
                                    <label className="block text-sm font-medium text-gray-700 mb-1">M├ú Tß╗ò hß╗úp</label>
                                    <input
                                        type="text"
                                        className="w-full border border-gray-300 rounded-lg px-3 py-2 outline-none focus:ring-2 focus:ring-blue-500"
                                        placeholder="VD: KHTN01"
                                        value={formData.code}
                                        onChange={e => setFormData({ ...formData, code: e.target.value })}
                                    />
                                </div>
                            </div>

                            <div className="space-y-3">
                                <label className="block text-sm font-medium text-gray-700">Chß╗ìn Ban (Stream)</label>
                                <div className="grid grid-cols-2 gap-4">
                                    <div
                                        onClick={() => {
                                            setFormData(prev => ({ ...prev, stream: 'TU_NHIEN', electiveSubjectIds: [], specializedSubjectIds: [] }));
                                        }}
                                        className={`cursor-pointer border rounded-xl p-4 flex items-center justify-between transition-all ${formData.stream === 'TU_NHIEN'
                                            ? 'bg-blue-50 border-blue-500 ring-1 ring-blue-500'
                                            : 'bg-white border-gray-200 hover:border-gray-300'
                                            }`}
                                    >
                                        <div>
                                            <p className={`font-semibold ${formData.stream === 'TU_NHIEN' ? 'text-blue-800' : 'text-gray-900'}`}>Khoa hß╗ìc Tß╗▒ nhi├¬n</p>
                                            <p className="text-xs text-gray-500 mt-1">L├╜, H├│a, Sinh, Tin...</p>
                                        </div>
                                        {formData.stream === 'TU_NHIEN' && <Check className="w-5 h-5 text-blue-600" />}
                                    </div>

                                    <div
                                        onClick={() => {
                                            setFormData(prev => ({ ...prev, stream: 'XA_HOI', electiveSubjectIds: [], specializedSubjectIds: [] }));
                                        }}
                                        className={`cursor-pointer border rounded-xl p-4 flex items-center justify-between transition-all ${formData.stream === 'XA_HOI'
                                            ? 'bg-pink-50 border-pink-500 ring-1 ring-pink-500'
                                            : 'bg-white border-gray-200 hover:border-gray-300'
                                            }`}
                                    >
                                        <div>
                                            <p className={`font-semibold ${formData.stream === 'XA_HOI' ? 'text-pink-800' : 'text-gray-900'}`}>Khoa hß╗ìc X├ú hß╗Öi</p>
                                            <p className="text-xs text-gray-500 mt-1">Sß╗¡, ─Éß╗ïa, GDKT&PL...</p>
                                        </div>
                                        {formData.stream === 'XA_HOI' && <Check className="w-5 h-5 text-pink-600" />}
                                    </div>
                                </div>
                            </div>

                            {/* Elective Selection */}
                            <div>
                                <div className="flex justify-between items-center mb-2">
                                    <label className="block text-base font-medium text-gray-800">
                                        Chß╗ìn 4 M├┤n tß╗▒ chß╗ìn
                                    </label>
                                    <span className={`text-sm font-medium ${formData.electiveSubjectIds.length === 4 ? 'text-green-600' : 'text-orange-500'}`}>
                                        ─É├ú chß╗ìn: {formData.electiveSubjectIds.length}/4
                                    </span>
                                </div>
                                <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-4 gap-3">
                                    {electives.map(subject => {
                                        const isSelected = formData.electiveSubjectIds.includes(subject.id);
                                        return (
                                            <div
                                                key={subject.id}
                                                onClick={() => toggleSubject(subject.id, 'ELECTIVE')}
                                                className={`cursor-pointer rounded-lg border p-3 flex items-center justify-between transition-all ${isSelected
                                                    ? 'bg-blue-50 border-blue-500 ring-1 ring-blue-500'
                                                    : 'bg-white border-gray-200 hover:border-gray-300 scroll-smooth'
                                                    }`}
                                            >
                                                <span className={`text-sm font-medium ${isSelected ? 'text-blue-700' : 'text-gray-700'}`}>
                                                    {subject.name}
                                                </span>
                                                {isSelected && <Check className="w-4 h-4 text-blue-600" />}
                                            </div>
                                        )
                                    })}
                                </div>
                            </div>

                            {/* Specialized Selection */}
                            <div>
                                <div className="flex justify-between items-center mb-2">
                                    <label className="block text-base font-medium text-gray-800">
                                        Chß╗ìn 3 Chuy├¬n ─æß╗ü hß╗ìc tß║¡p
                                    </label>
                                    <span className={`text-sm font-medium ${formData.specializedSubjectIds.length === 3 ? 'text-green-600' : 'text-orange-500'}`}>
                                        ─É├ú chß╗ìn: {formData.specializedSubjectIds.length}/3
                                    </span>
                                </div>
                                <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-3 gap-3">
                                    {specialized.map(subject => {
                                        const isSelected = formData.specializedSubjectIds.includes(subject.id);
                                        return (
                                            <div
                                                key={subject.id}
                                                onClick={() => toggleSubject(subject.id, 'SPECIALIZED')}
                                                className={`cursor-pointer rounded-lg border p-3 flex items-center justify-between transition-all ${isSelected
                                                    ? 'bg-purple-50 border-purple-500 ring-1 ring-purple-500'
                                                    : 'bg-white border-gray-200 hover:border-gray-300'
                                                    }`}
                                            >
                                                <span className={`text-sm font-medium ${isSelected ? 'text-purple-700' : 'text-gray-700'}`}>
                                                    {subject.name}
                                                </span>
                                                {isSelected && <Check className="w-4 h-4 text-purple-600" />}
                                            </div>
                                        )
                                    })}
                                </div>
                            </div>

                            {/* Info Box */}
