import { useState, useEffect, useCallback } from "react";
import { createPortal } from "react-dom";
import { Plus, Bell, Send, X, ChevronDown, Clock, RotateCcw, Users, Search, ClipboardList, Calendar } from "lucide-react";
import { useToast } from "../../../context/ToastContext";
import { useConfirmation } from "../../../hooks/useConfirmation";

interface NotificationDto {
    id: string;
    title: string;
    content: string;
    type: string;
    targetGroup: string;
    referenceId?: string;
    actionUrl?: string;
    status: string;
    createdByName?: string;
    createdAt: string;
}

interface ClassRoomOption {
    id: string;
    name: string;
}

const API_BASE = import.meta.env.VITE_API_URL || "";

const TARGET_GROUP_LABELS: Record<string, string> = {
    ALL: "To├án tr╞░ß╗¥ng",
    TEACHER: "Gi├ío vi├¬n",
    STUDENT: "Hß╗ìc sinh",
    GUARDIAN: "Phß╗Ñ huynh",
    CLASS: "Theo lß╗¢p",
};

const NOTIFICATION_TYPE_LABELS: Record<string, string> = {
    EXAM: "Kiß╗âm tra",
    SCHEDULE: "Thß╗¥i kh├│a biß╗âu",
    OTHER: "Kh├íc",
};

function getToken() {
    return localStorage.getItem("accessToken");
}

export default function NotificationManagement() {
    const { toast } = useToast();
    const [notifications, setNotifications] = useState<NotificationDto[]>([]);
    const [loading, setLoading] = useState(true);
    const { confirm, ConfirmationDialog } = useConfirmation();
    const [page, setPage] = useState(0);
    const [totalPages, setTotalPages] = useState(0);
    const [showModal, setShowModal] = useState(false);
    const [submitting, setSubmitting] = useState(false);
    const [recalling, setRecalling] = useState<string | null>(null);

    // Form state
    const [formTitle, setFormTitle] = useState("");
    const [formContent, setFormContent] = useState("");
    const [formType, setFormType] = useState("OTHER");
    const [formTargetGroup, setFormTargetGroup] = useState("ALL");
    const [formClassId, setFormClassId] = useState("");

    // Filter states
    const [searchTerm, setSearchTerm] = useState("");
    const [typeFilter, setTypeFilter] = useState("");
    const [targetFilter, setTargetFilter] = useState("");
    const [statusFilter, setStatusFilter] = useState("");
    const [pageSize] = useState(15);

    // Class list (for CLASS target)
    const [classOptions, setClassOptions] = useState<ClassRoomOption[]>([]);

    const fetchNotifications = useCallback(async (p = 0) => {
        const token = getToken();
        setLoading(true);
        try {
            const params = new URLSearchParams({
                page: p.toString(),
                size: pageSize.toString(),
            });

            if (searchTerm) params.append("search", searchTerm);
            if (typeFilter) params.append("type", typeFilter);
            if (targetFilter) params.append("targetGroup", targetFilter);
            if (statusFilter) params.append("status", statusFilter);

            const res = await fetch(`${API_BASE}/v1/admin/notifications?${params.toString()}`, {
                headers: { Authorization: `Bearer ${token}` },
            });
            if (res.ok) {
                const data = await res.json();
                setNotifications(data.content || []);
                setTotalPages(data.totalPages || 0);
                setPage(data.number || 0);
            } else {
                toast.error("Lß╗ùi khi tß║úi danh s├ích th├┤ng b├ío");
            }
        } catch (error) {
            toast.error("Lß╗ùi khi tß║úi danh s├ích th├┤ng b├ío");
        } finally {
            setLoading(false);
        }
    }, [toast, searchTerm, typeFilter, targetFilter, statusFilter, pageSize]);

    const fetchClasses = async () => {
        try {
            const token = getToken();
            const res = await fetch(`${API_BASE}/school/classes`, {
                headers: { Authorization: `Bearer ${token}` },
            });
            if (res.ok) {
                const data = await res.json();
                const classes = (data || []).map((c: { id: string; name: string }) => ({
                    id: c.id,
                    name: c.name,
                }));
                setClassOptions(classes);
            }
        } catch (error) {
            console.error("Error fetching classes:", error);
        }
    };

    useEffect(() => {
        setPage(0);
        fetchNotifications(0);
        fetchClasses();
    }, [searchTerm, typeFilter, targetFilter, statusFilter, pageSize]);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!formTitle.trim() || !formContent.trim()) return;
        if (formTargetGroup === "CLASS" && !formClassId) {
            toast.error("Vui l├▓ng chß╗ìn lß╗¢p.");
            return;
        }

        setSubmitting(true);
        try {
            const token = getToken();
            const body: Record<string, string | null> = {
                title: formTitle.trim(),
                content: formContent.trim(),
                type: formType,
                targetGroup: formTargetGroup,
                referenceId: formTargetGroup === "CLASS" ? formClassId : null,
                actionUrl: null,
            };

            const res = await fetch(`${API_BASE}/v1/admin/notifications`, {
                method: "POST",
                headers: {
                    "Content-Type": "application/json",
                    Authorization: `Bearer ${token}`,
                },
                body: JSON.stringify(body),
            });

            if (res.ok) {
                resetForm();
                setShowModal(false);
                toast.success("Tß║ío th├┤ng b├ío th├ánh c├┤ng!");
                fetchNotifications(0);
            } else {
                const errData = await res.json().catch(() => ({}));
                toast.error(errData.message || "Lß╗ùi khi tß║ío th├┤ng b├ío");
            }
        } catch (error) {
            console.error("Error creating notification:", error);
            toast.error("Lß╗ùi khi tß║ío th├┤ng b├ío");
        } finally {
            setSubmitting(false);
        }
    };

    const handleRecall = async (id: string) => {
        confirm({
            title: "Thu hß╗ôi th├┤ng b├ío?",
            message: "Bß║ín c├│ chß║»c chß║»n muß╗æn thu hß╗ôi th├┤ng b├ío n├áy? Ng╞░ß╗¥i nhß║¡n sß║╜ kh├┤ng c├▓n thß║Ñy nß╗Öi dung th├┤ng b├ío nß╗»a.",
            variant: "danger",
            confirmText: "Thu hß╗ôi",
            onConfirm: async () => {
                setRecalling(id);
                try {
                    const token = getToken();
                    const res = await fetch(`${API_BASE}/v1/admin/notifications/${id}/recall`, {
                        method: "PATCH",
                        headers: { Authorization: `Bearer ${token}` },
                    });

                    if (res.ok) {
                        toast.success("─É├ú thu hß╗ôi th├┤ng b├ío");
                        fetchNotifications(page);
                    } else {
                        toast.error("Lß╗ùi khi thu hß╗ôi th├┤ng b├ío");
                    }
                } catch (error) {
                    console.error("Error recalling notification:", error);
                    toast.error("Lß╗ùi khi thu hß╗ôi th├┤ng b├ío");
                } finally {
                    setRecalling(null);
                }
            }
        });
    };

    const resetForm = () => {
        setFormTitle("");
        setFormContent("");
        setFormType("OTHER");
        setFormTargetGroup("ALL");
        setFormClassId("");
    };

    const formatDate = (dateString: string) => {
        const d = new Date(dateString);
        const day = String(d.getDate()).padStart(2, "0");
        const month = String(d.getMonth() + 1).padStart(2, "0");
        const year = d.getFullYear();
        const hours = String(d.getHours()).padStart(2, "0");
        const mins = String(d.getMinutes()).padStart(2, "0");
        return `${hours}:${mins} ${day}/${month}/${year}`;
    };

    if (loading && notifications.length === 0) {
        return (
            <div className="flex items-center justify-center h-64">
                <div className="w-8 h-8 border-4 border-blue-600 border-t-transparent rounded-full animate-spin" />
            </div>
        );
    }

    return (
        <div className="space-y-6 animate-fade-in-up">
            {/* Header */}
            <div className="flex items-center justify-between">
                <div>
                    <h1 className="text-2xl font-bold text-gray-900">Quß║ún l├╜ th├┤ng b├ío</h1>
                    <p className="text-sm text-gray-500 mt-1">Tß║ío v├á quß║ún l├╜ th├┤ng b├ío cho to├án tr╞░ß╗¥ng</p>
                </div>
                <button
                    onClick={() => setShowModal(true)}
                    className="flex items-center gap-2 px-4 py-2.5 bg-gradient-to-r from-blue-600 to-blue-500 text-white rounded-lg text-sm font-medium hover:shadow-lg transition-all"
                >
                    <Plus className="w-5 h-5" />
                    <span>Tß║ío th├┤ng b├ío</span>
                </button>
            </div>

            {/* Filter Bar */}
            <div className="bg-white p-4 rounded-xl shadow-sm border border-gray-100 flex flex-wrap items-center gap-4">
                <div className="relative flex-1 min-w-[200px]">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
                    <input
                        type="text"
                        placeholder="T├¼m kiß║┐m ti├¬u ─æß╗ü hoß║╖c nß╗Öi dung..."
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                        className="w-full pl-10 pr-4 py-2 rounded-lg border border-gray-200 focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 outline-none text-sm transition-all"
                    />
                </div>

                <select
                    value={typeFilter}
                    onChange={(e) => setTypeFilter(e.target.value)}
                    className="px-3 py-2 rounded-lg border border-gray-200 bg-white text-sm focus:ring-2 focus:ring-blue-500/20 outline-none transition-all"
                >
                    <option value="">Tß║Ñt cß║ú loß║íi</option>
                    <option value="EXAM">Kiß╗âm tra</option>
                    <option value="SCHEDULE">Thß╗¥i kh├│a biß╗âu</option>
                    <option value="OTHER">Kh├íc</option>
                </select>

                <select
                    value={targetFilter}
                    onChange={(e) => setTargetFilter(e.target.value)}
                    className="px-3 py-2 rounded-lg border border-gray-200 bg-white text-sm focus:ring-2 focus:ring-blue-500/20 outline-none transition-all"
                >
                    <option value="">Tß║Ñt cß║ú ─æß╗æi t╞░ß╗úng</option>
                    <option value="ALL">To├án tr╞░ß╗¥ng</option>
                    <option value="TEACHER">Gi├ío vi├¬n</option>
                    <option value="STUDENT">Hß╗ìc sinh</option>
                    <option value="GUARDIAN">Phß╗Ñ huynh</option>
                    <option value="CLASS">Theo lß╗¢p</option>
                    <option value="GRADE">Theo khß╗æi</option>
                </select>

                <select
                    value={statusFilter}
                    onChange={(e) => setStatusFilter(e.target.value)}
                    className="px-3 py-2 rounded-lg border border-gray-200 bg-white text-sm focus:ring-2 focus:ring-blue-500/20 outline-none transition-all"
                >
                    <option value="">Tß║Ñt cß║ú trß║íng th├íi</option>
                    <option value="ACTIVE">Hoß║ít ─æß╗Öng</option>
                    <option value="RECALLED">─É├ú thu hß╗ôi</option>
