                                        <Send className="w-5 h-5" />
                                    )}
                                    <span>{submitting ? "─Éang gß╗¡i..." : "Gß╗¡i th├┤ng b├ío"}</span>
                                </button>
                            </div>
                        </form>
                    </div>
                </div>,
                document.body
            )}
            {/* Confirmation Dialog */}
            <ConfirmationDialog />
        </div>
    );
}

