import { useEffect, useState } from "react";
import schoolReportService, {
    type ReportOverviewDto,
    type StudentReportDto,
    type TeacherReportDto,
    type ClassReportDto,
    type AttendanceReportDto,
    type AcademicReportDto,
    type TimetableReportDto,
} from "../../../services/schoolReportService";
import {
    StudentIcon,
    TeacherIcon,
    ClassIcon,
    CalendarIcon,
} from "../SchoolAdminIcons";
import { CheckIcon, BookIcon, TimetableIcon } from "../components/reports/ReportIcons";
import OverviewTab from "../components/reports/OverviewTab";
import StudentTab from "../components/reports/StudentTab";
import TeacherTab from "../components/reports/TeacherTab";
import ClassTab from "../components/reports/ClassTab";
import AttendanceTab from "../components/reports/AttendanceTab";
import AcademicTab from "../components/reports/AcademicTab";
import TimetableTab from "../components/reports/TimetableTab";
import { useSemester } from "../../../context/SemesterContext";
import SemesterSelector from "../../../components/common/SemesterSelector";

type TabType = "overview" | "students" | "teachers" | "classes" | "attendance" | "academic" | "timetable";

const ReportsPage = () => {
    const [activeTab, setActiveTab] = useState<TabType>("overview");
    const [loading, setLoading] = useState(false);
    const { activeSemester, allSemesters } = useSemester();
    const [selectedSemesterId, setSelectedSemesterId] = useState<string>("");

    // Initial load priority: System Active Semester
    useEffect(() => {
        if (!selectedSemesterId && activeSemester) {
            setSelectedSemesterId(activeSemester.id);
        }
    }, [activeSemester, selectedSemesterId]);

    const selectedSemester = allSemesters.find(s => s.id === selectedSemesterId);

    // Data states
    const [overview, setOverview] = useState<ReportOverviewDto | null>(null);
    const [studentReport, setStudentReport] = useState<StudentReportDto | null>(null);
    const [teacherReport, setTeacherReport] = useState<TeacherReportDto | null>(null);
    const [classReport, setClassReport] = useState<ClassReportDto | null>(null);
    const [attendanceReport, setAttendanceReport] = useState<AttendanceReportDto | null>(null);
    const [academicReport, setAcademicReport] = useState<AcademicReportDto | null>(null);
    const [timetableReport, setTimetableReport] = useState<TimetableReportDto | null>(null);

    useEffect(() => {
        if (selectedSemesterId) {
            fetchData(activeTab);
        }
    }, [activeTab, selectedSemesterId]);

    const fetchData = async (tab: TabType) => {
        setLoading(true);
        try {
            switch (tab) {
                case "overview":
                    const overviewData = await schoolReportService.getDashboardOverview();
                    setOverview(overviewData);
                    break;
                case "students":
                    const studentData = await schoolReportService.getStudentReport();
                    setStudentReport(studentData);
                    break;
                case "teachers":
                    const teacherData = await schoolReportService.getTeacherReport();
                    setTeacherReport(teacherData);
                    break;
                case "classes":
                    const classData = await schoolReportService.getClassReport();
                    setClassReport(classData);
                    break;
                case "attendance":
                    const attendanceData = await schoolReportService.getAttendanceReport();
                    setAttendanceReport(attendanceData);
                    break;
                case "academic":
                    const academicData = await schoolReportService.getAcademicReport(
                        selectedSemester?.academicYearName,
                        selectedSemester?.semesterNumber
                    );
                    setAcademicReport(academicData);
                    break;
                case "timetable":
                    const timetableData = await schoolReportService.getTimetableReport();
                    setTimetableReport(timetableData);
                    break;
            }
        } catch (error) {
            console.error("Failed to fetch report data:", error);
        } finally {
            setLoading(false);
        }
    };

    const tabs = [
        { id: "overview" as TabType, label: "Tß╗òng quan", icon: <CalendarIcon /> },
        { id: "students" as TabType, label: "Hß╗ìc sinh", icon: <StudentIcon /> },
        { id: "teachers" as TabType, label: "Gi├ío vi├¬n", icon: <TeacherIcon /> },
        { id: "classes" as TabType, label: "Lß╗¢p hß╗ìc", icon: <ClassIcon /> },
        { id: "attendance" as TabType, label: "─Éiß╗âm danh", icon: <CheckIcon /> },
        { id: "academic" as TabType, label: "Hß╗ìc tß║¡p", icon: <BookIcon /> },
        { id: "timetable" as TabType, label: "Thß╗¥i kh├│a biß╗âu", icon: <TimetableIcon /> },
    ];

    return (
        <div className="min-h-screen bg-gray-50 p-4 md:p-6 space-y-6">
            {/* Header */}
            <div className="bg-white rounded-xl p-6 shadow-sm border border-gray-100 flex flex-col md:flex-row md:items-center justify-between gap-4">
                <div>
                    <h1 className="text-2xl font-bold text-gray-900">B├ío c├ío & Thß╗æng k├¬</h1>
                    <p className="text-gray-500 text-sm">Hß╗ç thß╗æng ph├ón t├¡ch dß╗» liß╗çu gi├ío dß╗Ñc to├án diß╗çn</p>
                </div>
                <div className="flex items-center gap-4">
                    <SemesterSelector
                        value={selectedSemesterId}
                        onChange={setSelectedSemesterId}
                        label=""
                        className="bg-gray-50 border-gray-200 h-10 px-4 rounded-lg font-medium text-gray-700"
                    />
                </div>
            </div>

            {/* Navigation Tabs */}
            <div className="flex flex-wrap gap-2 border-b border-gray-200">
                {tabs.map((tab) => (
                    <button
                        key={tab.id}
                        onClick={() => setActiveTab(tab.id)}
                        className={`
                            px-6 py-3 text-sm font-semibold flex items-center gap-2 border-b-2 transition-all
                            ${activeTab === tab.id
                                ? 'border-blue-600 text-blue-600 bg-blue-50/30'
                                : 'border-transparent text-gray-500 hover:text-gray-700 hover:bg-gray-100'}
                        `}
                    >
                        {tab.label}
                    </button>
                ))}
            </div>

            {/* Content Area */}
            <div>
                {loading ? (
                    <div className="flex flex-col items-center justify-center h-64">
                        <div className="w-10 h-10 border-4 border-gray-200 border-t-blue-600 rounded-full animate-spin" />
                        <p className="text-gray-400 text-sm mt-4 font-medium">─Éang tß║úi dß╗» liß╗çu...</p>
                    </div>
                ) : (
                    <div className="animate-fade-in">
                        {activeTab === "overview" && overview && <OverviewTab data={overview} />}
                        {activeTab === "students" && studentReport && <StudentTab data={studentReport} />}
                        {activeTab === "teachers" && teacherReport && <TeacherTab data={teacherReport} />}
                        {activeTab === "classes" && classReport && <ClassTab data={classReport} />}
                        {activeTab === "attendance" && attendanceReport && <AttendanceTab data={attendanceReport} />}
                        {activeTab === "academic" && academicReport && <AcademicTab data={academicReport} />}
                        {activeTab === "timetable" && timetableReport && <TimetableTab data={timetableReport} />}
                    </div>
                )}
            </div>
        </div>
    );
};

export default ReportsPage;

import { useState, useEffect } from "react";
import { schoolAdminService, type RoomDto, type CreateRoomRequest } from "../../../services/schoolAdminService";
import { Plus, Edit2, Trash2, Building2, Users, X, Copy, Minus } from "lucide-react";
import { useToast } from "../../../context/ToastContext";
import { useConfirmation } from "../../../hooks/useConfirmation";

type ModalState = { open: boolean; room: RoomDto | null };

type BulkRoomRow = {
    name: string;
    capacity: number;
    building: string;
};

const emptyRow = (): BulkRoomRow => ({ name: "", capacity: 40, building: "" });

export default function RoomManagement() {
    const [rooms, setRooms] = useState<RoomDto[]>([]);
    const [loading, setLoading] = useState(true);
    const [modal, setModal] = useState<ModalState>({ open: false, room: null });
    const [form, setForm] = useState<CreateRoomRequest>({ name: "", capacity: 40, building: "", status: "ACTIVE" });
    const [saving, setSaving] = useState(false);
    const [sortConfig, setSortConfig] = useState<{ key: keyof RoomDto; direction: 'asc' | 'desc' } | null>(null);
    const { toast } = useToast();
    const { confirm, ConfirmationDialog } = useConfirmation();

    const sortedRooms = (rooms || []).slice().sort((a, b) => {
        if (!sortConfig) return 0;
        const { key, direction } = sortConfig;
        let aValue = a[key];
        let bValue = b[key];

        if (aValue === null || aValue === undefined) aValue = "";
        if (bValue === null || bValue === undefined) bValue = "";

        if (typeof aValue === 'string' && typeof bValue === 'string') {
            const cmp = aValue.localeCompare(bValue, undefined, { numeric: true, sensitivity: 'base' });
            return direction === 'asc' ? cmp : -cmp;
        }

        if (aValue < bValue) return direction === 'asc' ? -1 : 1;
        if (aValue > bValue) return direction === 'asc' ? 1 : -1;
        return 0;
    });

    const handleSort = (key: keyof RoomDto) => {
        setSortConfig(current => {
            if (current?.key === key) {
                if (current.direction === 'asc') return { key, direction: 'desc' };
                return null;
            }
            return { key, direction: 'asc' };
        });
    };

    const SortHeader = ({ label, sortKey, className = "" }: { label: string, sortKey: keyof RoomDto, className?: string }) => (
        <th
            className={`px-6 py-3 text-left text-xs font-semibold text-gray-500 uppercase tracking-wider cursor-pointer hover:bg-gray-100 hover:text-blue-600 transition-colors select-none ${className}`}
            onClick={() => handleSort(sortKey)}
        >
            <div className={`flex items-center gap-1 ${className.includes("text-center") ? "justify-center" : ""}`}>
                {label}
                <span className="text-gray-400">
                    {sortConfig?.key === sortKey ? (
                        sortConfig.direction === 'asc' ? 'Γåæ' : 'Γåô'
                    ) : (
                        <span className="opacity-0 group-hover:opacity-50">Γçà</span>
                    )}
                </span>
            </div>
        </th>
    );

    // Bulk add state
    const [bulkOpen, setBulkOpen] = useState(false);
    const [bulkRows, setBulkRows] = useState<BulkRoomRow[]>([emptyRow(), emptyRow(), emptyRow()]);
    const [bulkSaving, setBulkSaving] = useState(false);

    const fetchRooms = async () => {
        try {
            setLoading(true);
            const data = await schoolAdminService.listRooms();
            setRooms(data.content);
        } catch (e: any) {
            toast.error(e?.response?.data?.message || "Lß╗ùi tß║úi danh s├ích ph├▓ng");
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => { fetchRooms(); }, []);

    const openCreate = () => {
        setForm({ name: "", capacity: 40, building: "", status: "ACTIVE" });
        setModal({ open: true, room: null });
    };

    const openEdit = (room: RoomDto) => {
        setForm({ name: room.name, capacity: room.capacity, building: room.building || "", status: room.status });
        setModal({ open: true, room });
    };

    const handleSave = async () => {
        if (!form.name.trim()) { toast.error("T├¬n ph├▓ng kh├┤ng ─æ╞░ß╗úc ─æß╗â trß╗æng"); return; }
        if (form.capacity < 1) { toast.error("Sß╗⌐c chß╗⌐a phß║úi lß╗¢n h╞ín 0"); return; }
        try {
            setSaving(true);
            if (modal.room) {
                await schoolAdminService.updateRoom(modal.room.id, form);
            } else {
                await schoolAdminService.createRoom(form);
            }
            setModal({ open: false, room: null });
            toast.success(modal.room ? "Cß║¡p nhß║¡t ph├▓ng th├ánh c├┤ng!" : "Th├¬m ph├▓ng mß╗¢i th├ánh c├┤ng!");
            fetchRooms();
        } catch (e: any) {
            toast.error(e?.response?.data?.message || "Lß╗ùi l╞░u ph├▓ng");
        } finally {
            setSaving(false);
        }
    };

    const handleDelete = async (room: RoomDto) => {
        confirm({
            title: "X├│a ph├▓ng hß╗ìc?",
            message: (
                <span>
                    Bß║ín c├│ chß║»c chß║»n muß╗æn x├│a ph├▓ng <strong>{room.name}</strong>? H├ánh ─æß╗Öng n├áy kh├┤ng thß╗â ho├án t├íc.
                </span>
            ),
            variant: "danger",
            confirmText: "X├│a",
            onConfirm: async () => {
                try {
                    await schoolAdminService.deleteRoom(room.id);
                    toast.success("─É├ú x├│a ph├▓ng");
                    fetchRooms();
                } catch (e: any) {
                    toast.error(e?.response?.data?.message || "Lß╗ùi x├│a ph├▓ng");
                }
            }
        });
    };

    const handleStatusToggle = async (room: RoomDto) => {
        const newStatus = room.status === "ACTIVE" ? "INACTIVE" : "ACTIVE";
        try {
            await schoolAdminService.updateRoomStatus(room.id, newStatus);
            toast.success("─É├ú cß║¡p nhß║¡t trß║íng th├íi");
            fetchRooms();
        } catch (e: any) {
            toast.error(e?.response?.data?.message || "Lß╗ùi ─æß╗òi trß║íng th├íi");
        }
    };

    // ΓöÇΓöÇ Bulk add handlers ΓöÇΓöÇ
    const openBulk = () => {
        setBulkRows([emptyRow(), emptyRow(), emptyRow()]);
        setBulkOpen(true);
    };

    const updateBulkRow = (index: number, field: keyof BulkRoomRow, value: string | number) => {
        setBulkRows(prev => prev.map((r, i) => i === index ? { ...r, [field]: value } : r));
    };

    const addBulkRow = () => {
        setBulkRows(prev => [...prev, emptyRow()]);
    };

    const removeBulkRow = (index: number) => {
        if (bulkRows.length <= 1) return;
        setBulkRows(prev => prev.filter((_, i) => i !== index));
    };

    const handleBulkSave = async () => {
        const validRows = bulkRows.filter(r => r.name.trim() !== "");
        if (validRows.length === 0) {
            toast.error("Vui l├▓ng nhß║¡p ├¡t nhß║Ñt 1 ph├▓ng");
            return;
        }
        // Validate
        for (let i = 0; i < validRows.length; i++) {
            if (validRows[i].capacity < 1) {
                toast.error(`Ph├▓ng "${validRows[i].name}": Sß╗⌐c chß╗⌐a phß║úi lß╗¢n h╞ín 0`);
                return;
            }
        }
        // Check for duplicate names within the form
        const names = validRows.map(r => r.name.trim().toLowerCase());
        const duplicates = names.filter((name, idx) => names.indexOf(name) !== idx);
        if (duplicates.length > 0) {
            toast.error(`Tr├╣ng t├¬n ph├▓ng trong danh s├ích: ${[...new Set(duplicates)].join(", ")}`);
            return;
        }

        try {
            setBulkSaving(true);
            const requests: CreateRoomRequest[] = validRows.map(r => ({
                name: r.name.trim(),
                capacity: r.capacity,
                building: r.building.trim() || undefined,
                status: "ACTIVE" as const,
            }));
            await schoolAdminService.createBulkRooms(requests);
            setBulkOpen(false);
            toast.success(`─É├ú th├¬m ${validRows.length} ph├▓ng th├ánh c├┤ng!`);
            fetchRooms();
        } catch (e: any) {
            toast.error(e?.response?.data?.message || "Lß╗ùi th├¬m nhiß╗üu ph├▓ng");
        } finally {
            setBulkSaving(false);
        }
    };

    const statusBadge = (status: string) => {
        const colors: Record<string, string> = {
            ACTIVE: "bg-emerald-100 text-emerald-700",
            INACTIVE: "bg-gray-100 text-gray-500",
            MAINTENANCE: "bg-amber-100 text-amber-700",
        };
        const labels: Record<string, string> = { ACTIVE: "Hoß║ít ─æß╗Öng", INACTIVE: "Ng╞░ng", MAINTENANCE: "Bß║úo tr├¼" };
        return (
            <span className={`px-2.5 py-1 rounded-full text-xs font-medium ${colors[status] || "bg-gray-100 text-gray-500"}`}>
                {labels[status] || status}
            </span>
        );
    };

    return (
        <div className="space-y-6">
            {/* Header */}
            <div className="flex items-center justify-between">
                <div>
                    <h1 className="text-2xl font-bold text-gray-900">Quß║ún l├╜ Ph├▓ng hß╗ìc</h1>
                    <p className="text-sm text-gray-500 mt-1">Quß║ún l├╜ danh s├ích ph├▓ng hß╗ìc, ph├▓ng thi cß╗ºa tr╞░ß╗¥ng</p>
                </div>
                <div className="flex items-center gap-2">
                    <button onClick={openBulk}
                        className="flex items-center gap-2 px-4 py-2 bg-gradient-to-r from-violet-600 to-purple-500 text-white rounded-lg text-sm font-medium hover:shadow-lg transition-all">
                        <Copy className="w-4 h-4" /> Th├¬m nhiß╗üu ph├▓ng
                    </button>
                    <button onClick={openCreate}
                        className="flex items-center gap-2 px-4 py-2 bg-gradient-to-r from-blue-600 to-blue-500 text-white rounded-lg text-sm font-medium hover:shadow-lg transition-all">
                        <Plus className="w-4 h-4" /> Th├¬m ph├▓ng
                    </button>
                </div>
