                    setImportToastResult(null);
                    setShowImportModal(true);
                }}
            />
            <BatchDeleteModal
                isOpen={showBatchDeleteModal}
                onClose={() => setShowBatchDeleteModal(false)}
                onConfirm={handleBulkDelete}
                title="X├│a hß╗ìc sinh"
                message={
                    Array.from(selectedStudentIds).filter(id => students.find(s => s.id === id)?.hasAccount).length > 0
                        ? `Trong ─æ├│ c├│ ${Array.from(selectedStudentIds).filter(id => students.find(s => s.id === id)?.hasAccount).length} hß╗ìc sinh ─æang c├│ t├ái khoß║ún hß╗ç thß╗æng. T├ái khoß║ún ─æ─âng nhß║¡p cß╗ºa c├íc hß╗ìc sinh n├áy c┼⌐ng sß║╜ bß╗ï x├│a v─⌐nh viß╗àn.`
                        : `Bß║ín c├│ chß║»c chß║»n muß╗æn x├│a ${selectedStudentIds.size} hß╗ìc sinh ─æ├ú chß╗ìn?`
                }
                itemCount={selectedStudentIds.size}
                itemName="hß╗ìc sinh"
                confirmLabel={
                    Array.from(selectedStudentIds).some(id => students.find(s => s.id === id)?.hasAccount)
                        ? "T├┤i x├íc nhß║¡n x├│a hß╗ô s╞í v├á t├ái khoß║ún cß╗ºa c├íc hß╗ìc sinh n├áy"
                        : undefined
                }
            />
        </div>
    );
};

export default StudentManagement;

import { useState, useEffect, useRef, useMemo } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { createPortal } from 'react-dom';
import { schoolAdminService } from '../../../services/schoolAdminService';
import { teacherService } from '../../../services/teacherService';
import type { StudentProfileDto, ClassRoomDto, ScoreDto, SemesterDto } from '../../../services/schoolAdminService';
import { XIcon } from '../SchoolAdminIcons';
import { useToast } from '../../../context/ToastContext';
import { useAuth } from '../../../context/AuthContext';
import { formatDate } from '../../../utils/dateHelpers';
import StudentRiskProfileCard from '../components/StudentRiskProfileCard';



// Format instant for display
const formatInstant = (instantStr: string): string => {
    try {
        const date = new Date(instantStr);
        const day = String(date.getDate()).padStart(2, '0');
        const month = String(date.getMonth() + 1).padStart(2, '0');
        const year = date.getFullYear();
        return `${day}/${month}/${year}`;
    } catch {
        return instantStr;
    }
};

const StatusBadge = ({ status }: { status: string }) => {
    const statusColors: Record<string, string> = {
        ACTIVE: 'bg-emerald-100 text-emerald-700 border-emerald-200',
        GRADUATED: 'bg-blue-100 text-blue-700 border-blue-200',
        TRANSFERRED: 'bg-amber-100 text-amber-700 border-amber-200',
        SUSPENDED: 'bg-red-100 text-red-700 border-red-200',
    };
    const statusLabels: Record<string, string> = {
        ACTIVE: '─Éang hß╗ìc',
        GRADUATED: '─É├ú tß╗æt nghiß╗çp',
        TRANSFERRED: 'Chuyß╗ân tr╞░ß╗¥ng',
        SUSPENDED: 'Tß║ím nghß╗ë',
    };
    return (
        <span className={`inline-flex items-center px-2.5 py-0.5 rounded-md text-xs font-medium border ${statusColors[status] || 'bg-gray-100 text-gray-600 border-gray-200'}`}>
            {statusLabels[status] || status}
        </span>
    );
};

const TransferModal = ({
    isOpen,
    studentName,
    classes,
    currentClassId,
    onClose,
    onTransfer
}: {
    isOpen: boolean;
    studentName: string;
    classes: ClassRoomDto[];
    currentClassId: string | null;
    onClose: () => void;
    onTransfer: (newClassId: string) => void;
}) => {
    const [selectedClassId, setSelectedClassId] = useState('');
    const [loading, setLoading] = useState(false);

    if (!isOpen) return null;

    const handleTransfer = async () => {
        if (!selectedClassId) return;
        setLoading(true);
        try {
            await onTransfer(selectedClassId);
        } finally {
            setLoading(false);
        }
    };

    return createPortal(
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
