                        onChange={(e) => {
                            setGradeFilter(e.target.value);
                            setSelectedClassId(""); // Reset class when grade changes
                        }}
                    >
                        <option value="ALL">Tß║Ñt cß║ú c├íc khß╗æi</option>
                        <option value="10">Khß╗æi 10</option>
                        <option value="11">Khß╗æi 11</option>
                        <option value="12">Khß╗æi 12</option>
                    </select>

                    <select
                        value={selectedClassId}
                        onChange={(e) => setSelectedClassId(e.target.value)}
                        className="px-3 py-2 bg-slate-50 border border-slate-200 rounded-xl text-sm focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 outline-none transition-all min-w-[200px]"
                    >
                        <option value="">-- Chß╗ìn lß╗¢p --</option>
                        {filteredClasses.map(c => (
                            <option key={c.id} value={c.id}>{c.name} (Khß╗æi {c.grade})</option>
                        ))}
                    </select>

                    {selectedClassId && assignments.length > 0 && (
                        <div className="ml-auto flex items-center gap-4">
                            <div className="flex flex-col items-end">
                                <span className="text-xs text-slate-500">Tiß║┐n ─æß╗Ö ph├ón c├┤ng</span>
                                <div className="flex items-center gap-2">
                                    <span className="text-sm font-medium text-slate-700">{getAssignedCount()}/{assignments.length} m├┤n</span>
                                    <div className="w-24 bg-gray-200 rounded-full h-2">
                                        <div className={`h-2 rounded-full ${getProgressColor()}`} style={{ width: `${(getAssignedCount() / assignments.length) * 100}%` }}></div>
                                    </div>
                                </div>
                            </div>
                        </div>
                    )}
                </div>
            </div>

            {/* Assignments List */}
            {loading ? (
                <div className="text-center py-12">
                    <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600 mx-auto"></div>
                </div>
            ) : assignments.length === 0 ? (
                <div className="text-center py-12 bg-gray-50 rounded-xl border border-dashed border-gray-300">
                    <p className="text-gray-500 mb-4">Ch╞░a c├│ dß╗» liß╗çu ph├ón c├┤ng cho lß╗¢p n├áy. H├úy chß║»c chß║»n lß╗¢p n├áy ─æ├ú ─æ╞░ß╗úc g├ín tß╗ò hß╗úp m├┤n.</p>
                </div>
            ) : (
                <div className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden">
                    <table className="min-w-full divide-y divide-gray-200">
                        <thead className="bg-gray-50">
                            <tr>
                                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">M├┤n hß╗ìc</th>
                                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Sß╗æ tiß║┐t/Tuß║ºn</th>
                                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Gi├ío vi├¬n phß╗Ñ tr├ích</th>
                                <th className="px-6 py-3 text-right text-xs font-medium text-gray-500 uppercase tracking-wider">Thao t├íc</th>
                            </tr>
                        </thead>
                        <tbody className="bg-white divide-y divide-gray-200">
                            {assignments.map(assign => (
                                <tr key={assign.id} className="hover:bg-blue-50 transition-colors">
                                    <td className="px-6 py-4 whitespace-nowrap">
                                        <div className="flex items-center">
                                            <div className="h-8 w-8 rounded-full bg-blue-100 flex items-center justify-center text-blue-600 font-bold text-xs mr-3">
                                                {assign.subjectName.substring(0, 1)}
                                            </div>
                                            <div className="text-sm font-medium text-gray-900">{assign.subjectName}</div>
                                        </div>
                                    </td>
                                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
                                        {assign.lessonsPerWeek} tiß║┐t
                                    </td>
                                    <td className="px-6 py-4 whitespace-nowrap">
                                        <select
                                            value={pendingAssignments[assign.id] || ""}
                                            onChange={(e) => setPendingAssignments({
                                                ...pendingAssignments,
                                                [assign.id]: e.target.value
                                            })}
                                            className={`w-full border rounded-lg px-3 py-2 outline-none focus:ring-2 focus:ring-blue-500 text-sm transition-all ${pendingAssignments[assign.id] ? 'border-gray-300 bg-white' : 'border-slate-200 bg-slate-50 font-medium'
                                                }`}
                                        >
                                            <option value="">-- Ch╞░a g├ín --</option>
                                            {filterTeachersForSubject(assign.subjectId, assign.subjectName).map(t => (
                                                <option key={t.id} value={t.id}>{t.fullName} ({t.email})</option>
                                            ))}
                                        </select>
                                    </td>
                                    <td className="px-6 py-4 whitespace-nowrap text-right text-sm font-medium">
                                        {pendingAssignments[assign.id] !== (assign.teacherId || "") && (
                                            <span className="text-blue-500 text-[10px] font-bold uppercase tracking-tight">Cß║ºn l╞░u</span>
                                        )}
                                    </td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>
            )}

            {/* Confirmation Dialog */}
            <ConfirmationDialog />
        </div>
    );
}

import React, { useEffect, useState } from "react";
import {
    schoolAdminService,
    type TeacherDto,
    type ImportTeacherResult
} from "../../../services/schoolAdminService";
import { PlusIcon } from "../SchoolAdminIcons";
import { TeacherStatusBadge } from '../../../components/common/StatusBadge';
import BatchDeleteModal from '../../../components/common/BatchDeleteModal';

import AddTeacherModal from "../components/teacher/AddTeacherModal";
import TeacherDetailModal from "../components/teacher/TeacherDetailModal";
import EditTeacherModal from "../components/teacher/EditTeacherModal";
import ImportTeacherExcelModal from "../components/teacher/ImportTeacherExcelModal";
import ImportTeacherResultModal from "../components/teacher/ImportTeacherResultModal";
import { useToast } from "../../../context/ToastContext";
import { vietnameseNameSort } from "../../../utils/sortUtils";
import Pagination from "../../../components/common/Pagination";



// ==================== PAGE COMPONENT ======================================

const TeacherManagement = () => {

    // ... (keep existing state)
    const [teachers, setTeachers] = useState<TeacherDto[]>([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState<string | null>(null);
    const [showAddTeacherModal, setShowAddTeacherModal] = useState(false);
    const [showImportModal, setShowImportModal] = useState(false);
    const [importResult, setImportResult] = useState<ImportTeacherResult | null>(null);
    const [selectedTeacher, setSelectedTeacher] = useState<TeacherDto | null>(null);
    const [editingTeacher, setEditingTeacher] = useState<TeacherDto | null>(null);

    // Pagination
    const [currentPage, setCurrentPage] = useState(0);
    const [pageSize, setPageSize] = useState(50);
    const [totalItems, setTotalItems] = useState(0);
    const [searchQuery, setSearchQuery] = useState("");
    const [debouncedSearch, setDebouncedSearch] = useState("");

    // Bulk selection
    const [showBatchDeleteModal, setShowBatchDeleteModal] = useState(false);
    const [selectedTeacherIds, setSelectedTeacherIds] = useState<Set<string>>(new Set());


    // Success toast state - Replaced by global useToast
    const { showSuccess } = useToast();

    // New State for Filter & Sort
    const [subjects, setSubjects] = useState<any[]>([]);
    const [filterSubjectId, setFilterSubjectId] = useState<string>("");
    const [sortConfig, setSortConfig] = useState<{ key: keyof TeacherDto | 'subjectName'; direction: 'asc' | 'desc' } | null>(null);

    useEffect(() => {
        fetchSubjects();
    }, []);

    useEffect(() => {
        const timer = setTimeout(() => {
            setDebouncedSearch(searchQuery);
            setCurrentPage(0); // Reset page on search
        }, 500);
        return () => clearTimeout(timer);
    }, [searchQuery]);

    useEffect(() => {
        fetchData();
        setSelectedTeacherIds(new Set());
    }, [currentPage, pageSize, debouncedSearch]);


    const fetchData = async (silent = false) => {
        try {
            if (!silent) setLoading(true);
            const data = await schoolAdminService.listTeacherProfiles(currentPage, pageSize, debouncedSearch);
            setTeachers(data.content);
            setTotalItems(data.totalElements);
        } catch (err: any) {
            setError(err?.response?.data?.message || "Kh├┤ng thß╗â tß║úi dß╗» liß╗çu.");
        } finally {
            if (!silent) setLoading(false);
        }
    };

    const fetchSubjects = async () => {
        try {
            const data = await schoolAdminService.listSubjects();
            setSubjects(data);
        } catch (error) {
            console.error("Failed to fetch subjects:", error);
        }
    };

    const handleSelectAll = (e: React.ChangeEvent<HTMLInputElement>) => {
        if (e.target.checked) {
            const allIds = teachers.map(t => t.id);
            setSelectedTeacherIds(new Set(allIds));
        } else {
            setSelectedTeacherIds(new Set());
        }
    };

    const handleSelectOne = (id: string) => {
        const newSelected = new Set(selectedTeacherIds);
        if (newSelected.has(id)) {
            newSelected.delete(id);
        } else {
            newSelected.add(id);
        }
        setSelectedTeacherIds(newSelected);
    };



    const handleBulkDelete = async () => {
        try {
            const result = await schoolAdminService.bulkDeleteTeachers(Array.from(selectedTeacherIds));

            if (result.deleted > 0) {
                await fetchData(true); // Silent refresh
                setSelectedTeacherIds(new Set());
            }

            return result;
        } catch (error) {
            console.error("Failed to delete teachers:", error);
            return { deleted: 0, failed: selectedTeacherIds.size, errors: ["Lß╗ùi hß╗ç thß╗æng hoß║╖c mß║Ñt kß║┐t nß╗æi"] };
        }
    };


    // Filter & Sort Logic
    const sortedTeachers = React.useMemo(() => {
        let result = [...teachers];

        // 1. Local Filter by Subject (if needed)
        if (filterSubjectId) {
            result = result.filter(t => t.subjects && t.subjects.some(s => s.id === filterSubjectId));
        }

        // 2. Sort
        if (sortConfig) {
            result.sort((a, b) => {
                let aValue: any = sortConfig.key === 'subjectName' ? (a.subjectNames || '') : a[sortConfig.key as keyof TeacherDto];
                let bValue: any = sortConfig.key === 'subjectName' ? (b.subjectNames || '') : b[sortConfig.key as keyof TeacherDto];

                if (!aValue) aValue = "";
                if (!bValue) bValue = "";

                if (typeof aValue === 'string') {
                    if (sortConfig.key === 'fullName') {
                        return sortConfig.direction === 'asc'
                            ? vietnameseNameSort(aValue, bValue as string)
                            : vietnameseNameSort(bValue as string, aValue);
                    }
                    return sortConfig.direction === 'asc'
                        ? aValue.localeCompare(bValue as string, 'vi')
                        : (bValue as string).localeCompare(aValue, 'vi');
                }

                if (aValue < bValue) return sortConfig.direction === 'asc' ? -1 : 1;
                if (aValue > bValue) return sortConfig.direction === 'asc' ? 1 : -1;
                return 0;
            });
        }

        return result;
    }, [teachers, filterSubjectId, sortConfig]);

    // const { ... } = usePagination(...) -> Removed in favor of server-side pagination state

    const handleSort = (key: keyof TeacherDto | 'subjectName') => {
        setSortConfig(current => {
            if (current?.key === key) {
                if (current.direction === 'asc') return { key, direction: 'desc' };
                return null; // Reset sort
            }
            return { key, direction: 'asc' };
        });
    };

    // Helper to render sort icon
    const SortHeader = ({ label, sortKey, className = "" }: { label: string, sortKey: keyof TeacherDto | 'subjectName', className?: string }) => (
        <th
            className={`px-6 py-3 text-left text-xs font-semibold text-gray-500 uppercase cursor-pointer hover:bg-gray-100 hover:text-blue-600 transition-colors select-none ${className}`}
            onClick={() => handleSort(sortKey)}
        >
            <div className="flex items-center gap-1">
                {label}
                <span className="text-gray-400">
                    {sortConfig?.key === sortKey ? (
                        sortConfig.direction === 'asc' ? 'Γåæ' : 'Γåô'
                    ) : (
                        <span className="opacity-0 group-hover:opacity-50">Γçà</span>
                    )}
                </span>
            </div>
        </th>
    );

    return (
        <div className="bg-white rounded-xl shadow-sm border border-gray-100 animate-fade-in-up">
            <div className="px-6 py-4 border-b border-gray-100 flex items-center justify-between">
                <h2 className="text-lg font-semibold text-gray-900">Danh s├ích gi├ío vi├¬n</h2>
                <div className="flex gap-2">
                    <div className="relative">
                        <input
                            type="text"
                            placeholder="T├¼m kiß║┐m gi├ío vi├¬n..."
                            value={searchQuery}
                            onChange={(e) => setSearchQuery(e.target.value)}
                            className="pl-9 pr-4 py-2 border border-gray-200 rounded-lg text-sm focus:outline-none focus:border-blue-500 bg-gray-50 hover:bg-white transition-colors"
                        />
                        <svg className="w-4 h-4 text-gray-400 absolute left-3 top-2.5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
                        </svg>
                    </div>
                    <select
                        value={filterSubjectId}
                        onChange={(e) => setFilterSubjectId(e.target.value)}
                        className="px-3 py-2 border border-gray-200 rounded-lg text-sm text-gray-600 focus:outline-none focus:border-blue-500 bg-gray-50 hover:bg-white transition-colors cursor-pointer"
                    >
                        <option value="">Tß║Ñt cß║ú bß╗Ö m├┤n</option>
                        {subjects.map((sub: any) => (
                            <option key={sub.id} value={sub.id}>{sub.name}</option>
                        ))}
                    </select>
                    {selectedTeacherIds.size > 0 && (
                        <button
                            onClick={() => setShowBatchDeleteModal(true)}
                            className="flex items-center gap-2 px-4 py-2 bg-red-50 text-red-600 rounded-lg text-sm font-medium hover:bg-red-100 transition-all border border-red-200"
                        >
                            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                            </svg>
                            <span>X├│a {selectedTeacherIds.size} mß╗Ñc</span>
                        </button>
                    )}

                    <button
                        onClick={() => setShowImportModal(true)}
                        className="flex items-center gap-2 px-4 py-2 bg-gradient-to-r from-emerald-600 to-emerald-500 text-white rounded-lg text-sm font-medium hover:shadow-lg transition-all"
                    >
                        <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-8l-4-4m0 0L8 8m4-4v12" />
                        </svg>
                        <span>Import Excel</span>
                    </button>
                    <button
                        onClick={() => setShowAddTeacherModal(true)}
                        className="flex items-center gap-2 px-4 py-2 bg-gradient-to-r from-blue-600 to-blue-500 text-white rounded-lg text-sm font-medium hover:shadow-lg transition-all"
                    >
                        <PlusIcon />
                        <span>Th├¬m gi├ío vi├¬n</span>
                    </button>
                </div>
            </div>

            {loading && <div className="p-8 text-center text-gray-500">─Éang tß║úi danh s├ích...</div>}
            {error && <div className="m-6 bg-red-50 text-red-600 p-4 rounded">{error}</div>}

            {!loading && !error && (
                <div className="overflow-x-auto">
                    <table className="w-full">
                        <thead className="bg-gray-50">
                            <tr>
                                <th className="px-6 py-3 w-4">
                                    <input
                                        type="checkbox"
                                        className="rounded border-gray-300 text-blue-600 focus:ring-blue-500"
                                        checked={teachers.length > 0 && teachers.every(t => selectedTeacherIds.has(t.id))}
                                        onChange={handleSelectAll}
                                    />
                                </th>
                                <SortHeader label="M├ú GV" sortKey="teacherCode" />

                                <SortHeader label="Hß╗ì t├¬n" sortKey="fullName" />
                                <SortHeader label="Email" sortKey="email" />
                                <SortHeader label="─Éiß╗çn thoß║íi" sortKey="phone" />
                                <SortHeader label="Bß╗Ö m├┤n" sortKey="subjectName" />
                                <SortHeader label="Lß╗¢p CN" sortKey="homeroomClassName" />
                                <SortHeader label="Trß║íng th├íi" sortKey="status" />
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-gray-100">
                            {sortedTeachers.map((teacher) => (
                                <tr key={teacher.id} className="hover:bg-blue-50 transition-colors cursor-pointer" onClick={() => setSelectedTeacher(teacher)}>
                                    <td className="px-6 py-4" onClick={(e) => e.stopPropagation()}>
                                        <input
                                            type="checkbox"
                                            className="rounded border-gray-300 text-blue-600 focus:ring-blue-500"
                                            checked={selectedTeacherIds.has(teacher.id)}
                                            onChange={() => handleSelectOne(teacher.id)}
                                        />
                                    </td>
                                    <td className="px-6 py-4 text-sm font-medium text-gray-900">{teacher.teacherCode}</td>

                                    <td className="px-6 py-4 text-sm text-gray-700">{teacher.fullName}</td>
                                    <td className="px-6 py-4 text-sm text-gray-600">{teacher.email || 'ΓÇö'}</td>
                                    <td className="px-6 py-4 text-sm text-gray-600">{teacher.phone || 'ΓÇö'}</td>
                                    <td className="px-6 py-4 text-sm text-gray-600">
                                        {teacher.subjects && teacher.subjects.length > 0 ? (
                                            <div className="flex flex-wrap gap-1">
                                                {teacher.subjects.map(sub => (
                                                    <span key={sub.id} className="inline-flex items-center px-2 py-0.5 rounded text-xs font-medium bg-purple-50 text-purple-700 border border-purple-100">
                                                        {sub.name}
                                                    </span>
                                                ))}
                                            </div>
                                        ) : (
                                            <span className="text-gray-400 italic">--</span>
                                        )}
                                    </td>

                                    <td className="px-6 py-4">
                                        {teacher.homeroomClassName ? (
                                            <span className="px-2 py-1 text-xs font-medium rounded-full bg-blue-100 text-blue-700">
                                                {teacher.homeroomClassName}
                                            </span>
                                        ) : (
                                            <span className="text-gray-400 text-sm">ΓÇö</span>
                                        )}
                                    </td>
                                    <td className="px-6 py-4">
                                        <TeacherStatusBadge status={teacher.status || 'ACTIVE'} />
                                    </td>
                                </tr>
                            ))}
                            {teachers.length === 0 && (
                                <tr>
                                    <td colSpan={8} className="px-6 py-8 text-center text-gray-500">
                                        Ch╞░a c├│ gi├ío vi├¬n n├áo. Bß║Ñm "Th├¬m gi├ío vi├¬n" ─æß╗â bß║»t ─æß║ºu.
                                    </td>
                                </tr>
                            )}
                        </tbody>
                    </table>
                </div>
            )}

            {totalItems > pageSize && !loading && !error && (
                <div className="mt-4 bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
                    <Pagination
                        currentPage={currentPage}
                        totalPages={Math.ceil(totalItems / pageSize)}
                        onPageChange={setCurrentPage}
                        pageSize={pageSize}
                        onPageSizeChange={setPageSize}
                        totalItems={totalItems}
                    />
                </div>
            )}

            <AddTeacherModal
                isOpen={showAddTeacherModal}
                onClose={() => setShowAddTeacherModal(false)}
                onSuccess={() => {
                    fetchData();
                    showSuccess("Th├¬m gi├ío vi├¬n th├ánh c├┤ng!");
                }}
            />
            <TeacherDetailModal
                isOpen={selectedTeacher !== null}
                teacher={selectedTeacher}
                onClose={() => setSelectedTeacher(null)}
                onEdit={(t) => {
                    setSelectedTeacher(null);
                    setEditingTeacher(t);
                }}
            />
            <EditTeacherModal
                isOpen={editingTeacher !== null}
                teacher={editingTeacher}
                onClose={() => setEditingTeacher(null)}
                onSuccess={() => {
                    fetchData();
                    showSuccess("Cß║¡p nhß║¡t th├┤ng tin gi├ío vi├¬n th├ánh c├┤ng!");
                }}
            />
            <BatchDeleteModal
                isOpen={showBatchDeleteModal}
                onClose={() => setShowBatchDeleteModal(false)}
                onConfirm={handleBulkDelete}
                title="X├│a gi├ío vi├¬n"
                message={`Bß║ín c├│ chß║»c chß║»n muß╗æn x├│a ${selectedTeacherIds.size} gi├ío vi├¬n ─æ├ú chß╗ìn?`}
                itemCount={selectedTeacherIds.size}
                itemName="gi├ío vi├¬n"
            />

            <ImportTeacherExcelModal
                isOpen={showImportModal}
                onClose={() => setShowImportModal(false)}
                onSuccess={fetchData}
                onImportComplete={(result) => {
                    setImportResult(result);
                }}
            />
            <ImportTeacherResultModal
                result={importResult}
                onClose={() => setImportResult(null)}
                onRetry={() => {
                    setImportResult(null);
                    setShowImportModal(true);
                }}
            />

        </div>
    );
};

export default TeacherManagement;

import { useState, useEffect, useCallback, useMemo } from "react";
import { useParams, useNavigate } from "react-router-dom";
import {
  DndContext,
  DragOverlay,
  closestCenter,
  PointerSensor,
  useSensor,
  useSensors,
  type DragStartEvent,
  type DragEndEvent,
  type DragOverEvent,
} from "@dnd-kit/core";
import api from "../../../services/api";
import { useToast } from "../../../context/ToastContext";
import { useConfirmation } from "../../../hooks/useConfirmation";
import {
  ArrowLeft,
  Lock,
  Unlock,
  AlertTriangle,
  Loader2,
  GripVertical,
  Sun,
  Moon,
  Rocket,
  Plus,
  XCircle,
} from "lucide-react";
import { schoolAdminService, type ClassRoomDto } from "../../../services/schoolAdminService";

// ΓöÇΓöÇΓöÇ Types ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
interface TimetableDetail {
  id: string;
  classRoomId: string;
  className: string;
  subjectId: string;
  subjectName: string;
  subjectCode: string;
  teacherId: string | null;
  teacherName: string | null;
  dayOfWeek: string;
  slotIndex: number;
  isFixed: boolean;
}

// ΓöÇΓöÇΓöÇ Constants ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
const DAYS = ["Thß╗⌐ Hai", "Thß╗⌐ Ba", "Thß╗⌐ T╞░", "Thß╗⌐ N─âm", "Thß╗⌐ S├íu", "Thß╗⌐ Bß║úy", "Chß╗º Nhß║¡t"];
const ENGLISH_DAYS = ["MONDAY", "TUESDAY", "WEDNESDAY", "THURSDAY", "FRIDAY", "SATURDAY", "SUNDAY"];
const MORNING_SLOTS = [1, 2, 3, 4, 5];
const AFTERNOON_SLOTS = [6, 7, 8, 9, 10];
const ALL_SLOTS = [...MORNING_SLOTS, ...AFTERNOON_SLOTS];

// Professional monochromatic theme for lessons
const LESSON_THEME = {
  bg: "bg-white",
  border: "border-slate-200",
  text: "text-slate-700",
  hover: "hover:border-blue-300 hover:bg-blue-50/30"
};

function getSubjectColor(_code: string) {
  return LESSON_THEME;
}

// ΓöÇΓöÇΓöÇ Droppable Cell ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
import { useDroppable } from "@dnd-kit/core";

function DroppableCell({
  id,
  children,
  isValidTarget,
  isInvalidTarget,
  isDragActive,
}: {
  id: string;
  children: React.ReactNode;
  isValidTarget?: boolean;
  isInvalidTarget?: boolean;
  isDragActive?: boolean;
}) {
  const { setNodeRef, isOver } = useDroppable({ id });

  return (
    <td
      ref={setNodeRef}
      className={`p-0.5 h-[56px] border-r border-gray-100 text-xs align-middle transition-all duration-200
        ${isOver && isValidTarget ? "bg-emerald-100/70 ring-2 ring-emerald-400 ring-inset scale-[1.01]" : ""}
        ${isOver && isInvalidTarget ? "bg-red-100/70 ring-2 ring-red-400 ring-inset" : ""}
        ${isOver && !isValidTarget && !isInvalidTarget ? "bg-blue-100/60 ring-2 ring-blue-400 ring-inset" : ""}
        ${isDragActive && isValidTarget && !isOver ? "bg-emerald-50/40" : ""}
        ${isDragActive && isInvalidTarget && !isOver ? "bg-red-50/30 opacity-60" : ""}
      `}
    >
      {children}
    </td>
  );
}

// ΓöÇΓöÇΓöÇ Draggable Lesson Card ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
import { useDraggable } from "@dnd-kit/core";

function DraggableLessonCard({
  detail,
  onToggleLock,
}: {
  detail: TimetableDetail;
  onToggleLock: (id: string) => void;
}) {
  const { attributes, listeners, setNodeRef, transform, isDragging } = useDraggable({
    id: detail.id,
    disabled: detail.isFixed,
  });

  const color = getSubjectColor(detail.subjectCode || "");

  const style = transform
    ? { transform: `translate3d(${transform.x}px, ${transform.y}px, 0)` }
    : undefined;

  const teacherLastName = detail.teacherName
    ? detail.teacherName.split(" ").pop()
    : null;

  return (
    <div
      ref={setNodeRef}
      style={style}
      {...listeners}
      {...attributes}
      className={`
        relative group flex flex-col items-center justify-center h-full w-full rounded-lg
        border ${color.border} ${color.bg} ${color.text} ${color.hover}
        transition-all duration-200 shadow-sm
        ${detail.isFixed
          ? "ring-2 ring-slate-400 cursor-not-allowed opacity-90 shadow-none border-slate-300"
          : "cursor-grab active:cursor-grabbing hover:shadow-lg hover:-translate-y-0.5"
        }
        ${isDragging ? "opacity-30 scale-95 rotate-1 shadow-2xl z-50" : ""}
      `}
    >
      {/* Drag grip hint */}
      {!detail.isFixed && (
        <GripVertical
          size={10}
          className="absolute top-0.5 left-0.5 text-gray-300 opacity-0 group-hover:opacity-60 transition-opacity"
        />
      )}

      <span className="font-semibold text-[11px] leading-tight text-center px-1 truncate w-full">
        {detail.subjectName}
      </span>
      {teacherLastName && (
        <span className="text-[9px] opacity-70 truncate w-full text-center px-1">
          {teacherLastName}
        </span>
      )}

      {/* Lock Button */}
      <button
        onClick={(e) => {
          e.stopPropagation();
          onToggleLock(detail.id);
        }}
        onPointerDown={(e) => e.stopPropagation()}
        className={`
          absolute -top-1 -right-1 w-4 h-4 rounded-full flex items-center justify-center
          transition-opacity z-10
          ${detail.isFixed
            ? "bg-amber-400 text-white opacity-100"
            : "bg-white border border-gray-300 text-gray-400 hover:bg-gray-100 opacity-0 group-hover:opacity-100"
          }
        `}
        title={detail.isFixed ? "Bß╗Å ghim" : "Ghim cß╗æ ─æß╗ïnh"}
      >
        {detail.isFixed ? <Lock size={8} /> : <Unlock size={8} />}
      </button>
    </div>
  );
}

// ΓöÇΓöÇΓöÇ Dragging Overlay Card ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
function DragOverlayCard({ detail }: { detail: TimetableDetail }) {
  const color = getSubjectColor(detail.subjectCode || "");
  const teacherLastName = detail.teacherName?.split(" ").pop();

  return (
    <div
      className={`
        flex flex-col items-center justify-center h-[52px] w-[120px] rounded-xl shadow-2xl
        border-2 ${color.border} ${color.bg} ${color.text}
        ring-2 ring-blue-500 ring-offset-2
        animate-scale-in
      `}
    >
      <span className="font-bold text-[11px]">{detail.subjectName}</span>
      {teacherLastName && (
        <span className="text-[9px] opacity-70">{teacherLastName}</span>
      )}
    </div>
  );
}



// ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ
// MAIN PAGE COMPONENT
// ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ
export default function TimetableAdjustPage() {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const { showSuccess, toast } = useToast();
  const { ConfirmationDialog } = useConfirmation();

  // Data
  const [details, setDetails] = useState<TimetableDetail[]>([]);
  const [timetableName, setTimetableName] = useState("");
  const [timetableStatus, setTimetableStatus] = useState("");
  const [loading, setLoading] = useState(true);

  // Filters
  const [gradeFilter, setGradeFilter] = useState<string>("ALL");
  const [selectedClass, setSelectedClass] = useState<string>("");
  const [classesList, setClassesList] = useState<ClassRoomDto[]>([]);

  // DnD state
  const [activeId, setActiveId] = useState<string | null>(null);
  const [saving, setSaving] = useState(false);

  const sensors = useSensors(
    useSensor(PointerSensor, {
      activationConstraint: { distance: 5 },
    })
  );

  // ΓöÇΓöÇΓöÇ Data Fetch ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  useEffect(() => {
    const fetchClasses = async () => {
      try {
        const data = await schoolAdminService.listClasses();
        setClassesList(data);
        if (data.length > 0 && !selectedClass) {
          setSelectedClass(data[0].name);
        }
      } catch {
        toast.error("Kh├┤ng thß╗â tß║úi danh s├ích lß╗¢p hß╗ìc");
      }
    };
    fetchClasses();
  }, []);

  const fetchDetails = useCallback(async () => {
    if (!id) return;
    try {
      setLoading(true);
      const params: Record<string, string> = {};
      if (gradeFilter !== "ALL") params.grade = gradeFilter;
      if (selectedClass) params.className = selectedClass;

      const [detailsRes, infoRes] = await Promise.all([
        api.get(`/school-admin/timetables/${id}/details`, { params }),
        api.get(`/school-admin/timetables/${id}`),
      ]);
      setDetails(detailsRes.data);
      setTimetableName(infoRes.data.name);
      setTimetableStatus(infoRes.data.status);
    } catch {
      toast.error("Kh├┤ng thß╗â tß║úi dß╗» liß╗çu thß╗¥i kh├│a biß╗âu");
    } finally {
      setLoading(false);
    }
  }, [id, gradeFilter, selectedClass]);

  useEffect(() => {
    if (id && selectedClass) fetchDetails();
  }, [id, selectedClass, gradeFilter, fetchDetails]);

  // ΓöÇΓöÇΓöÇ Helpers ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  const getCell = (className: string, englishDay: string, slot: number) =>
    details.find(
      (d) => d.className === className && d.dayOfWeek === englishDay && d.slotIndex === slot
    );

  const filteredClasses = classesList
    .filter((c) => gradeFilter === "ALL" || c.grade.toString() === gradeFilter)
    .sort((a, b) => a.name.localeCompare(b.name, undefined, { numeric: true, sensitivity: 'base' }));

  // ΓöÇΓöÇΓöÇ Real-time drag validation ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  // Compute which cells are valid/invalid when an item is being dragged
  const dragValidation = useMemo(() => {
    if (!activeId) return {};

    const sourceDetail = details.find((d) => d.id === activeId);
    if (!sourceDetail) return {};

    const result: Record<string, "valid" | "invalid"> = {};

    // For each empty cell, check if source teacher already occupies that slot in another class
    ENGLISH_DAYS.forEach((day) => {
      ALL_SLOTS.forEach((slot) => {
        const cellId = `cell-${day}-${slot}`;
        const existing = getCell(selectedClass, day, slot);

        if (existing) {
          // Cell has a lesson ΓÇö this will be a SWAP
          if (existing.id === activeId) return; // same cell
          if (existing.isFixed) {
            result[existing.id] = "invalid"; // can't swap with pinned
          } else {
            result[existing.id] = "valid"; // swappable
          }
        } else {
          // Empty cell ΓÇö check teacher conflict locally (simple heuristic)
          // If the teacher being dragged already teaches at this day+slot in another class of this timetable,
          // we mark it invalid. For now, we use local data ΓÇö the full check happens server-side on drop.
          if (sourceDetail.teacherId) {
            const teacherBusy = details.some(
              (d) =>
                d.id !== activeId &&
                d.teacherId === sourceDetail.teacherId &&
                d.dayOfWeek === day &&
                d.slotIndex === slot
            );
            result[cellId] = teacherBusy ? "invalid" : "valid";
          } else {
            result[cellId] = "valid";
          }
        }
      });
    });

    return result;
  }, [activeId, details, selectedClass]);

  // ΓöÇΓöÇΓöÇ DnD Handlers ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  function handleDragStart(event: DragStartEvent) {
    setActiveId(event.active.id as string);
  }

  function handleDragOver(_event: DragOverEvent) {
    // Keeping this for potential future UI high-level overrides
  }

  async function handleDragEnd(event: DragEndEvent) {
    setActiveId(null);
    const { active, over } = event;
    if (!over || active.id === over.id) return;

    const sourceDetail = details.find((d) => d.id === active.id);
    if (!sourceDetail) return;

    const droppedId = over.id as string;

    // Case 1: Dropped on another lesson card ΓåÆ SWAP
    const targetDetail = details.find((d) => d.id === droppedId);
    if (targetDetail) {
      if (targetDetail.isFixed) {
        toast.error(`Kh├┤ng thß╗â ho├ín ─æß╗òi: ${targetDetail.subjectName} ─æ├ú bß╗ï ghim cß╗æ ─æß╗ïnh.`);
        return;
      }
      await handleSwap(sourceDetail, targetDetail);
      return;
    }

    // Case 2: Dropped on empty cell ΓåÆ MOVE
    if (droppedId.startsWith("cell-")) {
      const parts = droppedId.split("-");
      const targetDay = parts[1];
      const targetSlot = parseInt(parts[2]);
      await handleMove(sourceDetail, targetDay, targetSlot);
    }
  }

  async function handleMove(source: TimetableDetail, targetDay: string, targetSlot: number) {
    const oldDay = source.dayOfWeek;
    const oldSlot = source.slotIndex;

    // Optimistic update
    setDetails((prev) =>
      prev.map((d) =>
        d.id === source.id ? { ...d, dayOfWeek: targetDay, slotIndex: targetSlot } : d
      )
    );

    try {
      setSaving(true);
      await api.put("/school-admin/timetables/adjust/move", {
        detailId: source.id,
        targetDay,
        targetSlot,
      });
      showSuccess(`Di chuyß╗ân ${source.subjectName} sang ${translateDay(targetDay)} tiß║┐t ${targetSlot}`);
    } catch (err: any) {
      // Revert
      setDetails((prev) =>
        prev.map((d) =>
          d.id === source.id ? { ...d, dayOfWeek: oldDay, slotIndex: oldSlot } : d
        )
      );
      const msg = err?.response?.data?.message || "Kh├┤ng thß╗â di chuyß╗ân tiß║┐t hß╗ìc";
      toast.error(msg);
    } finally {
      setSaving(false);
    }
  }

  async function handleSwap(source: TimetableDetail, target: TimetableDetail) {
    const srcDay = source.dayOfWeek, srcSlot = source.slotIndex;
    const tgtDay = target.dayOfWeek, tgtSlot = target.slotIndex;

    // Optimistic update
    setDetails((prev) =>
      prev.map((d) => {
        if (d.id === source.id) return { ...d, dayOfWeek: tgtDay, slotIndex: tgtSlot };
        if (d.id === target.id) return { ...d, dayOfWeek: srcDay, slotIndex: srcSlot };
        return d;
      })
    );

    try {
      setSaving(true);
      await api.put("/school-admin/timetables/adjust/swap", {
        sourceDetailId: source.id,
        targetDetailId: target.id,
      });
      showSuccess(`Ho├ín ─æß╗òi ${source.subjectName} vß╗¢i ${target.subjectName}`);
    } catch (err: any) {
      // Revert
      setDetails((prev) =>
        prev.map((d) => {
          if (d.id === source.id) return { ...d, dayOfWeek: srcDay, slotIndex: srcSlot };
          if (d.id === target.id) return { ...d, dayOfWeek: tgtDay, slotIndex: tgtSlot };
          return d;
        })
      );
      const msg = err?.response?.data?.message || "Kh├┤ng thß╗â ho├ín ─æß╗òi tiß║┐t hß╗ìc";
      toast.error(msg);
    } finally {
      setSaving(false);
    }
  }

  async function handleToggleLock(detailId: string) {
    // Optimistic toggle
    setDetails((prev) =>
      prev.map((d) => (d.id === detailId ? { ...d, isFixed: !d.isFixed } : d))
    );
    try {
      await api.patch(`/school-admin/timetables/adjust/${detailId}/toggle-lock`);
    } catch {
      // Revert
      setDetails((prev) =>
        prev.map((d) => (d.id === detailId ? { ...d, isFixed: !d.isFixed } : d))
      );
      toast.error("Kh├┤ng thß╗â thay ─æß╗òi trß║íng th├íi ghim");
    }
  }



  function translateDay(eng: string) {
    const idx = ENGLISH_DAYS.indexOf(eng);
    return idx >= 0 ? DAYS[idx] : eng;
  }

  // Active dragging lesson
  const activeDragDetail = activeId ? details.find((d) => d.id === activeId) : null;

  // ΓöÇΓöÇΓöÇ Render Slot Rows ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  function renderSlotRows(slots: number[]) {
    return slots.map((slot) => (
      <tr
        key={`slot-${slot}`}
        className={`border-b border-gray-100 transition-colors
          ${slot === 5 ? "border-b-2 border-gray-200" : ""}
