import { useSemester } from "../../../context/SemesterContext";
import SemesterSelector from "../../../components/common/SemesterSelector";
import { NoAcademicYearState } from "../../../components/common/EmptyState";

// Modal Component for Creating Timetable
interface CreateModalProps {
    isOpen: boolean;
    onClose: () => void;
    onSuccess: () => void;
}

function CreateTimetableModal({ isOpen, onClose, onSuccess }: CreateModalProps) {
    const { activeSemester, allSemesters } = useSemester();
    const [name, setName] = useState("");
    const [semesterId, setSemesterId] = useState<string>("");
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState<string | null>(null);

    // Auto-fill default semester info
    useEffect(() => {
        if (isOpen) {
            if (activeSemester) {
                setSemesterId(activeSemester.id);
            } else if (allSemesters.length > 0) {
                setSemesterId(allSemesters[0].id);
            }
            setName("");
            setError(null);
        }
    }, [isOpen, activeSemester, allSemesters]);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!semesterId) {
            setError("Vui l├▓ng chß╗ìn hß╗ìc kß╗│.");
            return;
        }
        setLoading(true);
        setError(null);

        try {
            await api.post("/school-admin/timetables", {
                name,
                semesterId
            });
            onSuccess();
            onClose();
        } catch (err) {
            setError("C├│ lß╗ùi xß║úy ra khi tß║ío thß╗¥i kh├│a biß╗âu. Vui l├▓ng thß╗¡ lß║íi.");
        } finally {
            setLoading(false);
        }
    };

    if (!isOpen) return null;

    return createPortal(
        <div className="fixed inset-0 z-[100] flex items-center justify-center">
            <div className="absolute inset-0 bg-black/60 backdrop-blur-sm" onClick={onClose} />
            <div className="relative bg-white rounded-2xl shadow-xl w-full max-w-md mx-4 overflow-hidden max-h-[90vh] flex flex-col z-[100]">
                <div className="bg-gradient-to-r from-blue-600 to-blue-500 px-6 py-4 flex-none z-[110]">
                    <div className="flex items-center justify-between">
                        <h2 className="text-xl font-semibold text-white">Tß║ío Thß╗¥i Kh├│a Biß╗âu Mß╗¢i</h2>
                        <button onClick={onClose} className="text-white/80 hover:text-white transition-colors">
                            <X size={24} />
                        </button>
                    </div>
                </div>
                <form onSubmit={handleSubmit} className="p-6 space-y-4 overflow-y-auto">
                    {error && (
                        <div className="bg-red-50 border border-red-200 text-red-700 px-4 py-3 rounded-xl text-sm flex items-center gap-2">
                            <AlertCircle size={16} />
                            <span>{error}</span>
                        </div>
                    )}

                    <div>
                        <label className="block text-sm font-medium text-gray-700 mb-1">T├¬n TKB *</label>
                        <input
                            type="text"
                            required
                            placeholder="VD: TKB HK1 N─âm hß╗ìc 2025-2026"
                            value={name}
                            onChange={(e) => setName(e.target.value)}
                            className="w-full px-3 py-2 border border-gray-200 rounded-xl focus:border-blue-500 outline-none text-gray-800"
                        />
                    </div>

                    <div>
                        <label className="block text-sm font-medium text-gray-700 mb-1">Hß╗ìc kß╗│ & N─âm hß╗ìc *</label>
                        <select
                            value={semesterId}
                            onChange={(e) => setSemesterId(e.target.value)}
                            className="w-full px-3 py-2 border border-gray-200 rounded-xl focus:border-blue-500 outline-none text-gray-800 bg-white"
                        >
                            <option value="">-- Chß╗ìn hß╗ìc kß╗│ --</option>
                            {allSemesters.map(s => (
                                <option key={s.id} value={s.id}>
                                    Hß╗ìc kß╗│ {s.semesterNumber} ({s.academicYearName})
                                </option>
                            ))}
                        </select>
                    </div>

                    <div className="pt-4 flex gap-3">
                        <button type="button" onClick={onClose} className="flex-1 px-4 py-3 rounded-xl border border-gray-200 text-gray-700 font-medium hover:bg-gray-50 transition-colors">
                            Hß╗ºy bß╗Å
                        </button>
                        <button
                            type="submit"
                            disabled={loading}
                            className="flex-1 px-4 py-3 rounded-xl bg-blue-600 text-white font-medium hover:bg-blue-700 disabled:opacity-50 transition-colors"
                        >
                            {loading ? <Loader2 className="animate-spin mx-auto" /> : "Tß║ío mß╗¢i"}
                        </button>
                    </div>
                </form>
            </div>
        </div>,
        document.body
    );
}

export default function TimetableManagement() {
    const [timetables, setTimetables] = useState<Timetable[]>([]);
    const navigate = useNavigate();
    const [loading, setLoading] = useState(false);
    const [generating, setGenerating] = useState<string | null>(null);
    const [error, setError] = useState<string | null>(null);

    // Global Hooks
    const { showSuccess } = useToast();
    const { confirm, ConfirmationDialog } = useConfirmation();

    // Create Modal state
    const [isCreateModalOpen, setIsCreateModalOpen] = useState(false);

    const { activeSemester, allSemesters, loading: isContextLoading } = useSemester();
    const [selectedSemesterId, setSelectedSemesterId] = useState<string>("");

    // Initial load priority: System Active Semester
    useEffect(() => {
        if (!selectedSemesterId && activeSemester) {
            setSelectedSemesterId(activeSemester.id);
        }
    }, [activeSemester, selectedSemesterId]);

    const fetchTimetables = async () => {
        if (!selectedSemesterId) return;
        setLoading(true);
        setError(null);
        try {
            const data = await api.get("/school-admin/timetables", {
                params: { semesterId: selectedSemesterId }
            }).then(res => res.data);
            setTimetables(data);
        } catch (error) {
            setError("Kh├┤ng thß╗â tß║úi danh s├ích thß╗¥i kh├│a biß╗âu");
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        if (!isContextLoading) {
            if (selectedSemesterId) {
                fetchTimetables();
            } else {
                setLoading(false);
            }
        }
    }, [selectedSemesterId, isContextLoading]);

    const handleGenerateClick = (timetable: Timetable) => {
        confirm({
            title: "Chß║íy Xß║┐p Lß╗ïch Tß╗▒ ─Éß╗Öng?",
            message: (
                <span>
                    Hß╗ç thß╗æng sß║╜ tß╗▒ ─æß╗Öng sß║»p xß║┐p thß╗¥i kh├│a biß╗âu cho <strong>{timetable.name}</strong> dß╗▒a tr├¬n dß╗» liß╗çu hiß╗çn tß║íi.<br />
                    <span className="text-xs text-gray-500 mt-2 block">Qu├í tr├¼nh n├áy c├│ thß╗â mß║Ñt v├ái ph├║t.</span>
                </span>
            ),
            confirmText: "X├íc nhß║¡n",
            onConfirm: async () => {
                setGenerating(timetable.id);
                setError(null);
                try {
                    await api.post(`/school-admin/timetables/${timetable.id}/generate`);
                    showSuccess(`─É├ú xß║┐p lß╗ïch th├ánh c├┤ng cho: ${timetable.name}`);
                    fetchTimetables();
                } catch (error) {
                    setError(`Lß╗ùi khi xß║┐p TKB: ${timetable.name}. Vui l├▓ng thß╗¡ lß║íi.`);
                } finally {
                    setGenerating(null);
                }
            }
        });
    };

    const confirmDelete = (timetable: Timetable) => {
        confirm({
            title: "X├│a thß╗¥i kh├│a biß╗âu?",
            message: <span>Bß║ín c├│ chß║»c chß║»n muß╗æn x├│a <strong>{timetable.name}</strong>? H├ánh ─æß╗Öng n├áy kh├┤ng thß╗â ho├án t├íc.</span>,
            variant: "danger",
            confirmText: "X├│a",
            onConfirm: async () => {
                setLoading(true);
                try {
                    await api.delete(`/school-admin/timetables/${timetable.id}`);
                    showSuccess(`─É├ú x├│a: ${timetable.name}`);
                    fetchTimetables();
                } catch (error) {
                    setError("Lß╗ùi khi x├│a thß╗¥i kh├│a biß╗âu.");
                } finally {
                    setLoading(false);
                }
            }
        });
    };

    const openApplyModal = (timetable: Timetable) => {
        confirm({
            title: "├üp dß╗Ñng thß╗¥i kh├│a biß╗âu?",
            message: (
                <span>
                    Bß║ín c├│ muß╗æn ├íp dß╗Ñng <strong>{timetable.name}</strong> cho to├án tr╞░ß╗¥ng kh├┤ng?<br />
                    <span className="text-sm text-gray-500 mt-2 block">Trß║íng th├íi sß║╜ chuyß╗ân th├ánh <strong>OFFICIAL</strong> v├á c├íc TKB kh├íc sß║╜ bß╗ï hß╗ºy k├¡ch hoß║ít.</span>
                </span>
            ),
            variant: "success",
            confirmText: "X├íc nhß║¡n",
            onConfirm: async () => {
                setLoading(true);
                try {
                    await api.post(`/school-admin/timetables/${timetable.id}/apply`);
                    showSuccess(`─É├ú ├íp dß╗Ñng TKB: ${timetable.name}`);
                    fetchTimetables();
                } catch (error) {
                    setError("Lß╗ùi khi ├íp dß╗Ñng thß╗¥i kh├│a biß╗âu.");
                } finally {
                    setLoading(false);
                }
            }
        });
    };

    return (
        <div className="space-y-6">
            <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
                <div>
                    <h1 className="text-2xl font-bold text-gray-900">Quß║ún l├╜ Thß╗¥i Kh├│a Biß╗âu</h1>
                    <p className="text-sm text-gray-500 mt-1">Danh s├ích c├íc phi├¬n bß║ún thß╗¥i kh├│a biß╗âu</p>
                </div>
                <div className="flex flex-col sm:flex-row sm:items-center gap-4">
                    <SemesterSelector
                        value={selectedSemesterId}
                        onChange={setSelectedSemesterId}
                        label=""
                        className="h-[42px]"
                    />
                    <button onClick={() => setIsCreateModalOpen(true)}
                        disabled={allSemesters.length === 0}
                        className="flex items-center gap-2 px-4 py-2 bg-gradient-to-r from-blue-600 to-blue-500 text-white rounded-lg text-sm font-medium hover:shadow-lg transition-all disabled:opacity-50"
                    >
                        <Plus size={20} />
                        Tß║ío TKB Mß╗¢i
                    </button>
                </div>
            </div>

            {allSemesters.length === 0 && !isContextLoading ? (
                <div className="bg-white rounded-xl border border-gray-200 p-6">
                    <NoAcademicYearState onAction={() => navigate("/school-admin/semesters")} />
                </div>
            ) : (
                <>
                    {/* Error Alerts (Keep error as banner, logical for persistent issues) */}
                    {error && (
                        <div className="bg-red-50 border border-red-200 text-red-700 px-4 py-3 rounded-xl flex items-center gap-2 animate-in fade-in slide-in-from-top-2">
                            <AlertCircle size={20} />
                            <span>{error}</span>
                        </div>
                    )}

                    <div className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden">
                        <table className="w-full">
                            <thead className="bg-gray-50 border-b border-gray-200">
                                <tr>
                                    <th className="px-6 py-4 text-left text-xs font-semibold text-gray-500 uppercase tracking-wider">T├¬n TKB</th>
                                    <th className="px-6 py-4 text-left text-xs font-semibold text-gray-500 uppercase tracking-wider">N─âm hß╗ìc</th>
                                    <th className="px-6 py-4 text-left text-xs font-semibold text-gray-500 uppercase tracking-wider">Hß╗ìc kß╗│</th>
                                    <th className="px-6 py-4 text-left text-xs font-semibold text-gray-500 uppercase tracking-wider">Trß║íng th├íi</th>
                                    <th className="px-6 py-4 text-left text-xs font-semibold text-gray-500 uppercase tracking-wider">Ng├áy tß║ío</th>
                                    <th className="px-6 py-4 text-right text-xs font-semibold text-gray-500 uppercase tracking-wider">Thao t├íc</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-gray-200">
                                {loading ? (
                                    <tr>
                                        <td colSpan={6} className="px-6 py-8 text-center text-gray-500">─Éang tß║úi...</td>
                                    </tr>
                                ) : !Array.isArray(timetables) || timetables.length === 0 ? (
                                    <tr>
                                        <td colSpan={6} className="px-6 py-8 text-center text-gray-500">Ch╞░a c├│ thß╗¥i kh├│a biß╗âu n├áo</td>
                                    </tr>
                                ) : (
                                    timetables.map((t) => (
                                        <tr key={t.id} className="hover:bg-blue-50 transition-colors">
                                            <td className="px-6 py-4">
                                                <div className="flex items-center gap-3">
                                                    <div className="w-8 h-8 rounded-lg bg-blue-50 flex items-center justify-center text-blue-600">
                                                        <Calendar size={18} />
                                                    </div>
                                                    <span className="font-semibold text-gray-900">{t.name}</span>
                                                </div>
                                            </td>
                                            <td className="px-6 py-4 text-gray-600 font-medium">{t.academicYear}</td>
                                            <td className="px-6 py-4 text-gray-600">{t.semester}</td>
                                            <td className="px-6 py-4">
                                                <span className={`px-2.5 py-0.5 rounded-full text-xs font-medium ${t.status === 'OFFICIAL' ? 'bg-green-100 text-green-700' : 'bg-gray-100 text-gray-600'
                                                    }`}>
                                                    {t.status === 'OFFICIAL' ? '─Éang ├íp dß╗Ñng' : 'Bß║ún nh├íp'}
                                                </span>
                                            </td>
                                            <td className="px-6 py-4 text-gray-500 text-sm">
                                                {formatDate(t.createdAt)}
                                            </td>
                                            <td className="px-6 py-4 text-right">
                                                <div className="flex items-center justify-end gap-2">
                                                    {t.status !== 'OFFICIAL' && (
                                                        <button
                                                            onClick={() => openApplyModal(t)}
                                                            className="p-1.5 text-gray-400 hover:text-green-600 hover:bg-green-50 rounded-lg transition-colors group"
                                                            title="├üp dß╗Ñng cho to├án tr╞░ß╗¥ng"
                                                        >
                                                            <CheckCircle2 size={18} className="group-hover:stroke-[2.5px]" />
                                                        </button>
                                                    )}

                                                    <button
                                                        onClick={() => handleGenerateClick(t)}
                                                        disabled={generating === t.id}
                                                        className="flex items-center gap-1.5 px-3 py-1.5 text-xs font-medium text-white bg-indigo-600 hover:bg-indigo-700 rounded-lg transition-colors disabled:opacity-50 shadow-sm"
                                                        title="Chß║íy thuß║¡t to├ín xß║┐p tß╗▒ ─æß╗Öng"
                                                    >
                                                        {generating === t.id ? <Loader2 size={14} className="animate-spin" /> : <Play size={14} />}
                                                        Auto Xß║┐p
                                                    </button>

                                                    <button
                                                        onClick={() => navigate(`/school-admin/schedule/${t.id}`)}
                                                        className="flex items-center gap-1.5 px-3 py-1.5 text-xs font-medium text-gray-700 bg-white border border-gray-200 hover:bg-gray-50 rounded-lg transition-colors"
                                                    >
                                                        <Eye size={14} />
                                                    </button>

                                                    <button
                                                        onClick={() => confirmDelete(t)}
                                                        className="p-1.5 text-red-500 hover:bg-red-50 rounded-lg transition-colors"
                                                        title="X├│a thß╗¥i kh├│a biß╗âu"
                                                    >
                                                        <Trash2 size={18} />
                                                    </button>
                                                </div>
                                            </td>
                                        </tr>
                                    ))
                                )}
                            </tbody>
                        </table>
                    </div>

                    {/* Create Modal */}
                    <CreateTimetableModal
                        isOpen={isCreateModalOpen}
                        onClose={() => setIsCreateModalOpen(false)}
                        onSuccess={() => {
                            fetchTimetables();
                            showSuccess("Tß║ío thß╗¥i kh├│a biß╗âu mß╗¢i th├ánh c├┤ng!");
                        }}
                    />

                    {/* Confirmation Dialog */}
                    <ConfirmationDialog />
                </>
            )}
        </div>
    );
}

import React, { useState } from "react";
import { User, Shield, Bell, Lock, Camera } from "lucide-react";
import { useAuth } from "../../../context/AuthContext";
import { authService } from "../../../services/authService";
import { toast } from "react-hot-toast";

type TabType = "profile" | "security" | "notifications" | "privacy";

export default function ProfileSettingsPage() {
  const { user } = useAuth();
  const [activeTab, setActiveTab] = useState<TabType>("profile");
  const [isSubmitting, setIsSubmitting] = useState(false);

  // Profile Form State
  const [profileData, setProfileData] = useState({
    fullName: user?.fullName || "",
    phone: user?.phone || "",
    dateOfBirth: user?.dateOfBirth || "",
    address: user?.address || "",
    bio: user?.bio || "",
  });

  // Password Form State
  const [passwordData, setPasswordData] = useState({
    currentPassword: "",
    newPassword: "",
    confirmPassword: "",
  });

  const handleProfileSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      setIsSubmitting(true);
      await authService.updateProfile(profileData);
      // We need to update context but useAuth doesn't expose a clean setter, maybe reload or login again
      // The easiest way is forcing a reload or using `me()` to update state if Context supports it.
      // Usually, it's fine. For now let's just show success
      toast.success("Cß║¡p nhß║¡t hß╗ô s╞í th├ánh c├┤ng!");
      window.location.reload(); // Simple state sync
    } catch (error: any) {
      toast.error(error.response?.data?.message || "Lß╗ùi khi cß║¡p nhß║¡t hß╗ô s╞í");
    } finally {
      setIsSubmitting(false);
    }
  };

  const handlePasswordSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (passwordData.newPassword !== passwordData.confirmPassword) {
      toast.error("Mß║¡t khß║⌐u x├íc nhß║¡n kh├┤ng khß╗¢p!");
      return;
    }
    try {
      setIsSubmitting(true);
      await authService.changePassword(passwordData.currentPassword, passwordData.newPassword);
      toast.success("─Éß╗òi mß║¡t khß║⌐u th├ánh c├┤ng!");
      setPasswordData({ currentPassword: "", newPassword: "", confirmPassword: "" });
    } catch (error: any) {
      toast.error(error.response?.data?.message || "Lß╗ùi khi ─æß╗òi mß║¡t khß║⌐u");
    } finally {
      setIsSubmitting(false);
    }
  };

  const tabs: { id: TabType; label: string; icon: React.ReactNode }[] = [
    { id: "profile", label: "Hß╗ô s╞í", icon: <User className="w-4 h-4 mr-2" /> },
    { id: "security", label: "Bß║úo mß║¡t", icon: <Shield className="w-4 h-4 mr-2" /> },
    { id: "notifications", label: "Th├┤ng b├ío", icon: <Bell className="w-4 h-4 mr-2" /> },
    { id: "privacy", label: "Ri├¬ng t╞░", icon: <Lock className="w-4 h-4 mr-2" /> },
  ];

  const handleLogoutOtherDevices = async () => {
    try {
      if (!window.confirm("Bß║ín c├│ chß║»c chß║»n muß╗æn ─æ─âng xuß║Ñt khß╗Åi tß║Ñt cß║ú c├íc thiß║┐t bß╗ï kh├íc kh├┤ng?")) return;
      setIsSubmitting(true);
      await authService.logoutOtherDevices();
      toast.success("─É├ú ─æ─âng xuß║Ñt khß╗Åi c├íc thiß║┐t bß╗ï kh├íc.");
    } catch (error: any) {
      toast.error(error.response?.data?.message || "Lß╗ùi khi ─æ─âng xuß║Ñt");
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="max-w-6xl mx-auto p-6 animate-fade-in space-y-6">
      <div className="flex items-center justify-between">
        <h1 className="text-2xl font-bold text-gray-800 dark:text-white">C├ái ─æß║╖t</h1>
        <p className="text-sm text-gray-500">Quß║ún l├╜ t├ái khoß║ún v├á t├╣y chß╗ìn cß╗ºa bß║ín</p>
      </div>

      <div className="flex flex-col md:flex-row gap-6">
        {/* Sidebar Tabs */}
        <div className="w-full md:w-64 flex-shrink-0">
          <nav className="flex flex-col space-y-1">
            {tabs.map((tab) => (
              <button
                key={tab.id}
                onClick={() => setActiveTab(tab.id)}
                className={`flex items-center px-4 py-3 text-sm font-medium rounded-lg transition-colors ${activeTab === tab.id
                    ? "bg-blue-50 text-blue-700 dark:bg-blue-900/30 dark:text-blue-400"
