import { useEffect, useState } from "react";
import { systemService, type ActivityLogDto } from "../../services/systemService";

export default function ActivityLogsPage() {
  const [logs, setLogs] = useState<ActivityLogDto[]>([]);
  const [page, setPage] = useState(0);
  const [totalPages, setTotalPages] = useState(0);
  const [loading, setLoading] = useState(true);

  const loadData = async () => {
    setLoading(true);
    try {
      const data = await systemService.listActivityLogs(page, 20);
      setLogs(data.content);
      setTotalPages(data.totalPages);
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadData();
  }, [page]);

  const getActionLabel = (action: string) => {
    const labels: Record<string, string> = {
      USER_CREATED: "Tß║ío t├ái khoß║ún",
      USER_ENABLED: "K├¡ch hoß║ít t├ái khoß║ún",
      USER_DISABLED: "V├┤ hiß╗çu ho├í t├ái khoß║ún",
      USER_PENDING_DELETE: "─É├ính dß║Ñu x├│a",
      USER_RESTORED: "Kh├┤i phß╗Ñc t├ái khoß║ún",
      USER_PERMANENT_DELETED: "X├│a v─⌐nh viß╗àn",
      USER_AUTO_DELETED: "Tß╗▒ ─æß╗Öng x├│a (14 ng├áy)",
      USER_PASSWORD_RESET: "Reset mß║¡t khß║⌐u",
      SCHOOL_CREATED: "Tß║ío tr╞░ß╗¥ng",
      SCHOOL_UPDATED: "Cß║¡p nhß║¡t tr╞░ß╗¥ng",
      NOTIFICATION_CREATED: "Tß║ío th├┤ng b├ío",
      NOTIFICATION_DELETED: "X├│a th├┤ng b├ío",
      LOGIN_SUCCESS: "─É─âng nhß║¡p",
    };
    return labels[action] || action;
  };

  const getActionColor = (action: string) => {
    if (action.includes("DELETE")) return "bg-rose-100 text-rose-700";
    if (action.includes("CREATED")) return "bg-emerald-100 text-emerald-700";
    if (action.includes("ENABLED") || action.includes("RESTORED")) return "bg-blue-100 text-blue-700";
    if (action.includes("DISABLED")) return "bg-amber-100 text-amber-700";
    return "bg-slate-100 text-slate-700";
  };

  return (
    <div className="max-w-6xl mx-auto">
      <div className="mb-6">
        <h1 className="text-2xl font-bold text-gray-900">B├ío c├ío hoß║ít ─æß╗Öng</h1>
        <p className="text-sm text-gray-500 mt-1">Lß╗ïch sß╗¡ c├íc thao t├íc trong hß╗ç thß╗æng</p>
      </div>

      <div className="bg-white rounded-2xl border border-slate-200 overflow-hidden">
        {loading ? (
          <div className="p-8 text-center text-slate-500">─Éang tß║úi...</div>
        ) : logs.length === 0 ? (
          <div className="p-8 text-center text-slate-500">Ch╞░a c├│ hoß║ít ─æß╗Öng n├áo</div>
        ) : (
          <>
            <table className="w-full">
              <thead className="bg-slate-50 border-b border-slate-200">
                <tr>
                  <th className="text-left px-4 py-3 text-sm font-medium text-slate-600">Thß╗¥i gian</th>
                  <th className="text-left px-4 py-3 text-sm font-medium text-slate-600">H├ánh ─æß╗Öng</th>
                  <th className="text-left px-4 py-3 text-sm font-medium text-slate-600">Ng╞░ß╗¥i thß╗▒c hiß╗çn</th>
                  <th className="text-left px-4 py-3 text-sm font-medium text-slate-600">Chi tiß║┐t</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                {logs.map((log) => (
                  <tr key={log.id} className="hover:bg-slate-50">
                    <td className="px-4 py-3 text-sm text-slate-600">
                      {new Date(log.createdAt).toLocaleString("vi-VN")}
                    </td>
                    <td className="px-4 py-3">
                      <span className={`inline-flex px-2 py-1 text-xs font-medium rounded-lg ${getActionColor(log.action)}`}>
                        {getActionLabel(log.action)}
                      </span>
                    </td>
                    <td className="px-4 py-3 text-sm text-slate-600">
                      {log.performedByEmail || "Hß╗ç thß╗æng"}
                    </td>
                    <td className="px-4 py-3 text-sm text-slate-500 max-w-xs truncate">
                      {log.details || "-"}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>

            {/* Pagination */}
            {totalPages > 1 && (
              <div className="flex items-center justify-between px-4 py-3 border-t border-slate-100">
                <button
                  onClick={() => setPage(Math.max(0, page - 1))}
                  disabled={page === 0}
                  className="px-3 py-1.5 text-sm bg-slate-100 rounded-lg disabled:opacity-50"
                >
                  ΓåÉ Tr╞░ß╗¢c
                </button>
                <span className="text-sm text-slate-600">
                  Trang {page + 1} / {totalPages}
                </span>
                <button
                  onClick={() => setPage(Math.min(totalPages - 1, page + 1))}
                  disabled={page >= totalPages - 1}
                  className="px-3 py-1.5 text-sm bg-slate-100 rounded-lg disabled:opacity-50"
                >
                  Sau ΓåÆ
                </button>
              </div>
            )}
          </>
        )}
      </div>
    </div>
  );
}

