import { useEffect, useState } from "react";
import { Link } from "react-router-dom";
import { systemService, type UserListDto, type SchoolDto } from "../../services/systemService";
import { extractErrorMessage } from "../../utils/errorUtils";
import {
  UsersIcon,
  FilterIcon,
  TrashIcon,
  CheckCircleIcon,
  XCircleIcon,
  BanIcon,
  ShieldIcon,
  SchoolIcon,
  ClockIcon,
} from "../../components/layout/SystemIcons";
import Pagination from "../../components/common/Pagination";

export default function SystemUsersPage() {
  const [users, setUsers] = useState<UserListDto[]>([]);
  const [schools, setSchools] = useState<SchoolDto[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [success, setSuccess] = useState<string | null>(null);

  // Filters
  const [roleFilter, setRoleFilter] = useState<string>("");
  const [schoolFilter, setSchoolFilter] = useState<string>("");
  const [enabledFilter, setEnabledFilter] = useState<string>("");

  const [currentPage, setCurrentPage] = useState(0);
  const [pageSize, setPageSize] = useState(50);
  const [totalItems, setTotalItems] = useState(0);

  const loadData = async () => {
    try {
      setLoading(true);
      const [usersData, schoolsData] = await Promise.all([
        systemService.listUsers({
          role: roleFilter || undefined,
          schoolId: schoolFilter || undefined,
          enabled: enabledFilter === "" ? undefined : enabledFilter === "true",
          pendingDelete: false,
          page: currentPage,
          size: pageSize,
        }),
        systemService.listSchools(0, 1000), // Get all schools for filter
      ]);
      setUsers(usersData.content);
      setTotalItems(usersData.totalElements);
      setSchools(schoolsData.content);
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadData();
  }, [roleFilter, schoolFilter, enabledFilter, currentPage, pageSize]);

  // Reset page when filters change
  useEffect(() => {
    setCurrentPage(0);
  }, [roleFilter, schoolFilter, enabledFilter]);

  const handleEnable = async (id: string) => {
    setError(null);
    setSuccess(null);
    try {
      await systemService.enableUser(id);
      setSuccess("─É├ú k├¡ch hoß║ít t├ái khoß║ún");
      loadData();
    } catch (e: unknown) {
      setError(extractErrorMessage(e, "Lß╗ùi khi k├¡ch hoß║ít"));
    }
  };

  const handleDisable = async (id: string) => {
    setError(null);
    setSuccess(null);
    try {
      await systemService.disableUser(id);
      setSuccess("─É├ú v├┤ hiß╗çu ho├í t├ái khoß║ún");
      loadData();
    } catch (e: unknown) {
      setError(extractErrorMessage(e, "Lß╗ùi khi v├┤ hiß╗çu ho├í"));
    }
  };

  const handleDelete = async (id: string) => {
    if (
