                                        placeholder="Ghi ch├║..."
                                    />
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>
        </div>
    );
}

import { useState, useEffect, useCallback } from "react";
import { format, startOfWeek, endOfWeek, startOfMonth, endOfMonth } from "date-fns";
import { attendanceService } from "../../../../services/attendanceService";
import type { AttendanceReportSummaryDto } from "../../../../services/attendanceService";
import { vietnameseNameSort } from "../../../../utils/sortUtils";
import AttendanceDetailModal from "./AttendanceDetailModal";

type Props = {
    date: Date;
    reportType: "WEEKLY" | "MONTHLY";
};

type ModalInfo = {
    studentId: string;
    studentName: string;
    statusFilter?: string;
    statusLabel: string;
} | null;

export default function AttendanceReportView({ date, reportType }: Props) {
    const [report, setReport] = useState<AttendanceReportSummaryDto | null>(null);
    const [loading, setLoading] = useState(true);
    const [sortField, setSortField] = useState<string>("studentName");
    const [sortAsc, setSortAsc] = useState(true);
    const [modalInfo, setModalInfo] = useState<ModalInfo>(null);

    const getDateRange = useCallback(() => {
        if (reportType === "WEEKLY") {
            const start = startOfWeek(date, { weekStartsOn: 1 });
            const end = endOfWeek(date, { weekStartsOn: 1 });
            return { start, end };
        } else {
            const start = startOfMonth(date);
            const end = endOfMonth(date);
            return { start, end };
        }
    }, [date, reportType]);

    const loadData = useCallback(async () => {
        try {
            setLoading(true);
            const { start, end } = getDateRange();
            const startStr = format(start, "yyyy-MM-dd");
            const endStr = format(end, "yyyy-MM-dd");
            const data = await attendanceService.getAttendanceReport(startStr, endStr, reportType);
            setReport(data);
        } catch (error) {
            console.error("Failed to load attendance report:", error);
        } finally {
            setLoading(false);
        }
    }, [date, reportType, getDateRange]);

    useEffect(() => {
        loadData();
    }, [loadData]);

    const handleSort = (field: string) => {
        if (sortField === field) {
            setSortAsc(!sortAsc);
        } else {
            setSortField(field);
            setSortAsc(true);
        }
    };

    const handleCellClick = (studentId: string, studentName: string, count: number, statusFilter: string | undefined, statusLabel: string) => {
        if (count === 0) return; // Don't open modal for 0 values
        setModalInfo({ studentId, studentName, statusFilter, statusLabel });
    };

    const sortedStudents = report?.students
        ? [...report.students].sort((a, b) => {
            let valA: string | number, valB: string | number;
            switch (sortField) {
                case "studentName": valA = a.studentName; valB = b.studentName; break;
                case "totalPresent": valA = a.totalPresent; valB = b.totalPresent; break;
                case "totalAbsentExcused": valA = a.totalAbsentExcused; valB = b.totalAbsentExcused; break;
                case "totalAbsentUnexcused": valA = a.totalAbsentUnexcused; valB = b.totalAbsentUnexcused; break;
                case "totalLate": valA = a.totalLate; valB = b.totalLate; break;
                case "attendanceRate": valA = a.attendanceRate; valB = b.attendanceRate; break;
                default: valA = a.studentName; valB = b.studentName;
            }
            if (typeof valA === "string") {
                if (sortField === "studentName") {
                    return sortAsc ? vietnameseNameSort(valA, valB as string) : vietnameseNameSort(valB as string, valA);
                }
                return sortAsc ? valA.localeCompare(valB as string) : (valB as string).localeCompare(valA);
            }
            return sortAsc ? (valA as number) - (valB as number) : (valB as number) - (valA as number);
        })
        : [];

    const { start, end } = getDateRange();
    const startDateStr = format(start, "yyyy-MM-dd");
    const endDateStr = format(end, "yyyy-MM-dd");
    const periodLabel = reportType === "WEEKLY"
        ? `Tuß║ºn ${format(start, "dd/MM")} - ${format(end, "dd/MM/yyyy")}`
        : `Th├íng ${format(date, "MM/yyyy")}`;

    const getAttendanceRateColor = (rate: number) => {
        if (rate >= 90) return "text-green-600";
        if (rate >= 75) return "text-yellow-600";
        return "text-red-600";
    };

    const getAttendanceRateBg = (rate: number) => {
        if (rate >= 90) return "bg-green-50";
        if (rate >= 75) return "bg-yellow-50";
        return "bg-red-50";
    };

    if (loading) return <div className="p-8 text-center">─Éang tß║úi b├ío c├ío...</div>;
    if (!report) return <div className="p-8 text-center text-gray-500">Kh├┤ng c├│ dß╗» liß╗çu</div>;

    return (
        <>
            <div className="bg-white rounded-xl shadow-sm border border-gray-200 flex flex-col h-full">
                {/* Header */}
                <div className="p-6 border-b border-gray-200">
                    <div className="flex justify-between items-start">
                        <div>
                            <h2 className="text-xl font-bold text-gray-800">
                                B├ío c├ío ─æiß╗âm danh - {report.classroomName}
                            </h2>
                            <p className="text-gray-500 mt-1">{periodLabel}</p>
                        </div>
                    </div>

                    {/* Stats Cards */}
                    <div className="grid grid-cols-1 sm:grid-cols-3 gap-4 mt-4">
                        <div className="bg-blue-50 rounded-xl p-4 border border-blue-100">
                            <div className="text-sm text-blue-600 font-medium">Tß╗òng hß╗ìc sinh</div>
                            <div className="text-2xl font-bold text-blue-800 mt-1">{report.totalStudents}</div>
                        </div>
                        <div className="bg-purple-50 rounded-xl p-4 border border-purple-100">
                            <div className="text-sm text-purple-600 font-medium">Sß╗æ ng├áy hß╗ìc</div>
                            <div className="text-2xl font-bold text-purple-800 mt-1">{report.totalSchoolDays}</div>
                        </div>
                        <div className={`rounded-xl p-4 border ${report.overallAttendanceRate >= 90 ? 'bg-green-50 border-green-100' : report.overallAttendanceRate >= 75 ? 'bg-yellow-50 border-yellow-100' : 'bg-red-50 border-red-100'}`}>
                            <div className={`text-sm font-medium ${getAttendanceRateColor(report.overallAttendanceRate)}`}>Tß╗╖ lß╗ç chuy├¬n cß║ºn</div>
                            <div className={`text-2xl font-bold mt-1 ${getAttendanceRateColor(report.overallAttendanceRate)}`}>{report.overallAttendanceRate}%</div>
                        </div>
                    </div>
                </div>

                {/* Table */}
                <div className="flex-1 overflow-auto p-0">
                    <table className="w-full border-collapse">
                        <thead className="bg-gray-50 sticky top-0 z-10">
                            <tr>
                                <th className="px-4 py-3 text-left text-xs font-semibold text-gray-500 uppercase border-b border-r border-gray-200 bg-gray-50 sticky left-0 z-20 cursor-pointer hover:bg-gray-100"
                                    onClick={() => handleSort("studentName")}>
                                    Hß╗ìc sinh {sortField === "studentName" && (sortAsc ? "Γåæ" : "Γåô")}
                                </th>
                                <th className="px-3 py-3 text-center text-xs font-semibold text-gray-500 uppercase border-b border-gray-200 cursor-pointer hover:bg-gray-100"
                                    onClick={() => handleSort("totalPresent")}>
                                    <span className="flex flex-col items-center">
                                        <span className="w-3 h-3 rounded-full bg-green-500 mb-1"></span>
                                        C├│ mß║╖t {sortField === "totalPresent" && (sortAsc ? "Γåæ" : "Γåô")}
                                    </span>
                                </th>
                                <th className="px-3 py-3 text-center text-xs font-semibold text-gray-500 uppercase border-b border-gray-200 cursor-pointer hover:bg-gray-100"
                                    onClick={() => handleSort("totalAbsentExcused")}>
                                    <span className="flex flex-col items-center">
                                        <span className="w-3 h-3 rounded-full bg-yellow-500 mb-1"></span>
                                        Vß║»ng P {sortField === "totalAbsentExcused" && (sortAsc ? "Γåæ" : "Γåô")}
                                    </span>
                                </th>
                                <th className="px-3 py-3 text-center text-xs font-semibold text-gray-500 uppercase border-b border-gray-200 cursor-pointer hover:bg-gray-100"
                                    onClick={() => handleSort("totalAbsentUnexcused")}>
                                    <span className="flex flex-col items-center">
                                        <span className="w-3 h-3 rounded-full bg-red-500 mb-1"></span>
                                        Vß║»ng KP {sortField === "totalAbsentUnexcused" && (sortAsc ? "Γåæ" : "Γåô")}
                                    </span>
                                </th>
                                <th className="px-3 py-3 text-center text-xs font-semibold text-gray-500 uppercase border-b border-gray-200 cursor-pointer hover:bg-gray-100"
                                    onClick={() => handleSort("totalLate")}>
                                    <span className="flex flex-col items-center">
                                        <span className="w-3 h-3 rounded-full bg-orange-500 mb-1"></span>
                                        Muß╗Ön {sortField === "totalLate" && (sortAsc ? "Γåæ" : "Γåô")}
                                    </span>
                                </th>
                                <th className="px-3 py-3 text-center text-xs font-semibold text-gray-500 uppercase border-b border-gray-200">
                                    Tß╗òng tiß║┐t
                                </th>
                                <th className="px-3 py-3 text-center text-xs font-semibold text-gray-500 uppercase border-b border-gray-200 cursor-pointer hover:bg-gray-100"
                                    onClick={() => handleSort("attendanceRate")}>
                                    Tß╗╖ lß╗ç % {sortField === "attendanceRate" && (sortAsc ? "Γåæ" : "Γåô")}
                                </th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-gray-200">
                            {sortedStudents.map((student) => (
                                <tr key={student.studentId} className="hover:bg-gray-50">
                                    <td className="px-4 py-3 text-sm font-medium text-gray-900 border-r border-gray-200 sticky left-0 bg-white hover:bg-gray-50 whitespace-nowrap">
                                        {student.studentName}
                                    </td>
                                    <td className="px-3 py-3 text-center text-sm">
                                        <span
                                            className={`inline-flex items-center justify-center min-w-[2rem] px-2 py-1 rounded-lg text-green-700 bg-green-50 font-medium ${student.totalPresent > 0 ? 'cursor-pointer hover:ring-2 hover:ring-green-300 transition-all' : ''}`}
                                            onClick={() => handleCellClick(student.studentId, student.studentName, student.totalPresent, "PRESENT", "C├│ mß║╖t")}
                                        >
                                            {student.totalPresent}
                                        </span>
                                    </td>
                                    <td className="px-3 py-3 text-center text-sm">
                                        <span
                                            className={`inline-flex items-center justify-center min-w-[2rem] px-2 py-1 rounded-lg font-medium ${student.totalAbsentExcused > 0 ? 'text-yellow-700 bg-yellow-50 cursor-pointer hover:ring-2 hover:ring-yellow-300 transition-all' : 'text-gray-400 bg-gray-50'}`}
                                            onClick={() => handleCellClick(student.studentId, student.studentName, student.totalAbsentExcused, "ABSENT_EXCUSED", "Vß║»ng c├│ ph├⌐p")}
                                        >
                                            {student.totalAbsentExcused}
                                        </span>
                                    </td>
                                    <td className="px-3 py-3 text-center text-sm">
                                        <span
                                            className={`inline-flex items-center justify-center min-w-[2rem] px-2 py-1 rounded-lg font-medium ${student.totalAbsentUnexcused > 0 ? 'text-red-700 bg-red-50 cursor-pointer hover:ring-2 hover:ring-red-300 transition-all' : 'text-gray-400 bg-gray-50'}`}
                                            onClick={() => handleCellClick(student.studentId, student.studentName, student.totalAbsentUnexcused, "ABSENT_UNEXCUSED", "Vß║»ng kh├┤ng ph├⌐p")}
                                        >
                                            {student.totalAbsentUnexcused}
                                        </span>
                                    </td>
                                    <td className="px-3 py-3 text-center text-sm">
                                        <span
                                            className={`inline-flex items-center justify-center min-w-[2rem] px-2 py-1 rounded-lg font-medium ${student.totalLate > 0 ? 'text-orange-700 bg-orange-50 cursor-pointer hover:ring-2 hover:ring-orange-300 transition-all' : 'text-gray-400 bg-gray-50'}`}
                                            onClick={() => handleCellClick(student.studentId, student.studentName, student.totalLate, "LATE", "─Éi muß╗Ön")}
                                        >
                                            {student.totalLate}
                                        </span>
                                    </td>
                                    <td className="px-3 py-3 text-center text-sm">
                                        <span
                                            className="inline-flex items-center justify-center min-w-[2rem] px-2 py-1 rounded-lg text-gray-600 font-medium cursor-pointer hover:bg-gray-100 hover:ring-2 hover:ring-gray-300 transition-all"
                                            onClick={() => handleCellClick(student.studentId, student.studentName, student.totalSessions, undefined, "Tß║Ñt cß║ú tiß║┐t")}
                                        >
                                            {student.totalSessions}
                                        </span>
                                    </td>
                                    <td className="px-3 py-3 text-center text-sm">
                                        <span className={`inline-flex items-center justify-center min-w-[3rem] px-2 py-1 rounded-lg font-bold ${getAttendanceRateColor(student.attendanceRate)} ${getAttendanceRateBg(student.attendanceRate)}`}>
                                            {student.attendanceRate}%
                                        </span>
                                    </td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>

                {/* Legend */}
                <div className="p-4 border-t border-gray-200 bg-gray-50 text-xs text-gray-500 flex flex-wrap gap-4">
                    <span className="flex items-center gap-1"><span className="w-2 h-2 rounded-full bg-green-500"></span> C├│ mß║╖t (C)</span>
                    <span className="flex items-center gap-1"><span className="w-2 h-2 rounded-full bg-yellow-500"></span> Vß║»ng c├│ ph├⌐p (P)</span>
                    <span className="flex items-center gap-1"><span className="w-2 h-2 rounded-full bg-red-500"></span> Vß║»ng kh├┤ng ph├⌐p (K)</span>
                    <span className="flex items-center gap-1"><span className="w-2 h-2 rounded-full bg-orange-500"></span> ─Éi muß╗Ön (M)</span>
                    <span className="ml-auto text-gray-400">
                        ≡ƒÆí Click v├áo sß╗æ ─æß╗â xem chi tiß║┐t
                    </span>
                </div>
            </div>

            {/* Detail Modal */}
            {modalInfo && (
                <AttendanceDetailModal
                    studentId={modalInfo.studentId}
                    studentName={modalInfo.studentName}
                    startDate={startDateStr}
                    endDate={endDateStr}
                    statusFilter={modalInfo.statusFilter}
                    statusLabel={modalInfo.statusLabel}
                    onClose={() => setModalInfo(null)}
                />
            )}
        </>
    );
}

import React, { useState, useRef } from "react";
import { createPortal } from "react-dom";
import { Upload, Download, X, FileSpreadsheet, AlertCircle, Info } from "lucide-react";
import { teacherService } from "../../../../services/teacherService";
import type { GradeImportResult } from "../../../../services/teacherService";
import ImportGradesResultModal from "./ImportGradesResultModal";

type ImportGradesModalProps = {
    isOpen: boolean;
    onClose: () => void;
    onSuccess: () => void;
    classId: string;
    subjectId: string;
    semesterId: string;
    className?: string;
    subjectName?: string;
};

const ImportGradesModal: React.FC<ImportGradesModalProps> = ({
    isOpen,
    onClose,
    onSuccess,
    classId,
    subjectId,
    semesterId,
    className,
    subjectName
}) => {
    const [file, setFile] = useState<File | null>(null);
    const [dragOver, setDragOver] = useState(false);
    const [uploading, setUploading] = useState(false);
    const [downloading, setDownloading] = useState(false);
    const [result, setResult] = useState<GradeImportResult | null>(null);
    const [error, setError] = useState<string | null>(null);
    const fileInputRef = useRef<HTMLInputElement>(null);

    if (!isOpen) return null;

    const handleReset = () => {
        setFile(null);
        setResult(null);
        setError(null);
    };

    const handleClose = () => {
        handleReset();
        onClose();
    };

    const handleFileSelect = (selectedFile: File) => {
        const validTypes = [
            "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
            "application/vnd.ms-excel"
        ];
        if (!validTypes.includes(selectedFile.type) && !selectedFile.name.match(/\.(xlsx|xls)$/i)) {
            setError("Vui l├▓ng chß╗ìn file Excel (.xlsx hoß║╖c .xls)");
            return;
        }
        setFile(selectedFile);
        setError(null);
        setResult(null);
    };

    const handleDrop = (e: React.DragEvent) => {
        e.preventDefault();
        setDragOver(false);
        if (e.dataTransfer.files.length > 0) {
            handleFileSelect(e.dataTransfer.files[0]);
        }
    };

    const handleUpload = async () => {
        if (!file) return;
        setUploading(true);
        setError(null);
        try {
            const importResult = await teacherService.importGrades(file, classId, subjectId, semesterId, true);
            setResult(importResult);
        } catch (err: any) {
            setError(err.response?.data?.message || "C├│ lß╗ùi xß║úy ra khi import ─æiß╗âm.");
        } finally {
            setUploading(false);
        }
    };

    const handleConfirmSave = async () => {
        if (!result?.previewData) return;
        setUploading(true); // reusing uploading state as saving state
        try {
            await teacherService.saveGrades({
                classId,
                subjectId,
                semesterId,
                students: result.previewData
            });
            onSuccess(); // Refresh grade table
            handleClose(); // Close all
        } catch (err: any) {
            alert(err.response?.data?.message || "C├│ lß╗ùi khi l╞░u ─æiß╗âm.");
        } finally {
            setUploading(false);
        }
    };

    const handleDownloadTemplate = async () => {
        setDownloading(true);
        try {
            await teacherService.downloadGradeTemplate(classId, subjectId, semesterId);
        } catch (err: any) {
            setError(err.response?.data?.message || "Kh├┤ng thß╗â tß║úi file mß║½u.");
        } finally {
            setDownloading(false);
        }
    };

    return (
        <>
            {createPortal(
                <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
                    <div className="absolute inset-0 bg-black/60 backdrop-blur-sm" onClick={handleClose} />
                    <div className="relative bg-white rounded-3xl shadow-2xl w-full max-w-xl overflow-hidden flex flex-col z-[100] animate-in zoom-in-95 duration-300 max-h-[85vh]">
                        {/* Header */}
                        <div className="bg-gradient-to-r from-emerald-600 to-emerald-500 px-8 py-5 flex-none text-white">
                            <div className="flex items-center justify-between">
                                <div className="flex items-center gap-3">
                                    <div className="w-10 h-10 bg-white/20 rounded-xl flex items-center justify-center shadow-inner">
                                        <FileSpreadsheet className="w-5 h-5 text-emerald-50" />
                                    </div>
                                    <div>
                                        <h1 className="text-xl font-bold tracking-tight">Nhß║¡p ─æiß╗âm tß╗½ Excel</h1>
                                        {className && subjectName && (
                                            <p className="text-emerald-50/80 text-xs font-medium mt-0.5">{className} ΓÇó {subjectName}</p>
                                        )}
                                    </div>
                                </div>
                                <button onClick={handleClose} className="w-9 h-9 rounded-lg bg-white/10 hover:bg-white/20 flex items-center justify-center transition-all">
                                    <X className="w-5 h-5 text-white" />
                                </button>
                            </div>
                        </div>

                        {/* Body */}
                        <div className="p-6 space-y-6 overflow-y-auto flex-1 custom-scrollbar">
                            {/* Download Template Section */}
                            <div className="bg-blue-50/50 border border-blue-100 rounded-2xl p-4 flex items-center justify-between shadow-sm">
                                <div className="flex gap-3 items-center">
                                    <div className="w-10 h-10 rounded-xl bg-blue-100 flex items-center justify-center">
                                        <Download className="w-5 h-5 text-blue-600" />
                                    </div>
                                    <div>
                                        <p className="text-sm font-bold text-blue-900">Tß║úi file mß║½u</p>
                                        <p className="text-[11px] text-blue-600/70 mt-0.5 font-medium">Gß╗ôm danh s├ích hß╗ìc sinh & ─æiß╗âm ─æ├ú c├│</p>
                                    </div>
                                </div>
                                <button
                                    onClick={handleDownloadTemplate}
                                    disabled={downloading}
                                    className="px-4 py-2 bg-blue-600 text-white rounded-xl text-xs font-bold hover:bg-blue-700 transition-all shadow-md shadow-blue-100 shrink-0 disabled:opacity-50"
                                >
                                    {downloading ? "─Éang tß║úi..." : "Tß║úi ngay"}
                                </button>
