                                            <p className="text-xs text-slate-400 font-medium mt-1">hoß║╖c click ─æß╗â chß╗ìn file tß╗½ m├íy t├¡nh</p>
                                        </div>
                                    </div>
                                )}
                            </div>

                            {/* Info Card - Softened colors */}
